      }

      // Get existing notifications
      const notifications = await storage.getInvoiceNotifications(invoiceId);
      const reminderCount = notifications.filter(n => n.notificationType === 'reminder').length;

      // Create reminder notification
      await storage.createInvoiceNotification({
        invoiceId: invoiceId,
        notificationType: 'reminder',
        recipientAddress: invoice.recipientAddress,
        reminderCount: reminderCount + 1,
        nextReminderAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000) // Next reminder in 7 days
      });

      // Update invoice status if overdue
      const now = new Date();
      if (new Date(invoice.dueDate) < now && invoice.status !== 'overdue') {
        await storage.updateInvoice(invoiceId, { status: 'overdue' });
      }

      res.json({ message: "Reminder sent successfully", reminderCount: reminderCount + 1 });
