  app.get("/api/marketplace/corridors/:id", async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      const corridor = await storage.getTradeCorridor(id);

      if (!corridor) {
        return res.status(404).json({ message: "Trade corridor not found" });
      }

