  app.post("/api/marketplace/corridors", async (req, res) => {
    try {
      const corridor = await storage.createTradeCorridor(req.body);
      res.status(201).json(corridor);
    } catch (error) {
      res.status(400).json({ 
        message: error instanceof Error ? error.message : "Failed to create trade corridor" 
      });
    }
  });

  // Marketplace Statistics Endpoint
  app.get("/api/marketplace/stats", async (req, res) => {
    try {
      const businesses = await storage.searchMarketplaceBusinesses({ limit: 1000 });
      const rfqs = await storage.searchMarketplaceRfqs({ limit: 1000, status: 'open' });
      const corridors = await storage.getAllTradeCorridors();

      res.json({
        totalBusinesses: businesses.length,
        verifiedBusinesses: businesses.filter(b => b.isVerified).length,
        activeRfqs: rfqs.length,
        tradeCorridors: corridors.length,
        regions: {
          africa: businesses.filter(b => b.region === 'Africa').length,
          asia: businesses.filter(b => b.region === 'Asia').length,
          europe: businesses.filter(b => b.region === 'Europe').length,
          americas: businesses.filter(b => b.region === 'Americas').length,
          middleEast: businesses.filter(b => b.region === 'Middle East').length
        }
      });
    } catch (error) {
      res.status(500).json({ 
        message: error instanceof Error ? error.message : "Failed to fetch marketplace stats" 
      });
    }
  });

  const httpServer = createServer(app);

  // WebSocket server for real-time messaging
  const wss = new WebSocketServer({ server: httpServer, path: '/ws' });

  // Store connected clients with their wallet addresses
  const connectedClients = new Map<string, WebSocket>();

  // Store offline messages for delivery when user comes online
  const offlineMessages = new Map<string, any[]>();

  wss.on('connection', (ws: WebSocket) => {
    let clientWalletAddress: string | null = null;

    ws.on('message', async (data: Buffer) => {
      try {
        const message = JSON.parse(data.toString());

        if (message.type === 'authenticate') {
          // Client authenticates with wallet address
          clientWalletAddress = message.walletAddress?.toLowerCase();
          if (clientWalletAddress) {
            connectedClients.set(clientWalletAddress, ws);
            console.log(`Client authenticated: ${clientWalletAddress}`);

            // Load and send undelivered messages from database (async operation)
            try {
              const undeliveredMessages = await storage.getMessages({
                to: clientWalletAddress,
                limit: 50
              });

              const pendingMessages = undeliveredMessages.filter(msg => !msg.delivered);

              for (const msg of pendingMessages) {
                try {
                  const messageData = {
                    type: 'new_message',
                    id: msg.id.toString(),
                    from: msg.from,
                    to: msg.to,
                    content: msg.content,
                    timestamp: msg.timestamp?.toISOString(),
                    read: msg.read,
                    attachment: msg.attachmentName ? {
                      name: msg.attachmentName,
                      type: msg.attachmentType!,
                      size: msg.attachmentSize!,
                      data: msg.attachmentData!
                    } : null
                  };

                  if (ws.readyState === WebSocket.OPEN) {
                    ws.send(JSON.stringify(messageData));
                    // Mark as delivered
                    await storage.markMessageAsDelivered(msg.id);
                  }
                } catch (msgError) {
                  console.error('Error processing undelivered message:', msgError);
                }
              }

              if (pendingMessages.length > 0) {
                console.log(`Delivered ${pendingMessages.length} undelivered messages to ${clientWalletAddress}`);
              }
            } catch (error) {
              console.error('Error loading undelivered messages:', error);
            }
          }

          ws.send(JSON.stringify({
            type: 'authenticated',
            walletAddress: clientWalletAddress
          }));
        } else if (message.type === 'send_message' && clientWalletAddress) {
          // Save message to database
          const savedMessage = await storage.createMessage({
            from: clientWalletAddress,
            to: message.to,
            content: message.content,
            attachmentName: message.attachment?.name || null,
            attachmentType: message.attachment?.type || null,
            attachmentSize: message.attachment?.size || null,
            attachmentData: message.attachment?.data || null,
            read: false,
            delivered: false
          });

          const messageData = {
            type: 'new_message',
            id: savedMessage.id.toString(),
            from: savedMessage.from,
            to: savedMessage.to,
            content: savedMessage.content,
            timestamp: savedMessage.timestamp?.toISOString(),
            read: savedMessage.read,
            attachment: savedMessage.attachmentName ? {
              name: savedMessage.attachmentName,
              type: savedMessage.attachmentType!,
              size: savedMessage.attachmentSize!,
              data: savedMessage.attachmentData!
            } : null
          };

          // Try to deliver to recipient if online (normalize address to lowercase)
          const recipientAddress = message.to?.toLowerCase();
          const recipientWs = connectedClients.get(recipientAddress);
          let delivered = false;

          console.log(`Attempting delivery to ${recipientAddress}, connected clients:`, Array.from(connectedClients.keys()));

          if (recipientWs && recipientWs.readyState === WebSocket.OPEN) {
            recipientWs.send(JSON.stringify(messageData));
            delivered = true;
            // Mark as delivered in database
            await storage.markMessageAsDelivered(savedMessage.id);
            console.log(`✅ Message delivered instantly from ${clientWalletAddress} to ${recipientAddress}`);
          } else {
            console.log(`💾 Message saved to database for ${recipientAddress} from ${clientWalletAddress} (recipient offline)`);
          }

          // Send confirmation back to sender
          ws.send(JSON.stringify({
            type: 'message_sent',
            id: savedMessage.id.toString(),
            from: savedMessage.from,
            to: savedMessage.to,
            content: savedMessage.content,
            timestamp: savedMessage.timestamp?.toISOString(),
            read: savedMessage.read,
            attachment: messageData.attachment,
            delivered: delivered
          }));
        } else if (message.type === 'call_offer' && clientWalletAddress) {
          // Forward call offer to recipient
          const recipientAddress = message.to?.toLowerCase();
          const recipientWs = connectedClients.get(recipientAddress);

          if (recipientWs && recipientWs.readyState === WebSocket.OPEN) {
            recipientWs.send(JSON.stringify({
              type: 'incoming_call',
              from: clientWalletAddress,
              callType: message.callType,
              offer: message.offer
            }));
            console.log(`📞 Call offer from ${clientWalletAddress} to ${recipientAddress}`);
          } else {
            // Recipient is offline - notify caller
            ws.send(JSON.stringify({
              type: 'call_failed',
              reason: 'recipient_offline',
              to: recipientAddress
            }));
            console.log(`❌ Call failed - ${recipientAddress} is offline`);
          }
        } else if (message.type === 'call_answer' && clientWalletAddress) {
          // Forward call answer to caller
          const callerAddress = message.to?.toLowerCase();
          const callerWs = connectedClients.get(callerAddress);

          if (callerWs && callerWs.readyState === WebSocket.OPEN) {
            callerWs.send(JSON.stringify({
              type: 'call_answered',
              from: clientWalletAddress,
              answer: message.answer
            }));
            console.log(`✅ Call answered by ${clientWalletAddress} to ${callerAddress}`);
          }
        } else if (message.type === 'ice_candidate' && clientWalletAddress) {
          // Forward ICE candidate to peer
          const peerAddress = message.to?.toLowerCase();
          const peerWs = connectedClients.get(peerAddress);

          if (peerWs && peerWs.readyState === WebSocket.OPEN) {
            peerWs.send(JSON.stringify({
              type: 'ice_candidate',
              from: clientWalletAddress,
              candidate: message.candidate
            }));
          }
        } else if (message.type === 'call_reject' && clientWalletAddress) {
          // Notify caller that call was rejected
          const callerAddress = message.to?.toLowerCase();
          const callerWs = connectedClients.get(callerAddress);

          if (callerWs && callerWs.readyState === WebSocket.OPEN) {
            callerWs.send(JSON.stringify({
              type: 'call_rejected',
              from: clientWalletAddress
            }));
            console.log(`❌ Call rejected by ${clientWalletAddress}`);
          }
        } else if (message.type === 'call_end' && clientWalletAddress) {
          // Notify peer that call has ended
          const peerAddress = message.to?.toLowerCase();
          const peerWs = connectedClients.get(peerAddress);

          if (peerWs && peerWs.readyState === WebSocket.OPEN) {
            peerWs.send(JSON.stringify({
              type: 'call_ended',
              from: clientWalletAddress
            }));
            console.log(`📞 Call ended by ${clientWalletAddress}`);
          }
        }
      } catch (error) {
        console.error('WebSocket message error:', error);
      }
    });

    ws.on('close', () => {
      if (clientWalletAddress) {
        connectedClients.delete(clientWalletAddress);
      }
    });

    ws.on('error', (error) => {
      console.error('WebSocket error:', error);
      if (clientWalletAddress) {
        connectedClients.delete(clientWalletAddress);
      }
    });
  });

  return httpServer;
}

