  async getMessage(id: number): Promise<Message | undefined> {
    const [message] = await db.select().from(messages).where(eq(messages.id, id));
    return message || undefined;
  }

  async getMessages(filters: {
    from?: string;
    to?: string;
    conversation?: { user1: string; user2: string };
    walletAddress?: string;
    limit?: number;
  }): Promise<Message[]> {
    let query = db.select().from(messages);

    if (filters.walletAddress) {
      // Filter messages where the user is either sender or receiver
      const walletAddress = filters.walletAddress.toLowerCase();
      query = query.where(
        or(
          eq(sql`LOWER(${messages.from})`, walletAddress),
          eq(sql`LOWER(${messages.to})`, walletAddress)
        )
      ) as any;
    } else if (filters.conversation) {
      const { user1, user2 } = filters.conversation;
      query = query.where(
        or(
          and(eq(sql`LOWER(${messages.from})`, user1.toLowerCase()), eq(sql`LOWER(${messages.to})`, user2.toLowerCase())),
          and(eq(sql`LOWER(${messages.from})`, user2.toLowerCase()), eq(sql`LOWER(${messages.to})`, user1.toLowerCase()))
        )
      ) as any;
    } else {
      if (filters.from) {
        query = query.where(eq(sql`LOWER(${messages.from})`, filters.from.toLowerCase())) as any;
      }
      if (filters.to) {
        query = query.where(eq(sql`LOWER(${messages.to})`, filters.to.toLowerCase())) as any;
      }
    }

    query = query.orderBy(desc(messages.timestamp)) as any;

    if (filters.limit) {
      query = query.limit(filters.limit) as any;
    }

    return await query;
  }

  async getAllMessages(): Promise<Message[]> {
    return await db.select().from(messages).orderBy(desc(messages.timestamp));
