import { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { useToast } from '@/hooks/use-toast';
import { useWallet } from '@/hooks/use-wallet';
import { walletManager } from '@/lib/wallet';
import { NETWORKS } from '@/lib/networks';
import { RefreshCw, AlertCircle, CheckCircle } from 'lucide-react';
import { ethers } from 'ethers';

interface BalanceResult {
  networkId: number;
  networkName: string;
  balance: string;
  symbol: string;
  success: boolean;
  error?: string;
}

export function BalanceRefresh() {
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [balanceResults, setBalanceResults] = useState<BalanceResult[]>([]);
  const { toast } = useToast();
  const { address, isUnlocked } = useWallet();

  const refreshBalances = async () => {
    if (!isUnlocked || !address) {
      toast({
        title: 'Error',
        description: 'Please unlock your wallet first',
        variant: 'destructive',
      });
      return;
    }

    setIsRefreshing(true);
    setBalanceResults([]);

    const results: BalanceResult[] = [];

    for (const network of NETWORKS) {
      try {
        console.log(`Checking balance for ${network.name}...`);

        // Create fresh provider for each network
        const provider = new ethers.JsonRpcProvider(network.rpcUrl);

        // Test connection first
        await provider._detectNetwork();

        // Get balance
        const balance = await provider.getBalance(address);
        const balanceEth = ethers.formatEther(balance);

        results.push({
          networkId: network.id,
          networkName: network.name,
          balance: balanceEth,
          symbol: network.symbol,
          success: true
        });

        console.log(`${network.name}: ${balanceEth} ${network.symbol}`);

      } catch (error) {
        console.error(`Failed to get balance for ${network.name}:`, error);
        results.push({
          networkId: network.id,
          networkName: network.name,
          balance: '0',
          symbol: network.symbol,
          success: false,
          error: error instanceof Error ? error.message : 'Unknown error'
        });
      }
    }

    setBalanceResults(results);
    setIsRefreshing(false);

    const successCount = results.filter(r => r.success).length;
    const hasBalances = results.some(r => r.success && parseFloat(r.balance) > 0);

    if (hasBalances) {
      toast({
        title: 'Balances Found!',
        description: `Successfully retrieved balances from ${successCount}/${NETWORKS.length} networks`,
      });
    } else if (successCount > 0) {
      toast({
        title: 'Networks Connected',
        description: `Connected to ${successCount}/${NETWORKS.length} networks, but no balances found`,
      });
    } else {
      toast({
        title: 'Connection Issues',
        description: 'Could not connect to any networks. Try again later.',
        variant: 'destructive',
      });
    }
  };

  return (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center space-x-2">
            <RefreshCw className="h-5 w-5" />
            <span>Manual Balance Refresh</span>
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <Alert>
            <AlertCircle className="h-4 w-4" />
            <AlertDescription>
              If your balance isn't showing but you confirmed the transaction on the blockchain, 
              use this tool to force refresh your balances across all networks.
            </AlertDescription>
          </Alert>

          <div className="flex items-center justify-between">
            <div>
              <p className="font-medium">Current Wallet Address:</p>
              <p className="text-sm font-mono text-muted-foreground break-all">{address}</p>
            </div>
            <Button 
              onClick={refreshBalances}
              disabled={isRefreshing || !isUnlocked}
            >
              {isRefreshing ? (
                <>
                  <RefreshCw className="h-4 w-4 mr-2 animate-spin" />
                  Refreshing...
                </>
              ) : (
                <>
                  <RefreshCw className="h-4 w-4 mr-2" />
                  Refresh Balances
                </>
              )}
            </Button>
          </div>

          {balanceResults.length > 0 && (
            <div className="space-y-3">
              <h3 className="font-medium">Balance Results:</h3>

              {balanceResults.map((result) => (
                <div 
                  key={result.networkId} 
                  className={`p-3 border rounded-lg ${
                    result.success 
                      ? parseFloat(result.balance) > 0 
                        ? 'border-green-200 bg-green-50 dark:border-green-800 dark:bg-green-900/20'
                        : 'border-gray-200 bg-gray-50 dark:border-gray-700 dark:bg-gray-800/20'
                      : 'border-red-200 bg-red-50 dark:border-red-800 dark:bg-red-900/20'
                  }`}
                >
                  <div className="flex items-center justify-between">
                    <div className="flex items-center space-x-2">
                      {result.success ? (
                        <CheckCircle className="h-4 w-4 text-green-600" />
                      ) : (
                        <AlertCircle className="h-4 w-4 text-red-600" />
                      )}
                      <span className="font-medium">{result.networkName}</span>
                    </div>

                    {result.success ? (
                      <div className="text-right">
                        <p className="font-mono font-medium">
                          {parseFloat(result.balance).toFixed(6)} {result.symbol}
                        </p>
                        {parseFloat(result.balance) > 0 && (
                          <p className="text-xs text-green-600 dark:text-green-400">
                            Balance found!
                          </p>
                        )}
                      </div>
                    ) : (
                      <div className="text-right">
                        <p className="text-xs text-red-600 dark:text-red-400">
                          Connection failed
                        </p>
                        <p className="text-xs text-muted-foreground">
                          {result.error?.slice(0, 40)}...
                        </p>
                      </div>
                    )}
                  </div>
                </div>
              ))}

              {balanceResults.some(r => r.success && parseFloat(r.balance) > 0) && (
                <Alert>
                  <CheckCircle className="h-4 w-4" />
                  <AlertDescription>
                    <strong>Success!</strong> Your balances have been found. The wallet interface should now display your correct balances.
                    If they still don't appear in the main wallet view, try refreshing the page.
                  </AlertDescription>
                </Alert>
              )}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

client/src/components/wallet/transaction.content:
import { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { useTransactions } from '@/hooks/use-transactions';
import { getNetworkById } from '@/lib/networks';
import { formatDistanceToNow } from 'date-fns';
import { ExternalLink, RefreshCw } from 'lucide-react';
import { Skeleton } from '@/components/ui/skeleton';

interface TransactionHistoryProps {
  networkId: number;
  className?: string;
}

export function TransactionHistory({ networkId, className = '' }: TransactionHistoryProps) {
  const [showAll, setShowAll] = useState(false);
  const { 
    transactions, 
    isLoadingTransactions, 
    formatCrypto, 
    formatCurrency,
    refreshAll 
  } = useTransactions(networkId);

  const network = getNetworkById(networkId);

  const displayTransactions = showAll ? transactions : transactions.slice(0, 5);

  const getTransactionIcon = (type: string, status: string) => {
    if (status === 'pending') {
      return 'fas fa-clock text-warning';
    }
    if (status === 'failed') {
      return 'fas fa-times text-destructive';
    }
    return type === 'received' ? 'fas fa-arrow-down text-success' : 'fas fa-arrow-up text-destructive';
  };

  const getStatusBadge = (status: string) => {
    const variants = {
      'confirmed': 'default',
      'pending': 'secondary',
      'failed': 'destructive'
    } as const;

    return (
      <Badge variant={variants[status as keyof typeof variants] || 'default'}>
        {status.charAt(0).toUpperCase() + status.slice(1)}
      </Badge>
    );
  };

  const openInExplorer = (hash: string) => {
    if (!network?.blockExplorerUrl) return;
    window.open(`${network.blockExplorerUrl}/tx/${hash}`, '_blank');
  };

  if (isLoadingTransactions) {
    return (
      <Card className={className}>
        <CardHeader>
          <CardTitle>Recent Transactions</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="space-y-4">
            {[...Array(3)].map((_, i) => (
              <div key={i} className="flex items-center space-x-4">
                <Skeleton className="h-10 w-10 rounded-full" />
                <div className="flex-1 space-y-2">
                  <Skeleton className="h-4 w-32" />
                  <Skeleton className="h-3 w-24" />
                </div>
                <div className="text-right space-y-2">
                  <Skeleton className="h-4 w-20" />
                  <Skeleton className="h-3 w-16" />
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card className={className}>
      <CardHeader>
        <div className="flex justify-between items-center">
          <CardTitle>Recent Transactions</CardTitle>
          <div className="flex items-center space-x-2">
            <Button
              variant="outline"
              size="sm"
              onClick={refreshAll}
              className="px-3"
            >
              <RefreshCw className="h-4 w-4" />
            </Button>
            {transactions.length > 5 && (
              <Button
                variant="outline"
                size="sm"
                onClick={() => setShowAll(!showAll)}
              >
                {showAll ? 'Show Less' : 'View All'}
              </Button>
            )}
          </div>
        </div>
      </CardHeader>

      <CardContent>
        {transactions.length === 0 ? (
          <div className="text-center py-8">
            <div className="w-16 h-16 bg-muted rounded-full flex items-center justify-center mx-auto mb-4">
              <i className="fas fa-receipt text-muted-foreground text-xl"></i>
            </div>
            <h3 className="font-medium text-lg mb-2">No transactions yet</h3>
            <p className="text-muted-foreground text-sm mb-4">
              Your transaction history will appear here once you send or receive funds.
            </p>
            <p className="text-xs text-muted-foreground">
              Current balance sources may be from testnet faucets which don't always create transaction records.
            </p>
          </div>
        ) : (
          <div className="space-y-4">
            {displayTransactions.map((tx, index) => (
              <div 
                key={tx.hash || index}
                className="flex items-center justify-between p-3 hover:bg-muted/50 rounded-lg transition-colors group"
              >
                <div className="flex items-center space-x-3">
                  <div className="w-10 h-10 rounded-full flex items-center justify-center bg-muted">
                    <i className={`${getTransactionIcon(tx.type, tx.status)} text-sm`}></i>
                  </div>
                  <div>
                    <div className="flex items-center space-x-2">
                      <span className="font-medium">
                        {tx.type === 'received' ? 'Received' : 'Sent'} {network?.symbol}
                      </span>
                      {getStatusBadge(tx.status)}
                    </div>
                    <div className="flex items-center space-x-2 text-sm text-muted-foreground">
                      <span>
                        {formatDistanceToNow(tx.timestamp, { addSuffix: true })}
                      </span>
                      <span>•</span>
                      <span>{network?.name}</span>
                      {network?.blockExplorerUrl && (
                        <Button
                          variant="ghost"
                          size="sm"
                          className="h-auto p-0 opacity-0 group-hover:opacity-100 transition-opacity"
                          onClick={() => openInExplorer(tx.hash)}
                        >
                          <ExternalLink className="h-3 w-3" />
                        </Button>
                      )}
                    </div>
                  </div>
                </div>
                <div className="text-right">
                  <div className={`font-medium ${
                    tx.type === 'received' ? 'text-success' : 'text-foreground'
                  }`}>
                    {tx.type === 'received' ? '+' : '-'}
                    {formatCrypto(tx.value, network?.symbol || '')}
                  </div>
                  {tx.usdValue && (
                    <div className="text-sm text-muted-foreground">
                      {formatCurrency(tx.usdValue)}
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

