  arbitratorAddress: z.string().regex(/^0x[a-fA-F0-9]{40}$/, 'Invalid Ethereum address'),
  totalAmount: z.string().min(1, 'Amount is required'),
  currency: z.string().min(1, 'Currency is required'),
