  const handleAttachmentContextMenu = (e: React.MouseEvent, messageId: string, attachment: MessageAttachment) => {
    e.preventDefault();
    e.stopPropagation();
    setContextMenu({
      show: true,
      x: e.clientX,
      y: e.clientY,
      messageId,
      attachment
