import { useQuery } from '@tanstack/react-query';
import { formatDistanceToNow } from 'date-fns';
import { Phone, Video, PhoneIncoming, PhoneOutgoing, PhoneMissed } from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';

interface CallLog {
  id: number;
  callerAddress: string;
  receiverAddress: string;
  callType: 'voice' | 'video';
  status: 'initiated' | 'answered' | 'ended' | 'rejected' | 'missed';
  duration?: number;
  startedAt: string;
  endedAt?: string;
}

interface CallHistoryProps {
  walletAddress: string;
  getDisplayName?: (address: string) => string;
}

export function CallHistory({ walletAddress, getDisplayName }: CallHistoryProps) {
  const { data: callLogs = [], isLoading } = useQuery<CallLog[]>({
    queryKey: ['/api/call-logs', walletAddress],
    queryFn: async () => {
      const response = await fetch(`/api/call-logs?walletAddress=${walletAddress.toLowerCase()}`);
      if (!response.ok) throw new Error('Failed to fetch call logs');
      return response.json();
    },
  });

  const formatDuration = (seconds?: number) => {
    if (!seconds) return 'N/A';
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const getCallIcon = (log: CallLog) => {
    const isIncoming = log.receiverAddress.toLowerCase() === walletAddress.toLowerCase();
    const iconClass = "h-4 w-4";

    if (log.status === 'missed' || log.status === 'rejected') {
      return <PhoneMissed className={`${iconClass} text-red-500`} />;
    }

    if (log.callType === 'video') {
      return <Video className={iconClass} />;
    }

    return isIncoming ? 
      <PhoneIncoming className={iconClass} /> : 
      <PhoneOutgoing className={iconClass} />;
  };

  const getStatusText = (log: CallLog) => {
    const isIncoming = log.receiverAddress.toLowerCase() === walletAddress.toLowerCase();

    switch (log.status) {
      case 'missed':
        return 'Missed';
      case 'rejected':
        return 'Rejected';
      case 'ended':
        return formatDuration(log.duration);
      default:
        return isIncoming ? 'Incoming' : 'Outgoing';
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center p-8">
        <div className="text-muted-foreground">Loading call history...</div>
      </div>
    );
  }

  if (callLogs.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center p-8 text-center">
        <Phone className="h-12 w-12 text-muted-foreground mb-4" />
        <h3 className="text-lg font-semibold mb-2">No call history</h3>
        <p className="text-sm text-muted-foreground">
          Start a voice or video call with your contacts
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-2 p-4">
      {callLogs.map((log) => {
        const isIncoming = log.receiverAddress.toLowerCase() === walletAddress.toLowerCase();
        const otherAddress = isIncoming ? log.callerAddress : log.receiverAddress;
        const displayName = getDisplayName?.(otherAddress) || otherAddress;

        return (
          <Card key={log.id} className="hover:bg-accent/50 transition-colors">
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div className="flex items-center space-x-3">
                  <div className="flex-shrink-0">
                    {getCallIcon(log)}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium truncate">
                      {displayName}
                    </p>
                    <p className="text-xs text-muted-foreground">
                      {log.callType === 'video' ? 'Video Call' : 'Voice Call'}
                    </p>
                  </div>
                </div>
                <div className="text-right">
                  <p className="text-sm font-medium">
                    {getStatusText(log)}
                  </p>
                  <p className="text-xs text-muted-foreground">
                    {formatDistanceToNow(new Date(log.startedAt), { addSuffix: true })}
                  </p>
                </div>
              </div>
            </CardContent>
          </Card>
        );
      })}
    </div>
  );
}

client/src/hooks/use-webrtc.ts.content:
import { useEffect, useRef, useState, useCallback } from 'react';

interface UseWebRTCProps {
  localWalletAddress: string;
  remoteWalletAddress: string | null;
  callType: 'voice' | 'video';
  webSocket: WebSocket | null;
  onCallEnd?: () => void;
}

interface CallState {
  isActive: boolean;
  isCalling: boolean;
  isReceiving: boolean;
  callType: 'voice' | 'video';
  startTime: Date | null;
  remoteAddress: string | null;
}

// STUN servers for NAT traversal
const ICE_SERVERS = {
  iceServers: [
    { urls: 'stun:stun.l.google.com:19302' },
    { urls: 'stun:stun1.l.google.com:19302' },
    { urls: 'stun:stun2.l.google.com:19302' },
  ]
};

export function useWebRTC({ localWalletAddress, remoteWalletAddress, callType, webSocket, onCallEnd }: UseWebRTCProps) {
  const socket = webSocket;
  const [callState, setCallState] = useState<CallState>({
    isActive: false,
    isCalling: false,
    isReceiving: false,
    callType,
    startTime: null,
    remoteAddress: null,
  });

  const [localStream, setLocalStream] = useState<MediaStream | null>(null);
  const [remoteStream, setRemoteStream] = useState<MediaStream | null>(null);
  const peerConnection = useRef<RTCPeerConnection | null>(null);
  const callLogId = useRef<number | null>(null);

  // Send message via WebSocket
  const sendMessage = useCallback((message: any) => {
    if (socket && socket.readyState === WebSocket.OPEN) {
      socket.send(JSON.stringify(message));
    }
  }, [socket]);

  // Initialize peer connection
  const initializePeerConnection = useCallback(() => {
    if (peerConnection.current) {
      peerConnection.current.close();
    }

    const pc = new RTCPeerConnection(ICE_SERVERS);

    // Handle ICE candidates
    pc.onicecandidate = (event) => {
      if (event.candidate && socket && remoteWalletAddress) {
        sendMessage({
          type: 'ice_candidate',
          to: remoteWalletAddress,
          candidate: event.candidate,
        });
      }
    };

    // Handle remote stream
    pc.ontrack = (event) => {
      console.log('📺 Remote track received:', event.track.kind);
      setRemoteStream(event.streams[0]);
    };

    // Connection state monitoring
    pc.onconnectionstatechange = () => {
      console.log('Connection state:', pc.connectionState);
      if (pc.connectionState === 'disconnected' || pc.connectionState === 'failed') {
        endCall();
      }
    };

    peerConnection.current = pc;
    return pc;
  }, [socket, remoteWalletAddress, sendMessage]);

  // Get user media (camera/microphone)
  const getUserMedia = useCallback(async (type: 'voice' | 'video') => {
    try {
      const constraints = {
        audio: true,
        video: type === 'video',
      };

      const stream = await navigator.mediaDevices.getUserMedia(constraints);
      setLocalStream(stream);
      return stream;
    } catch (error) {
      console.error('Error accessing media devices:', error);
      throw error;
    }
  }, []);

  // Initiate a call
  const startCall = useCallback(async () => {
    if (!remoteWalletAddress) {
      console.error('No remote address specified');
      return;
    }

    try {
      // Create call log
      const response = await fetch('/api/call-logs', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          callerAddress: localWalletAddress.toLowerCase(),
          receiverAddress: remoteWalletAddress.toLowerCase(),
          callType,
          status: 'initiated',
          startedAt: new Date().toISOString(),
        }),
      });
      const callLog = await response.json();
      callLogId.current = callLog.id;

      const stream = await getUserMedia(callType);
      const pc = initializePeerConnection();

      // Add local tracks to peer connection
      stream.getTracks().forEach(track => {
        pc.addTrack(track, stream);
      });

      // Create offer
      const offer = await pc.createOffer();
      await pc.setLocalDescription(offer);

      // Send offer via WebSocket
      sendMessage({
        type: 'call_offer',
        to: remoteWalletAddress,
        callType,
        offer,
      });

      setCallState({
        isActive: false,
        isCalling: true,
        isReceiving: false,
        callType,
        startTime: null,
        remoteAddress: remoteWalletAddress,
      });

      console.log('📞 Call initiated to:', remoteWalletAddress);
    } catch (error) {
      console.error('Error starting call:', error);
      // Update call log as failed
      if (callLogId.current) {
        await fetch(`/api/call-logs/${callLogId.current}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ status: 'failed' }),
        });
      }
    }
  }, [localWalletAddress, remoteWalletAddress, callType, getUserMedia, initializePeerConnection, sendMessage]);

  // Answer incoming call
  const answerCall = useCallback(async (offer: RTCSessionDescriptionInit, callerAddress: string) => {
    try {
      console.log('📱 Starting answerCall for:', callerAddress);

      // Create call log
      const now = new Date();
      console.log('📝 Creating call log...');
      const response = await fetch('/api/call-logs', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          callerAddress: callerAddress.toLowerCase(),
          receiverAddress: localWalletAddress.toLowerCase(),
          callType,
          status: 'answered',
          startedAt: now.toISOString(),
        }),
      });

      if (!response.ok) {
        throw new Error(`Failed to create call log: ${response.status}`);
      }

      const callLog = await response.json();
      callLogId.current = callLog.id;
      console.log('✅ Call log created:', callLog.id);

      console.log('🎤 Requesting media access...');
      const stream = await getUserMedia(callType);
      console.log('✅ Media access granted');

      console.log('🔌 Initializing peer connection...');
      const pc = initializePeerConnection();

      // Add local tracks
      stream.getTracks().forEach(track => {
        pc.addTrack(track, stream);
      });
      console.log('✅ Local tracks added');

      // Set remote description (offer)
      console.log('📡 Setting remote description...');
      await pc.setRemoteDescription(new RTCSessionDescription(offer));

      // Create answer
      console.log('📤 Creating answer...');
      const answer = await pc.createAnswer();
      await pc.setLocalDescription(answer);

      // Send answer via WebSocket
      console.log('📨 Sending answer via WebSocket...');
      sendMessage({
        type: 'call_answer',
        to: callerAddress,
        answer,
      });

      setCallState({
        isActive: true,
        isCalling: false,
        isReceiving: false,
        callType,
        startTime: new Date(),
        remoteAddress: callerAddress,
      });

      console.log('✅ Call answered from:', callerAddress);
    } catch (error) {
      console.error('❌ Error answering call:', error);
      console.error('❌ Error details:', error instanceof Error ? error.message : error);

      if (callLogId.current) {
        await fetch(`/api/call-logs/${callLogId.current}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ status: 'failed' }),
        });
      }

      // Rethrow so the acceptPendingCall can show the alert
      throw error;
    }
  }, [localWalletAddress, callType, getUserMedia, initializePeerConnection, sendMessage]);

  // Handle incoming call answer
  const handleCallAnswer = useCallback(async (answer: RTCSessionDescriptionInit) => {
    try {
      if (!peerConnection.current) {
        console.error('No peer connection available');
        return;
      }

      await peerConnection.current.setRemoteDescription(new RTCSessionDescription(answer));

      setCallState(prev => ({
        ...prev,
        isActive: true,
        isCalling: false,
        startTime: new Date(),
      }));

      // Update call log
      if (callLogId.current) {
        await fetch(`/api/call-logs/${callLogId.current}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ 
            status: 'answered',
            startedAt: new Date().toISOString(),
          }),
        });
      }

      console.log('✅ Call connected');
    } catch (error) {
      console.error('Error handling call answer:', error);
    }
  }, []);

  // Handle ICE candidate
  const handleIceCandidate = useCallback(async (candidate: RTCIceCandidateInit) => {
    try {
      if (peerConnection.current) {
        await peerConnection.current.addIceCandidate(new RTCIceCandidate(candidate));
      }
    } catch (error) {
      console.error('Error adding ICE candidate:', error);
    }
  }, []);

  // Reject incoming call
  const rejectCall = useCallback((callerAddress: string) => {
    sendMessage({
      type: 'call_reject',
      to: callerAddress,
    });

    setCallState({
      isActive: false,
      isCalling: false,
      isReceiving: false,
      callType,
      startTime: null,
      remoteAddress: null,
    });
  }, [callType, sendMessage]);

  // End call
  const endCall = useCallback(async () => {
    // Stop all tracks
    if (localStream) {
      localStream.getTracks().forEach(track => track.stop());
      setLocalStream(null);
    }

    // Close peer connection
    if (peerConnection.current) {
      peerConnection.current.close();
      peerConnection.current = null;
    }

    // Notify remote peer
    if (callState.remoteAddress) {
      sendMessage({
        type: 'call_end',
        to: callState.remoteAddress,
      });
    }

    // Update call log
    if (callLogId.current && callState.startTime) {
      const duration = Math.floor((new Date().getTime() - callState.startTime.getTime()) / 1000);
      await fetch(`/api/call-logs/${callLogId.current}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
          status: 'ended',
          endedAt: new Date().toISOString(),
          duration,
        }),
      });
    }

    setCallState({
      isActive: false,
      isCalling: false,
      isReceiving: false,
      callType,
      startTime: null,
      remoteAddress: null,
    });

    setRemoteStream(null);
    callLogId.current = null;

    if (onCallEnd) {
      onCallEnd();
    }

    console.log('📞 Call ended');
  }, [localStream, callState, callType, sendMessage, onCallEnd]);

  // Toggle video
  const toggleVideo = useCallback(() => {
    if (localStream) {
      const videoTrack = localStream.getVideoTracks()[0];
      if (videoTrack) {
        videoTrack.enabled = !videoTrack.enabled;
        return videoTrack.enabled;
      }
    }
    return false;
  }, [localStream]);

  // Toggle audio
  const toggleAudio = useCallback(() => {
    if (localStream) {
      const audioTrack = localStream.getAudioTracks()[0];
      if (audioTrack) {
        audioTrack.enabled = !audioTrack.enabled;
        return audioTrack.enabled;
      }
    }
    return false;
  }, [localStream]);

  // Listen for WebSocket messages
  useEffect(() => {
    if (!socket) return;

    const handleMessage = (event: MessageEvent) => {
      const message = JSON.parse(event.data);

      switch (message.type) {
        case 'incoming_call':
          setCallState({
            isActive: false,
            isCalling: false,
            isReceiving: true,
            callType: message.callType,
            startTime: null,
            remoteAddress: message.from,
          });
          // Store offer for when user accepts
          (window as any).__pendingCallOffer = {
            offer: message.offer,
            from: message.from,
            callType: message.callType,
          };
          break;

        case 'call_answered':
          handleCallAnswer(message.answer);
          break;

        case 'ice_candidate':
          handleIceCandidate(message.candidate);
          break;

        case 'call_rejected':
          console.log('❌ Call rejected by:', message.from);
          endCall();
          break;

        case 'call_ended':
          console.log('📞 Call ended by remote peer');
          endCall();
          break;

        case 'call_failed':
          console.log('❌ Call failed:', message.reason);
          endCall();
          break;
      }
    };

    socket.addEventListener('message', handleMessage);

    return () => {
      socket.removeEventListener('message', handleMessage);
    };
  }, [socket, handleCallAnswer, handleIceCandidate, endCall]);

  // Accept pending call
  const acceptPendingCall = useCallback(async () => {
    console.log('🟢 Accept button clicked!');
    const pendingCall = (window as any).__pendingCallOffer;
    console.log('📞 Pending call data:', pendingCall);

    if (pendingCall) {
      try {
        console.log('✅ Answering call from:', pendingCall.from);
        await answerCall(pendingCall.offer, pendingCall.from);
        delete (window as any).__pendingCallOffer;
        console.log('✅ Call answered successfully');
      } catch (error) {
        console.error('❌ Error answering call:', error);
        alert(`Could not answer call: ${error instanceof Error ? error.message : 'Unknown error'}`);
      }
    } else {
      console.error('❌ No pending call found!');
      alert('No incoming call to answer. Please try again.');
    }
  }, [answerCall]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (localStream) {
        localStream.getTracks().forEach(track => track.stop());
      }
      if (peerConnection.current) {
        peerConnection.current.close();
      }
    };
  }, [localStream]);

  return {
    callState,
    localStream,
    remoteStream,
    startCall,
    answerCall: acceptPendingCall,
    rejectCall,
    endCall,
    toggleVideo,
    toggleAudio,
  };
}

