import { useEffect, useRef, useState } from 'react';
import { Dialog, DialogContent } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Phone, PhoneOff, Mic, MicOff, Video, VideoOff } from 'lucide-react';

interface CallModalProps {
  isOpen: boolean;
  callState: {
    isActive: boolean;
    isCalling: boolean;
    isReceiving: boolean;
    callType: 'voice' | 'video';
    startTime: Date | null;
    remoteAddress: string | null;
  };
  localStream: MediaStream | null;
  remoteStream: MediaStream | null;
  onEndCall: () => void;
  onToggleAudio: () => boolean;
  onToggleVideo: () => boolean;
  remoteContactName?: string;
}

export function CallModal({
  isOpen,
  callState,
  localStream,
  remoteStream,
  onEndCall,
  onToggleAudio,
  onToggleVideo,
  remoteContactName,
}: CallModalProps) {
  const localVideoRef = useRef<HTMLVideoElement>(null);
  const remoteVideoRef = useRef<HTMLVideoElement>(null);
  const remoteAudioRef = useRef<HTMLAudioElement>(null);
  const [isMuted, setIsMuted] = useState(false);
  const [isVideoOff, setIsVideoOff] = useState(false);
  const [callDuration, setCallDuration] = useState('00:00');

  // Set up local video stream
  useEffect(() => {
    if (localVideoRef.current && localStream) {
      localVideoRef.current.srcObject = localStream;
    }
  }, [localStream]);

  // Set up remote video stream
  useEffect(() => {
    if (remoteVideoRef.current && remoteStream) {
      remoteVideoRef.current.srcObject = remoteStream;
    }
  }, [remoteStream]);

  // Set up remote audio stream (for voice calls and video calls)
  useEffect(() => {
    if (remoteAudioRef.current && remoteStream) {
      remoteAudioRef.current.srcObject = remoteStream;
      console.log('🔊 Remote audio stream attached');
    }
  }, [remoteStream]);

  // Call duration timer
  useEffect(() => {
    if (!callState.startTime) {
      setCallDuration('00:00');
      return;
    }

    const interval = setInterval(() => {
      const elapsed = Math.floor((new Date().getTime() - callState.startTime!.getTime()) / 1000);
      const minutes = Math.floor(elapsed / 60);
      const seconds = elapsed % 60;
      setCallDuration(`${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`);
    }, 1000);

    return () => clearInterval(interval);
  }, [callState.startTime]);

  const handleToggleAudio = () => {
    const enabled = onToggleAudio();
    setIsMuted(!enabled);
  };

  const handleToggleVideo = () => {
    const enabled = onToggleVideo();
    setIsVideoOff(!enabled);
  };

  const displayAddress = callState.remoteAddress 
    ? `${callState.remoteAddress.slice(0, 6)}...${callState.remoteAddress.slice(-4)}`
    : 'Unknown';

  return (
    <Dialog open={isOpen} onOpenChange={() => {}}>
      <DialogContent className="max-w-4xl p-0 gap-0 bg-gray-900 border-gray-800">
        {/* Hidden audio element for remote stream (CRITICAL for voice calls) */}
        <audio ref={remoteAudioRef} autoPlay playsInline className="hidden" />

        <div className="relative w-full h-[600px] bg-gray-900">
          {/* Remote video (main view) */}
          {callState.callType === 'video' ? (
            <video
              ref={remoteVideoRef}
              autoPlay
              playsInline
              className="w-full h-full object-cover"
              data-testid="video-remote"
            />
          ) : (
            <div className="w-full h-full flex items-center justify-center bg-gradient-to-br from-blue-600 to-purple-600">
              <div className="text-center">
                <div className="w-32 h-32 rounded-full bg-white/20 flex items-center justify-center mx-auto mb-4">
                  <span className="text-5xl text-white font-bold">
                    {(remoteContactName || displayAddress).charAt(0).toUpperCase()}
                  </span>
                </div>
                <p className="text-white text-xl font-semibold" data-testid="text-remote-name">
                  {remoteContactName || displayAddress}
                </p>
              </div>
            </div>
          )}

          {/* Local video (picture-in-picture) */}
          {callState.callType === 'video' && localStream && (
            <div className="absolute top-4 right-4 w-48 h-36 rounded-lg overflow-hidden border-2 border-white/30 shadow-xl">
              <video
                ref={localVideoRef}
                autoPlay
                playsInline
                muted
                className="w-full h-full object-cover"
                data-testid="video-local"
              />
            </div>
          )}

          {/* Call status overlay */}
          <div className="absolute top-4 left-4 bg-black/50 backdrop-blur-sm px-4 py-2 rounded-full">
            <p className="text-white text-sm font-medium" data-testid="text-call-status">
              {callState.isCalling && '📞 Calling...'}
              {callState.isActive && `🔴 ${callDuration}`}
            </p>
          </div>

          {/* Call controls */}
          <div className="absolute bottom-8 left-1/2 transform -translate-x-1/2 flex items-center gap-4">
            {/* Mute/Unmute */}
            <Button
              size="lg"
              variant={isMuted ? "destructive" : "secondary"}
              className="rounded-full w-14 h-14"
              onClick={handleToggleAudio}
              data-testid="button-toggle-audio"
            >
              {isMuted ? <MicOff className="w-6 h-6" /> : <Mic className="w-6 h-6" />}
            </Button>

            {/* Video toggle (only for video calls) */}
            {callState.callType === 'video' && (
              <Button
                size="lg"
                variant={isVideoOff ? "destructive" : "secondary"}
                className="rounded-full w-14 h-14"
                onClick={handleToggleVideo}
                data-testid="button-toggle-video"
              >
                {isVideoOff ? <VideoOff className="w-6 h-6" /> : <Video className="w-6 h-6" />}
              </Button>
            )}

            {/* End call */}
            <Button
              size="lg"
              variant="destructive"
              className="rounded-full w-16 h-16 bg-red-600 hover:bg-red-700"
              onClick={onEndCall}
              data-testid="button-end-call"
            >
              <PhoneOff className="w-7 h-7" />
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

