import { useEffect, useRef } from 'react';
import { Dialog, DialogContent } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Phone, PhoneOff, Video } from 'lucide-react';

interface IncomingCallProps {
  isOpen: boolean;
  callerAddress: string;
  callerName?: string;
  callType: 'voice' | 'video';
  onAccept: () => void;
  onReject: () => void;
}

export function IncomingCall({
  isOpen,
  callerAddress,
  callerName,
  callType,
  onAccept,
  onReject,
}: IncomingCallProps) {
  const ringtoneRef = useRef<HTMLAudioElement | null>(null);
  const displayAddress = `${callerAddress.slice(0, 6)}...${callerAddress.slice(-4)}`;
  const displayName = callerName || displayAddress;

  // Play ringtone when call comes in
  useEffect(() => {
    if (isOpen) {
      const audioContext = new AudioContext();
      let currentOscillator: OscillatorNode | null = null;

      const playRing = () => {
        // Create a NEW oscillator each time (can't reuse oscillators)
        const oscillator = audioContext.createOscillator();
        const gainNode = audioContext.createGain();

        oscillator.connect(gainNode);
        gainNode.connect(audioContext.destination);

        oscillator.frequency.value = 480; // Ringtone frequency  
        oscillator.type = 'sine';
        gainNode.gain.value = 0.3;

        oscillator.start();
        currentOscillator = oscillator;

        // Stop after 1 second
        setTimeout(() => {
          try {
            oscillator.stop();
          } catch (e) {
            // Already stopped
          }
        }, 1000);
      };

      // Play first ring immediately
      playRing();
      // Then repeat every 2 seconds
      const ringInterval = setInterval(playRing, 2000);

      return () => {
        clearInterval(ringInterval);
        if (currentOscillator) {
          try {
            currentOscillator.stop();
          } catch (e) {
            // Already stopped
          }
        }
        audioContext.close();
      };
    }
  }, [isOpen]);

  return (
    <Dialog open={isOpen} onOpenChange={() => {}}>
      <DialogContent className="max-w-md bg-gradient-to-br from-blue-600 to-purple-600 border-none text-white">
        <div className="text-center py-6">
          {/* Caller avatar */}
          <div className="w-24 h-24 rounded-full bg-white/20 flex items-center justify-center mx-auto mb-4 animate-pulse">
            <span className="text-4xl font-bold">
              {displayName.charAt(0).toUpperCase()}
            </span>
          </div>

          {/* Caller info */}
          <h2 className="text-2xl font-bold mb-2" data-testid="text-caller-name">
            {displayName}
          </h2>
          <p className="text-white/80 text-sm mb-1" data-testid="text-caller-address">
            {displayAddress}
          </p>
          <p className="text-white/60 text-sm mb-6" data-testid="text-call-type">
            Incoming {callType === 'video' ? 'video' : 'voice'} call
          </p>

          {/* Call actions */}
          <div className="flex justify-center gap-6">
            {/* Reject */}
            <div className="text-center">
              <Button
                size="lg"
                variant="destructive"
                className="rounded-full w-16 h-16 bg-red-600 hover:bg-red-700"
                onClick={onReject}
                data-testid="button-reject-call"
              >
                <PhoneOff className="w-7 h-7" />
              </Button>
              <p className="text-sm mt-2">Decline</p>
            </div>

            {/* Accept */}
            <div className="text-center">
              <Button
                size="lg"
                className="rounded-full w-16 h-16 bg-green-600 hover:bg-green-700"
                onClick={onAccept}
                data-testid="button-accept-call"
              >
                {callType === 'video' ? (
                  <Video className="w-7 h-7" />
                ) : (
                  <Phone className="w-7 h-7" />
                )}
              </Button>
              <p className="text-sm mt-2">Accept</p>
            </div>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

