  const [paymentConfirmOpen, setPaymentConfirmOpen] = useState(false);

  // Certificate viewing state
  const [viewCertificateDialogOpen, setViewCertificateDialogOpen] = useState(false);
  const [viewingCertificate, setViewingCertificate] = useState<any>(null);
  const [viewingCertificateContent, setViewingCertificateContent] = useState("");

  // Invoice viewing state
  const [viewInvoiceDialogOpen, setViewInvoiceDialogOpen] = useState(false);
  const [viewingInvoice, setViewingInvoice] = useState<any>(null);
  const [invoiceContent, setInvoiceContent] = useState("");

  // Claim dialog state
  const [claimDialogOpen, setClaimDialogOpen] = useState(false);
  const [selectedClaimApp, setSelectedClaimApp] = useState<any>(null);

  // BoL upload dialog state
  const [bolUploadDialogOpen, setBolUploadDialogOpen] = useState(false);
  const [selectedBolUploadApp, setSelectedBolUploadApp] = useState<any>(null);
  const [bolNumber, setBolNumber] = useState("");
  const [bolTrackingNumber, setBolTrackingNumber] = useState("");
  const [bolLogisticsProvider, setBolLogisticsProvider] = useState("");
  const [invoiceFileUrl, setInvoiceFileUrl] = useState<string | null>(null);
  const [invoiceDocument, setInvoiceDocument] = useState<any>(null);

  // NEW: Trade Lifecycle UI state (80% coverage + BoL custody)
  const [buyerPaymentDialogOpen, setBuyerPaymentDialogOpen] = useState(false);
  const [selectedBuyerPaymentApp, setSelectedBuyerPaymentApp] = useState<any>(null);
