      // Get private key from session storage
      const privateKey = sessionStorage.getItem('wallet_private_key_session');
      if (!privateKey) {
        throw new Error("Wallet not unlocked. Please unlock your wallet first.");
      }

      const sellerAddress = selectedBuyerPaymentApp.sellerAddress;
      const requestedAmount = parseFloat(selectedBuyerPaymentApp.requestedAmount);
      const totalPaid = parseFloat(selectedBuyerPaymentApp.totalAmountPaid || "0");
      const remainingBalance = requestedAmount - totalPaid;

      // Use custom amount if provided, otherwise use remaining balance
      let paymentAmount: number;
      if (customPaymentAmount && customPaymentAmount.trim() !== "") {
        paymentAmount = parseFloat(customPaymentAmount);
        if (isNaN(paymentAmount)) {
          throw new Error("Please enter a valid payment amount");
        }
      } else {
        paymentAmount = remainingBalance;
      }

      // Round to 2 decimals for USDC precision
      paymentAmount = Math.round(paymentAmount * 100) / 100;

      // Validate payment amount
      if (paymentAmount <= 0) {
        throw new Error("Payment amount must be greater than 0");
      }
      if (paymentAmount > remainingBalance + 0.01) { // Allow 1 cent tolerance for rounding
        throw new Error(`Payment amount (${paymentAmount.toFixed(2)} USDC) exceeds remaining balance (${remainingBalance.toFixed(2)} USDC)`);
      }

      const amount = paymentAmount.toString();

      console.log(`💸 Initiating payment of ${amount} USDC to ${sellerAddress}`);

      const result = await sendUSDCPayment(privateKey, sellerAddress, amount);

      if (result.success && result.txHash) {
        // Auto-fill the transaction hash and amount
        setBuyerPaymentTxHash(result.txHash);
        setBuyerPaymentAmount(amount);

        // Automatically submit the payment proof
