      },
      { 
        id: 5, 
        label: "Cert Issued", 
        completed: step5Completed,
        isCurrent: app.status === 'fee_paid'
      },
      { 
        id: 6, 
        label: "Goods Shipped", 
        completed: step6Completed,
        isCurrent: app.status === 'approved' && !app.bolUploadedToTreasury
      },
      { 
        id: 7, 
        label: "Delivery Confirmed", 
        completed: step7Completed,
        isCurrent: app.bolUploadedToTreasury && !app.buyerConfirmedDelivery
      },
      { 
        id: 8, 
        label: "Payment Complete", 
        completed: step8Completed,
        isCurrent: app.buyerConfirmedDelivery && !app.buyerPaymentUploaded
      }
    ];

    return steps;
  };

  // Early return after all hooks are initialized
  if (!wallet?.address) {
    return (
      <Card>
        <CardContent className="pt-6">
          <p className="text-center text-muted-foreground">Please connect your wallet to access Workflow Management</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-4">
      {/* Role Switcher - Buyer & Seller only */}
      <Card>
        <CardContent className="pt-6">
          <div className="flex items-center justify-between">
            <div>
              <h3 className="font-semibold text-lg">I am a...</h3>
              <p className="text-sm text-muted-foreground">Select your role in the trade finance process</p>
            </div>
            <div className="flex gap-2">
              <Button
                variant={userRole === "buyer" ? "default" : "outline"}
                onClick={() => setUserRole("buyer")}
                data-testid="button-role-buyer"
              >
                <UserIcon className="h-4 w-4 mr-2" />
                Buyer
              </Button>
              <Button
                variant={userRole === "seller" ? "default" : "outline"}
                onClick={() => setUserRole("seller")}
                data-testid="button-role-seller"
              >
                <BuildingIcon className="h-4 w-4 mr-2" />
                Seller
              </Button>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Buyer Actions */}
      {userRole === "buyer" && (
        <Card>
          <CardHeader>
            <div className="flex justify-between items-center">
              <div>
                <CardTitle>My Pool Guarantee Applications</CardTitle>
                <CardDescription>Apply for new guarantees and track your applications</CardDescription>
              </div>
              <Button onClick={() => setShowApplicationForm(true)} data-testid="button-open-pool-guarantee-form">
                Apply for Pool Guarantee
              </Button>
            </div>
          </CardHeader>
        </Card>
      )}

      {/* Applications List */}
      <Card>
        <CardHeader>
          <CardTitle>
            {userRole === "buyer" && "Your Pool Guarantee Applications"}
            {userRole === "seller" && "Drafts Awaiting Your Approval"}
          </CardTitle>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <div className="flex justify-center py-8">
              <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
            </div>
          ) : filteredApplications.length === 0 ? (
            <p className="text-center text-muted-foreground py-8">
              {userRole === "buyer" && "No applications yet. Click 'Apply for Pool Guarantee' to get started."}
              {userRole === "seller" && "No pending draft approvals at this time."}
            </p>
          ) : (
            <div className="space-y-4">
              {filteredApplications.map((app: any) => (
                <div key={app.requestId} className="border rounded-lg p-4 space-y-3">
                  <div className="flex justify-between items-start">
                    <div>
                      <h4 className="font-semibold">{app.buyerCompanyName}</h4>
                      <p className="text-sm text-muted-foreground">Request ID: {app.requestId}</p>
                    </div>
                    <Badge className={
                      app.status === 'approved'
                      ? 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200'
                      : app.status === 'draft_sent_to_seller'
                      ? 'bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200'
                      : app.status === 'seller_approved'
                      ? 'bg-purple-100 text-purple-800 dark:bg-purple-900 dark:text-purple-200'
                      : app.status === 'awaiting_fee_payment'
                      ? 'bg-orange-100 text-orange-800 dark:bg-orange-900 dark:text-orange-200'
                      : app.status === 'fee_paid'
                      ? 'bg-indigo-100 text-indigo-800 dark:bg-indigo-900 dark:text-indigo-200'
                      : app.status === 'seller_rejected'
                      ? 'bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200'
                      : 'bg-gray-100 text-gray-800 dark:bg-gray-800 dark:text-gray-200'
                    }>
                      {getStatusLabel(app.status)}
                    </Badge>
                  </div>

                  {/* Workflow Progress Indicator - Horizontal */}
                  {(app.status !== 'seller_rejected' && app.status !== 'rejected') && (
                    <div className="border border-gray-200 dark:border-gray-700 rounded-lg p-3">
                      <div className="flex items-center justify-between gap-2 mb-2">
                        {getWorkflowSteps(app).map((step, index) => {
                          const isLast = index === getWorkflowSteps(app).length - 1;
                          return (
                            <div key={step.id} className="flex items-center flex-1">
                              <div className="flex flex-col items-center flex-1">
                                <div className={`w-8 h-8 rounded-full flex items-center justify-center ${
                                  step.completed 
                                    ? 'bg-green-500 text-white' 
                                    : step.isCurrent 
                                    ? 'bg-blue-500 text-white animate-pulse' 
                                    : 'bg-gray-200 dark:bg-gray-700 text-gray-400'
                                }`}>
                                  {step.completed ? (
                                    <CheckCircle2 className="h-5 w-5" />
                                  ) : (
                                    <span className="text-xs font-bold">{step.id}</span>
                                  )}
                                </div>
                                <p className={`text-xs mt-1 text-center ${
                                  step.completed 
                                    ? 'text-green-600 dark:text-green-400 font-medium' 
                                    : step.isCurrent 
                                    ? 'text-blue-600 dark:text-blue-400 font-medium' 
                                    : 'text-gray-500'
                                }`}>
                                  {step.label}
                                </p>
                              </div>
                              {!isLast && (
                                <div className={`h-0.5 flex-1 ${
                                  step.completed ? 'bg-green-500' : 'bg-gray-200 dark:bg-gray-700'
                                }`}></div>
                              )}
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  )}

                  {/* Conditional display based on role */}
                  {userRole === "buyer" ? (
                    <div className="grid grid-cols-2 gap-2 text-sm">
                      <div><span className="text-muted-foreground">Amount:</span> {parseFloat(app.requestedAmount).toFixed(2)} USDC</div>
                      <div><span className="text-muted-foreground">Seller:</span> {app.sellerCompanyName || 'N/A'}</div>
                      <div className="col-span-2"><span className="text-muted-foreground">Trade:</span> {app.tradeDescription}</div>
                      {app.feeDue && <div><span className="text-muted-foreground">Fee:</span> {parseFloat(app.feeDue).toFixed(2)} USDC</div>}
                    </div>
                  ) : (
                    <div className="space-y-4">
                      {/* Risk Exposure Section - Most Important for Sellers */}
                      <div className="bg-amber-50 dark:bg-amber-950/20 border border-amber-200 dark:border-amber-800 rounded-lg p-3">
                        <h5 className="font-semibold text-sm mb-2 flex items-center gap-2">
                          <AlertCircle className="h-4 w-4 text-amber-600" />
                          Your Risk Exposure
                        </h5>
                        <div className="grid grid-cols-3 gap-3 text-sm">
                          <div>
                            <p className="text-xs text-muted-foreground">Invoice Amount</p>
                            <p className="font-bold text-lg">{parseFloat(app.requestedAmount).toFixed(2)} USDC</p>
                          </div>
                          <div>
                            <p className="text-xs text-muted-foreground">Treasury Coverage (80%)</p>
                            <p className="font-semibold text-green-600">{app.guaranteeCoverageAmount ? parseFloat(app.guaranteeCoverageAmount).toFixed(2) : (parseFloat(app.requestedAmount) * 0.80).toFixed(2)} USDC</p>
                          </div>
                          <div>
                            <p className="text-xs text-muted-foreground">Your Risk (20%)</p>
                            <p className="font-semibold text-red-600">{app.sellerRiskAmount ? parseFloat(app.sellerRiskAmount).toFixed(2) : (parseFloat(app.requestedAmount) * 0.20).toFixed(2)} USDC</p>
                          </div>
                        </div>
                        <p className="text-xs text-amber-800 dark:text-amber-200 mt-2">
                          If buyer defaults, Treasury will pay you 80% and you will bear 20% loss. Treasury will liquidate goods using Bill of Lading.
                        </p>
                      </div>

                      {/* Buyer Information */}
                      <div className="border-l-2 border-blue-500 pl-3 space-y-2">
                        <h5 className="font-semibold text-sm">Buyer Information</h5>
                        <div className="grid grid-cols-2 gap-2 text-sm">
                          {app.buyerCompanyName && (
                            <div>
                              <p className="text-xs text-muted-foreground">Company Name</p>
                              <p className="font-medium">{app.buyerCompanyName}</p>
                            </div>
                          )}
                          {app.buyerCountry && (
                            <div>
                              <p className="text-xs text-muted-foreground">Country</p>
                              <p>{app.buyerCountry}</p>
                            </div>
                          )}
                          {app.buyerRegistrationNumber && (
                            <div>
                              <p className="text-xs text-muted-foreground">Registration Number</p>
                              <p className="font-mono text-xs">{app.buyerRegistrationNumber}</p>
                            </div>
                          )}
                          <div>
                            <p className="text-xs text-muted-foreground">Wallet Address</p>
                            <p className="font-mono text-xs">{app.buyerAddress?.slice(0, 10)}...{app.buyerAddress?.slice(-8)}</p>
                          </div>
                          {app.buyerContactPerson && (
                            <div>
                              <p className="text-xs text-muted-foreground">Contact Person</p>
                              <p>{app.buyerContactPerson}</p>
                            </div>
                          )}
                          {app.buyerEmail && (
                            <div>
                              <p className="text-xs text-muted-foreground">Email</p>
                              <p className="text-xs">{app.buyerEmail}</p>
                            </div>
                          )}
                        </div>
                      </div>

                      {/* Trade Contract Details */}
                      <div className="border-l-2 border-purple-500 pl-3 space-y-2">
                        <h5 className="font-semibold text-sm">Trade Contract Details</h5>
                        <div className="space-y-2 text-sm">
                          <div>
                            <p className="text-xs text-muted-foreground">Trade Description</p>
                            <p className="mt-1">{app.tradeDescription}</p>
                          </div>
                          {app.collateralDescription && (
                            <div>
                              <p className="text-xs text-muted-foreground">Collateral (Goods)</p>
                              <p className="mt-1">{app.collateralDescription}</p>
                            </div>
                          )}
                          <div className="grid grid-cols-2 gap-2">
                            {app.salesContractNumber && (
                              <div>
                                <p className="text-xs text-muted-foreground">Contract Number</p>
                                <p className="font-mono text-xs">{app.salesContractNumber}</p>
                              </div>
                            )}
                            {app.tradeValue && (
                              <div>
                                <p className="text-xs text-muted-foreground">Total Trade Value</p>
                                <p className="font-semibold">{parseFloat(app.tradeValue).toFixed(2)} USDC</p>
                              </div>
                            )}
                          </div>
                        </div>
                      </div>

                      {/* Financial Terms & Timeline */}
                      <div className="grid grid-cols-2 gap-4 text-sm">
                        <div>
                          <p className="text-xs text-muted-foreground">Financing Duration</p>
                          <p className="font-semibold">{app.requestedDuration || 'N/A'} days</p>
                        </div>
                        <div>
                          <p className="text-xs text-muted-foreground">Payment Due Date</p>
                          <p className="font-semibold">{app.paymentDueDate ? new Date(app.paymentDueDate).toLocaleDateString() : 'N/A'}</p>
                        </div>
                        <div>
                          <p className="text-xs text-muted-foreground">Issuance Fee (1%)</p>
                          <p className="font-semibold text-blue-600">{app.feeDue ? parseFloat(app.feeDue).toFixed(2) : (parseFloat(app.requestedAmount) * 0.01).toFixed(2)} USDC</p>
                        </div>
                        <div>
                          <p className="text-xs text-muted-foreground">Application Date</p>
                          <p>{app.createdAt ? new Date(app.createdAt).toLocaleDateString() : 'N/A'}</p>
                        </div>
                      </div>

                      {/* Seller Obligations & Decision Explanation - Only show when draft is ready for approval */}
                      {app.status === "draft_sent_to_seller" && (
                        <div className="bg-blue-50 dark:bg-blue-950/20 border border-blue-200 dark:border-blue-800 rounded-lg p-3">
                          <h5 className="font-semibold text-sm mb-2 flex items-center gap-2">
                            <Info className="h-4 w-4 text-blue-600" />
                            Your Decision & Obligations
                          </h5>
                          <div className="space-y-2 text-xs">
                            <div>
                              <p className="font-medium text-blue-900 dark:text-blue-200">If you APPROVE:</p>
                              <ul className="list-disc list-inside ml-2 space-y-1 text-blue-800 dark:text-blue-300">
                                <li>Buyer will be notified to pay 1% issuance fee</li>
                                <li>Once fee is paid, final Pool Guarantee certificate will be issued</li>
                                <li>You accept 20% risk exposure if buyer defaults</li>
                                <li>You must provide Bill of Lading to Treasury before shipment</li>
                                <li>Treasury will hold BoL as collateral until buyer pays or defaults</li>
                              </ul>
                            </div>
                            <div>
                              <p className="font-medium text-blue-900 dark:text-blue-200">If you REJECT:</p>
                              <ul className="list-disc list-inside ml-2 space-y-1 text-blue-800 dark:text-blue-300">
                                <li>The Pool Guarantee application will be cancelled</li>
                                <li>Buyer will be notified of rejection</li>
                                <li>You can provide a reason for rejection</li>
                                <li>No further action required from either party</li>
                              </ul>
                            </div>
                          </div>
                        </div>
                      )}
                    </div>
                  )}

                  {/* Role-based actions */}
                  <div className="flex gap-2 pt-2 flex-wrap">
                    {/* Buyer actions */}
                    {userRole === "buyer" && app.status === "awaiting_fee_payment" && (
                      <Button onClick={() => {
                        setSelectedPaymentApp(app);
                        setPaymentDialogOpen(true);
                      }} size="sm" data-testid={`button-pay-fee-${app.requestId}`}>
                        <DollarSignIcon className="h-4 w-4 mr-1" />
                        Pay Fee ({parseFloat(app.feeDue).toFixed(2)} USDC)
                      </Button>
                    )}

                    {/* View Certificate for buyers - show for any status with certificate */}
                    {userRole === "buyer" && (app.status === 'draft_sent_to_seller' || app.status === 'seller_approved' || app.status === 'awaiting_fee_payment' || app.status === 'fee_paid' || app.status === 'approved') && (
                      <Button 
                        variant="outline"
                        size="sm"
                        onClick={() => handleViewCertificate(app)}
                        data-testid={`button-view-certificate-workflow-${app.requestId}`}
                      >
                        <Eye className="h-4 w-4 mr-1" />
                        View {app.status === 'approved' ? 'Final' : 'Draft'} Certificate
                      </Button>
                    )}

                    {/* Buyer delivery confirmation - appears after seller ships goods */}
                    {userRole === "buyer" && app.status === 'approved' && 
                     (app.tradeLifecycleStatus === 'goods_shipped' || app.tradeLifecycleStatus === 'bol_in_treasury_custody') && 
                     !app.buyerConfirmedDelivery && (
                      <Button 
                        size="sm"
                        onClick={() => {
                          setSelectedBuyerDeliveryApp(app);
                          setBuyerDeliveryDialogOpen(true);
                        }}
                        className="bg-blue-600 hover:bg-blue-700"
                        data-testid={`button-confirm-delivery-${app.requestId}`}
                      >
                        <CheckCircleIcon className="h-4 w-4 mr-1" />
                        Confirm Delivery
                      </Button>
                    )}

                    {/* Settle Invoice - only appears AFTER buyer confirms delivery and if remaining balance */}
                    {userRole === "buyer" && app.status === 'approved' && app.buyerConfirmedDelivery && 
                     (parseFloat(app.totalAmountPaid || "0") < parseFloat(app.requestedAmount)) && (
                      <Button 
                        size="sm"
                        onClick={() => {
                          setSelectedBuyerPaymentApp(app);
                          setCustomPaymentAmount("");
                          setBuyerPaymentDialogOpen(true);
                        }}
                        className="bg-green-600 hover:bg-green-700"
                        data-testid={`button-settle-invoice-${app.requestId}`}
                      >
                        <DollarSignIcon className="h-4 w-4 mr-1" />
                        {parseFloat(app.totalAmountPaid || "0") > 0 ? "Pay Remaining" : "Settle Invoice"}
                      </Button>
                    )}

                    {/* Payment Status - show when payments have been made */}
                    {userRole === "buyer" && app.status === 'approved' && parseFloat(app.totalAmountPaid || "0") > 0 && (
                      <div className="text-xs text-muted-foreground mt-1">
                        Paid: {parseFloat(app.totalAmountPaid || "0").toFixed(2)} / {parseFloat(app.requestedAmount).toFixed(2)} USDC
                        {app.buyerPaymentUploaded && <span className="text-green-600 ml-2">✓ Fully Paid</span>}
                      </div>
                    )}

                    {/* Seller actions */}
                    {userRole === "seller" && app.status === "draft_sent_to_seller" && (
                      <>
                        <Button 
                          onClick={() => handleViewInvoice(app)}
                          size="sm" 
                          variant="outline"
                          data-testid={`button-view-invoice-${app.requestId}`}
                        >
                          <FileText className="h-4 w-4 mr-1" />
                          View Invoice
                        </Button>
                        <Button 
                          onClick={() => handleViewCertificate(app)}
                          size="sm" 
                          variant="outline"
                          data-testid={`button-view-draft-certificate-${app.requestId}`}
                        >
                          <Eye className="h-4 w-4 mr-1" />
                          View Draft
                        </Button>
                        <Button onClick={() => {
                          setSelectedReviewApp(app);
                          setReviewDialogOpen(true);
                        }} size="sm" className="bg-blue-600 hover:bg-blue-700" data-testid={`button-review-${app.requestId}`}>
                          <CheckCircleIcon className="h-4 w-4 mr-1" />
                          Approve / Reject
                        </Button>
                      </>
                    )}

                    {/* View Certificate for sellers - show after they've interacted with it */}
                    {userRole === "seller" && (app.status === 'awaiting_fee_payment' || app.status === 'fee_paid' || app.status === 'approved') && (
                      <Button 
                        variant="outline"
                        size="sm"
                        onClick={() => handleViewCertificate(app)}
                        data-testid={`button-view-certificate-seller-${app.requestId}`}
                      >
                        <Eye className="h-4 w-4 mr-1" />
                        View {app.status === 'approved' ? 'Final' : 'Draft'} Certificate
                      </Button>
                    )}

                    {/* Seller: Upload Shipment Proof (Step 6: Goods Shipped) - AFTER certificate is issued */}
                    {userRole === "seller" && app.status === 'approved' && !app.bolUploadedToTreasury && (
                      <Button 
                        size="sm"
                        onClick={() => {
                          setSelectedSellerBolApp(app);
                          setSellerBolDialogOpen(true);
                        }}
                        className="bg-blue-600 hover:bg-blue-700"
                        data-testid={`button-upload-shipment-proof-${app.requestId}`}
                      >
                        <Upload className="h-4 w-4 mr-1" />
                        Upload Shipment Proof
                      </Button>
                    )}

                    {/* Seller: Make Claim (if buyer defaults on payment after delivery) */}
                    {userRole === "seller" && app.status === 'approved' && app.buyerConfirmedDelivery && !app.buyerPaymentUploaded && (
                      <Button 
                        size="sm"
                        variant="destructive"
                        onClick={() => {
                          setSelectedClaimApp(app);
                          setClaimDialogOpen(true);
                        }}
                        data-testid={`button-make-claim-${app.requestId}`}
                      >
                        <AlertTriangle className="h-4 w-4 mr-1" />
                        File Default Claim
                      </Button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Application Form Dialog */}
      {showApplicationForm && (
        <Dialog open={showApplicationForm} onOpenChange={setShowApplicationForm}>
          <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>Apply for Pool Guarantee</DialogTitle>
              <DialogDescription>Submit your application for a blockchain-based trade finance guarantee</DialogDescription>
            </DialogHeader>
            <PoolGuaranteeApplication walletAddress={wallet.address} />
          </DialogContent>
        </Dialog>
      )}

      {/* Draft Creation Dialog */}
      <Dialog open={draftDialogOpen} onOpenChange={setDraftDialogOpen}>
        <DialogContent className="max-w-3xl max-h-[90vh]">
          <DialogHeader>
            <DialogTitle>Create Draft Pool Guarantee Certificate</DialogTitle>
            <DialogDescription>Review and customize the ICC URDG 758 compliant draft</DialogDescription>
          </DialogHeader>
          <Textarea
            value={draftCertificate}
            onChange={(e) => setDraftCertificate(e.target.value)}
            className="min-h-[400px] font-mono text-xs"
            data-testid="textarea-draft-certificate"
          />
          <DialogFooter>
            <Button variant="outline" onClick={() => setDraftDialogOpen(false)}>Cancel</Button>
            <Button onClick={() => createDraftMutation.mutate({ requestId: selectedDraftApp.requestId, certificate: draftCertificate })} disabled={createDraftMutation.isPending} data-testid="button-send-draft">
              {createDraftMutation.isPending ? "Sending..." : "Send Draft to Seller"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Seller Review Dialog */}
      <Dialog open={reviewDialogOpen} onOpenChange={setReviewDialogOpen}>
        <DialogContent className="max-w-3xl">
          <DialogHeader>
            <DialogTitle>Review Draft Certificate</DialogTitle>
          </DialogHeader>
          {selectedReviewApp && (
            <div className="space-y-4">
              <div className="border rounded p-3 bg-muted/30 space-y-1 text-sm">
                <p><strong>Request ID:</strong> {selectedReviewApp.requestId}</p>
                <p><strong>Buyer:</strong> {selectedReviewApp.buyerCompanyName}</p>
                <p><strong>Amount:</strong> {parseFloat(selectedReviewApp.requestedAmount).toFixed(2)} USDC</p>
              </div>
              <div>
                <Label>Draft Certificate (Read-Only)</Label>
                <Textarea
                  value={getDraftCertificate(selectedReviewApp.requestId)?.content || "Loading draft certificate..."}
                  readOnly
                  className="min-h-[300px] font-mono text-xs"
                  data-testid="textarea-view-draft"
                />
              </div>
              <div>
                <Label>Rejection Reason (optional)</Label>
                <Textarea
                  value={rejectionReason}
                  onChange={(e) => setRejectionReason(e.target.value)}
                  placeholder="Provide reason if rejecting..."
                  data-testid="textarea-rejection-reason"
                />
              </div>
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => {
              setReviewDialogOpen(false);
              setRejectionReason("");
            }}>Cancel</Button>
            <Button variant="destructive" onClick={() => rejectMutation.mutate({ requestId: selectedReviewApp.requestId, reason: rejectionReason })} disabled={rejectMutation.isPending} data-testid="button-reject-draft">
              {rejectMutation.isPending ? "Rejecting..." : "Reject"}
            </Button>
            <Button onClick={() => approveMutation.mutate(selectedReviewApp.requestId)} disabled={approveMutation.isPending} data-testid="button-approve-draft">
              {approveMutation.isPending ? "Approving..." : "Approve"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Fee Payment Dialog */}
      <Dialog open={paymentDialogOpen} onOpenChange={setPaymentDialogOpen}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>Pay Issuance Fee</DialogTitle>
            <DialogDescription>Pay the 1% issuance fee to complete your Pool Guarantee</DialogDescription>
          </DialogHeader>
          {selectedPaymentApp && (
            <div className="space-y-4">
              <div className="border rounded p-3 bg-muted/30 space-y-1 text-sm">
                <p><strong>Fee Due:</strong> {parseFloat(selectedPaymentApp.feeDue).toFixed(2)} USDC</p>
                <p><strong>Guarantee Amount:</strong> {parseFloat(selectedPaymentApp.requestedAmount).toFixed(2)} USDC</p>
              </div>

              {/* Treasury Address - Prominent Display */}
