                <p className="font-medium text-blue-900 dark:text-blue-100">⚠️ Important</p>
                <p className="text-blue-800 dark:text-blue-200 mt-1">
                  Only confirm if you have verified the payment in your wallet. After confirmation, you'll need to upload the Bill of Lading to Treasury custody.
                </p>
              </div>
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setSellerConfirmPaymentDialogOpen(false)}>Cancel</Button>
            <Button 
              onClick={() => confirmSellerPaymentMutation.mutate(selectedSellerConfirmApp.requestId)} 
              disabled={confirmSellerPaymentMutation.isPending}
              data-testid="button-confirm-seller-payment"
            >
              {confirmSellerPaymentMutation.isPending ? "Confirming..." : "Confirm Payment Received"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Seller: File Default Claim Dialog */}
      <Dialog open={claimDialogOpen} onOpenChange={setClaimDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>File Default Claim</DialogTitle>
            <DialogDescription>Submit a claim to treasury stakers for buyer payment default</DialogDescription>
          </DialogHeader>
          {selectedClaimApp && (
            <div className="space-y-4">
              <Alert variant="destructive">
                <AlertCircle className="h-4 w-4" />
                <AlertTitle>Buyer Default</AlertTitle>
                <AlertDescription>
                  The buyer confirmed delivery but has not uploaded payment proof. You can file a claim to recover funds from the Treasury pool (80% coverage).
                </AlertDescription>
              </Alert>

              <div className="border rounded p-3 bg-muted/30 space-y-1 text-sm">
                <p><strong>Buyer:</strong> {selectedClaimApp.buyerCompanyName}</p>
                <p><strong>Invoice Amount:</strong> {parseFloat(selectedClaimApp.requestedAmount).toFixed(2)} USDC</p>
                <p><strong>Treasury Coverage:</strong> {(parseFloat(selectedClaimApp.requestedAmount) * 0.8).toFixed(2)} USDC (80%)</p>
                <p><strong>Your Risk:</strong> {(parseFloat(selectedClaimApp.requestedAmount) * 0.2).toFixed(2)} USDC (20%)</p>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium">Claim Amount (USDC)</label>
                <Input
                  type="number"
                  placeholder={(parseFloat(selectedClaimApp.requestedAmount) * 0.8).toFixed(2)}
                  max={(parseFloat(selectedClaimApp.requestedAmount) * 0.8).toFixed(2)}
                  data-testid="input-claim-amount"
                  id="claim-amount"
                />
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium">Reason for Claim</label>
                <Textarea
                  placeholder="Describe the buyer default situation..."
                  rows={4}
                  data-testid="input-claim-reason"
                  id="claim-reason"
                />
              </div>

              <div className="bg-yellow-50 dark:bg-yellow-950 border border-yellow-200 dark:border-yellow-800 rounded p-3 text-sm">
                <p className="font-medium text-yellow-900 dark:text-yellow-100">📢 Voting Process</p>
                <p className="text-yellow-800 dark:text-yellow-200 mt-1">
                  Your claim will be reviewed by treasury stakers who will vote on approval. You'll be notified of the voting outcome.
                </p>
              </div>
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setClaimDialogOpen(false)}>Cancel</Button>
            <Button 
              variant="destructive"
              onClick={() => {
                const claimAmount = (document.getElementById('claim-amount') as HTMLInputElement)?.value;
                const claimReason = (document.getElementById('claim-reason') as HTMLTextAreaElement)?.value;

                if (!claimAmount || !claimReason) {
                  toast({ 
                    title: "Missing Information", 
                    description: "Please provide claim amount and reason", 
                    variant: "destructive" 
                  });
                  return;
                }

                fileClaimMutation.mutate({
                  requestId: selectedClaimApp.requestId,
                  claimAmount,
                  claimReason
                });
              }}
              disabled={fileClaimMutation.isPending}
              data-testid="button-submit-claim"
            >
              {fileClaimMutation.isPending ? "Submitting..." : "Submit Claim to Treasury"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* NEW: Seller BoL Upload Dialog (Step 8) */}
      <Dialog open={sellerBolDialogOpen} onOpenChange={setSellerBolDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Upload Bill of Lading to Treasury</DialogTitle>
            <DialogDescription>Transfer BoL custody to Treasury as collateral (80% guarantee coverage)</DialogDescription>
          </DialogHeader>
          {selectedSellerBolApp && (
            <div className="space-y-4">
              <div className="border rounded p-3 bg-muted/30 space-y-1 text-sm">
                <p><strong>Guarantee Amount:</strong> {parseFloat(selectedSellerBolApp.requestedAmount).toFixed(2)} USDC</p>
                <p><strong>Treasury Coverage:</strong> {(parseFloat(selectedSellerBolApp.requestedAmount) * 0.8).toFixed(2)} USDC (80%)</p>
                <p><strong>Your Risk:</strong> {(parseFloat(selectedSellerBolApp.requestedAmount) * 0.2).toFixed(2)} USDC (20%)</p>
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium">Bill of Lading Number</label>
                <input
                  type="text"
                  placeholder="BOL-2025-001234"
                  value={bolNumber}
                  onChange={(e) => setBolNumber(e.target.value)}
                  className="w-full border rounded px-3 py-2"
                  data-testid="input-bol-number"
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium">Tracking Number</label>
                <input
                  type="text"
                  placeholder="TRACK123456789"
                  value={bolTrackingNumber}
                  onChange={(e) => setBolTrackingNumber(e.target.value)}
                  className="w-full border rounded px-3 py-2"
                  data-testid="input-tracking-number"
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium">Logistics Provider</label>
                <input
                  type="text"
                  placeholder="Maersk, MSC, etc."
                  value={bolLogisticsProvider}
                  onChange={(e) => setBolLogisticsProvider(e.target.value)}
                  className="w-full border rounded px-3 py-2"
                  data-testid="input-logistics-provider"
                />
              </div>
              <div className="bg-amber-50 dark:bg-amber-950 border border-amber-200 dark:border-amber-800 rounded p-3 text-sm">
                <p className="font-medium text-amber-900 dark:text-amber-100">📋 Treasury Custody</p>
                <p className="text-amber-800 dark:text-amber-200 mt-1">
                  By uploading, you transfer BoL custody to Treasury. If buyer defaults, Treasury can sell goods using BoL to recover their 80% payment to you.
                </p>
              </div>
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setSellerBolDialogOpen(false)}>Cancel</Button>
            <Button 
              onClick={() => uploadSellerBolMutation.mutate({ 
                requestId: selectedSellerBolApp.requestId,
                bolNumber,
                trackingNumber: bolTrackingNumber,
                logisticsProvider: bolLogisticsProvider
              })} 
              disabled={uploadSellerBolMutation.isPending || !bolNumber || !bolTrackingNumber || !bolLogisticsProvider}
              data-testid="button-upload-bol"
            >
              {uploadSellerBolMutation.isPending ? "Uploading..." : "Upload BoL to Treasury"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* NEW: Buyer Delivery Confirmation Dialog (Step 10) */}
      <Dialog open={buyerDeliveryDialogOpen} onOpenChange={setBuyerDeliveryDialogOpen}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>Verify Shipment & Confirm Delivery</DialogTitle>
            <DialogDescription>Review shipment details and confirm receipt to release BoL from Treasury custody</DialogDescription>
          </DialogHeader>
          {selectedBuyerDeliveryApp && (
            <div className="space-y-4">
              {/* Trade Summary */}
              <div className="border rounded p-3 bg-muted/30 space-y-1 text-sm">
                <p><strong>Seller:</strong> {selectedBuyerDeliveryApp.sellerCompanyName}</p>
                <p><strong>Goods:</strong> {selectedBuyerDeliveryApp.goodsDescription}</p>
                <p><strong>Amount:</strong> {parseFloat(selectedBuyerDeliveryApp.requestedAmount).toFixed(2)} USDC</p>
              </div>

              {/* Shipment Tracking Details */}
              {selectedBuyerDeliveryApp.goodsCollateral && (
                <div className="border border-blue-200 dark:border-blue-800 rounded-lg p-4 bg-blue-50 dark:bg-blue-950/20 space-y-3">
                  <div className="flex items-center gap-2">
                    <Package className="h-5 w-5 text-blue-600 dark:text-blue-400" />
                    <h4 className="font-semibold text-blue-900 dark:text-blue-100">Shipment Tracking Details</h4>
                  </div>
                  <div className="grid gap-2 text-sm">
                    {selectedBuyerDeliveryApp.goodsCollateral.billOfLadingNumber && (
                      <div className="flex justify-between">
                        <span className="text-blue-700 dark:text-blue-300 font-medium">Bill of Lading Number:</span>
                        <span className="text-blue-900 dark:text-blue-100 font-mono" data-testid="text-bol-number">
                          {selectedBuyerDeliveryApp.goodsCollateral.billOfLadingNumber}
                        </span>
                      </div>
                    )}
                    {selectedBuyerDeliveryApp.goodsCollateral.trackingNumber && (
                      <div className="flex justify-between">
                        <span className="text-blue-700 dark:text-blue-300 font-medium">Tracking Number:</span>
                        <span className="text-blue-900 dark:text-blue-100 font-mono" data-testid="text-tracking-number">
                          {selectedBuyerDeliveryApp.goodsCollateral.trackingNumber}
                        </span>
                      </div>
                    )}
                    {selectedBuyerDeliveryApp.goodsCollateral.logisticsProvider && (
                      <div className="flex justify-between">
                        <span className="text-blue-700 dark:text-blue-300 font-medium">Logistics Provider:</span>
                        <span className="text-blue-900 dark:text-blue-100" data-testid="text-logistics-provider">
                          {selectedBuyerDeliveryApp.goodsCollateral.logisticsProvider}
                        </span>
                      </div>
                    )}
                    {selectedBuyerDeliveryApp.goodsCollateral.actualShipmentDate && (
                      <div className="flex justify-between">
                        <span className="text-blue-700 dark:text-blue-300 font-medium">Shipment Date:</span>
                        <span className="text-blue-900 dark:text-blue-100" data-testid="text-shipment-date">
                          {new Date(selectedBuyerDeliveryApp.goodsCollateral.actualShipmentDate).toLocaleDateString()}
                        </span>
                      </div>
                    )}
                  </div>
                  <div className="bg-blue-100 dark:bg-blue-900/40 rounded p-2 text-xs text-blue-800 dark:text-blue-200">
                    <strong>Note:</strong> Treasury holds the Bill of Lading as collateral. Use the tracking details above to verify shipment status with the logistics provider.
                  </div>
                </div>
              )}

              {/* Delivery Condition */}
              <div className="space-y-2">
                <label className="text-sm font-medium">Delivery Condition</label>
                <select
                  value={deliveryCondition}
                  onChange={(e) => setDeliveryCondition(e.target.value)}
                  className="w-full border rounded px-3 py-2"
                  data-testid="select-delivery-condition"
                >
                  <option value="excellent">Excellent - As Described</option>
                  <option value="good">Good - Minor Issues</option>
                  <option value="acceptable">Acceptable - Within Tolerance</option>
                </select>
              </div>

              {/* Completion Notice */}
              <div className="bg-green-50 dark:bg-green-950 border border-green-200 dark:border-green-800 rounded p-3 text-sm">
                <p className="font-medium text-green-900 dark:text-green-100">✅ Trade Complete</p>
                <p className="text-green-800 dark:text-green-200 mt-1">
                  Confirming delivery releases the Bill of Lading from Treasury custody to you, completing the trade.
                </p>
              </div>
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setBuyerDeliveryDialogOpen(false)}>Cancel</Button>
            <Button 
              onClick={() => confirmDeliveryMutation.mutate({ 
                requestId: selectedBuyerDeliveryApp.requestId,
                condition: deliveryCondition
              })} 
              disabled={confirmDeliveryMutation.isPending}
              data-testid="button-confirm-delivery"
            >
              {confirmDeliveryMutation.isPending ? "Confirming..." : "Confirm Delivery"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

