import { ethers } from 'ethers';
import { walletManager } from './wallet';
import { getTokenBySymbol, getTokensForNetwork } from './tokens';
import { getNetworkByChainId } from './networks';

// Treasury Pool Wallet - This is where all staked USDC tokens are held
// Treasury Address (PUBLIC - safe to share):
// 0xcAA69BE342a0fA76dfC87b2fE14E403255F9ce0F
// 
// SECURITY NOTE: The private key for this treasury is NOT stored in code.
// It should be stored securely by the platform administrator.
// Users stake TO this address, withdrawals managed separately.
const TREASURY_POOL_ADDRESS = "0xcAA69BE342a0fA76dfC87b2fE14E403255F9ce0F";

// Helper to convert chainId to network.id for token lookup
function chainIdToNetworkId(chainId: number): number {
  // Base Sepolia: chainId = 84532, network.id = 1
  // Lisk Sepolia: chainId = 4202, network.id = 2
  if (chainId === 84532) return 1;
  if (chainId === 4202) return 2;
  return chainId;
}

export interface StakeParams {
  amount: string;
  tokenAddress: string;
  tokenSymbol: string;
  networkId: number; // This is chainId from the wallet
}

export class StakingManager {
  /**
   * Get the treasury pool address where staked tokens are held
   */
  getTreasuryAddress(): string {
    return TREASURY_POOL_ADDRESS;
  }

  async stakeTokens(params: StakeParams): Promise<{ txHash: string; amount: string }> {
    try {
      console.log('💰 Staking tokens to Treasury Pool:', params);

      // Convert chainId to network.id for token lookup
      const networkIdForTokenLookup = chainIdToNetworkId(params.networkId);

      // Get the token configuration
      const token = getTokenBySymbol(networkIdForTokenLookup, params.tokenSymbol);
      if (!token) {
        throw new Error(`Token ${params.tokenSymbol} not supported on this network`);
      }

      // Get signer (uses chainId)
      const signer = await walletManager.getSigner(params.networkId);
      if (!signer) {
        throw new Error('Wallet not unlocked - signer not available');
      }

      // Check user's token balance
      const userAddress = await signer.getAddress();
      const tokenContract = new ethers.Contract(
        params.tokenAddress,
        [
          "function balanceOf(address owner) view returns (uint256)",
          "function transfer(address to, uint256 amount) returns (bool)"
        ],
        signer
      );

      const balance = await tokenContract.balanceOf(userAddress);
      const amountInWei = ethers.parseUnits(params.amount, token.decimals);

      if (balance < amountInWei) {
        throw new Error(`Insufficient ${params.tokenSymbol} balance. You have ${ethers.formatUnits(balance, token.decimals)} ${params.tokenSymbol}`);
      }

      console.log(`✓ Token balance verified: ${ethers.formatUnits(balance, token.decimals)} ${params.tokenSymbol}`);

      // Transfer tokens directly to Treasury Pool
      console.log(`📤 Transferring ${params.amount} ${params.tokenSymbol} to Treasury Pool...`);
      const tx = await tokenContract.transfer(TREASURY_POOL_ADDRESS, amountInWei);
      console.log('✅ Transfer transaction sent:', tx.hash);

      const receipt = await tx.wait();
      console.log('✅ Stake transaction confirmed on blockchain!');
      console.log(`💎 Your ${params.amount} USDC is now in the Treasury Pool`);

      return {
        txHash: receipt.hash,
        amount: params.amount
      };
    } catch (error: any) {
      console.error('❌ Staking failed:', error);

      // Provide user-friendly error messages
      if (error.message?.includes('insufficient funds')) {
        throw new Error('Insufficient ETH for gas fees');
      } else if (error.message?.includes('user rejected')) {
        throw new Error('Transaction cancelled by user');
      } else if (error.message?.includes('Insufficient')) {
        throw error; // Already user-friendly
      } else {
        throw new Error(`Staking failed: ${error.message || 'Unknown error'}`);
      }
    }
  }

  /**
   * Get total staked amount in Treasury Pool
   * This queries the USDC/USDC.e balance of the treasury wallet on the specified network
   */
  async getTotalStaked(networkId: number): Promise<string> {
    try {
      const provider = await walletManager.getProvider(networkId);
      if (!provider) {
        return '0';
      }

      // Convert chainId to network.id for token lookup
      const networkIdForTokenLookup = chainIdToNetworkId(networkId);

      // Get USDC token for this network (USDC on Base, USDC.e on Lisk)
      const tokens = getTokensForNetwork(networkIdForTokenLookup);
      const usdcToken = tokens.find(t => t.symbol === 'USDC' || t.symbol === 'USDC.e');

      if (!usdcToken) {
        console.warn(`No USDC token found for network ${networkId}`);
        return '0';
      }

      const tokenContract = new ethers.Contract(
        usdcToken.address,
        ["function balanceOf(address owner) view returns (uint256)"],
        provider
      );

      const balance = await tokenContract.balanceOf(TREASURY_POOL_ADDRESS);
      return ethers.formatUnits(balance, usdcToken.decimals);
    } catch (error) {
      console.error('Failed to get total staked:', error);
      return '0';
    }
  }
}

export const stakingManager = new StakingManager();

