const hre = require("hardhat");

async function main() {
  console.log("🚀 Deploying BlockFinaX Smart Contracts...\n");

  // Get deployer account
  const [deployer] = await hre.ethers.getSigners();
  console.log("📝 Deploying with account:", deployer.address);

  const balance = await hre.ethers.provider.getBalance(deployer.address);
  console.log("💰 Account balance:", hre.ethers.formatEther(balance), "ETH\n");

  // USDC token address on Base Sepolia
  const USDC_ADDRESS = "0x036CbD53842c5426634e7929541eC2318f3dCF7e";

  // Deploy LiquidityPool
  console.log("📦 Deploying LiquidityPool contract...");
  const LiquidityPool = await hre.ethers.getContractFactory("LiquidityPool");
  const liquidityPool = await LiquidityPool.deploy(USDC_ADDRESS);
  await liquidityPool.waitForDeployment();
  const liquidityPoolAddress = await liquidityPool.getAddress();
  console.log("✅ LiquidityPool deployed to:", liquidityPoolAddress);

  // Deploy TradeFinanceGovernance
  console.log("\n📦 Deploying TradeFinanceGovernance contract...");
  const TradeFinanceGovernance = await hre.ethers.getContractFactory("TradeFinanceGovernance");
  const governance = await TradeFinanceGovernance.deploy(USDC_ADDRESS, liquidityPoolAddress);
  await governance.waitForDeployment();
  const governanceAddress = await governance.getAddress();
  console.log("✅ TradeFinanceGovernance deployed to:", governanceAddress);

  // Transfer LiquidityPool ownership to Governance contract
  console.log("\n🔐 Transferring LiquidityPool ownership to Governance...");
  const transferTx = await liquidityPool.transferOwnership(governanceAddress);
  await transferTx.wait();
  console.log("✅ Ownership transferred successfully");

  // Print deployment summary
  console.log("\n" + "=".repeat(60));
  console.log("📋 DEPLOYMENT SUMMARY");
  console.log("=".repeat(60));
  console.log("Network:", hre.network.name);
  console.log("USDC Token:", USDC_ADDRESS);
  console.log("LiquidityPool:", liquidityPoolAddress);
  console.log("TradeFinanceGovernance:", governanceAddress);
  console.log("Deployer:", deployer.address);
  console.log("=".repeat(60));

  // Save deployment addresses
  const fs = require("fs");
  const deploymentInfo = {
    network: hre.network.name,
    chainId: hre.network.config.chainId,
    usdcToken: USDC_ADDRESS,
    liquidityPool: liquidityPoolAddress,
    governance: governanceAddress,
    deployer: deployer.address,
    timestamp: new Date().toISOString()
  };

  fs.writeFileSync(
    `./deployments-${hre.network.name}.json`,
    JSON.stringify(deploymentInfo, null, 2)
  );
  console.log(`\n💾 Deployment info saved to deployments-${hre.network.name}.json`);

  // Verification instructions
  console.log("\n📝 To verify contracts on Basescan, run:");
  console.log(`npx hardhat verify --network ${hre.network.name} ${liquidityPoolAddress} ${USDC_ADDRESS}`);
  console.log(`npx hardhat verify --network ${hre.network.name} ${governanceAddress} ${USDC_ADDRESS} ${liquidityPoolAddress}`);
}

main()
  .then(() => process.exit(0))
  .catch((error) => {
    console.error("❌ Deployment failed:", error);
    process.exit(1);
  });

contracts/facets/LiquidityPoolFacet.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import {LibAppStorage} from "../libraries/LibAppStorage.sol";
import {LibDiamond} from "../libraries/LibDiamond.sol";

/**
 * @title LiquidityPoolFacet
 * @notice Handles LP staking, unstaking, and pool management for BlockFinaX
 */
contract LiquidityPoolFacet {
    using SafeERC20 for IERC20;

    event Staked(address indexed staker, uint256 amount, uint256 votingPower);
    event Unstaked(address indexed staker, uint256 amount);
    event RewardsDistributed(address indexed staker, uint256 amount);

    /**
     * @notice Stake USDC tokens to become LP provider
     */
    function stake(uint256 amount) external {
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();

        require(amount >= s.minimumStake, "Below minimum stake");
        IERC20 usdc = IERC20(s.usdcToken);
        require(usdc.balanceOf(msg.sender) >= amount, "Insufficient balance");

        // Transfer USDC from staker to diamond
        usdc.safeTransferFrom(msg.sender, address(this), amount);

        // Update stake record
        if (s.stakes[msg.sender].amount == 0) {
            s.stakers.push(msg.sender);
            s.totalLPs++;
        }

        s.stakes[msg.sender].amount += amount;
        s.stakes[msg.sender].timestamp = block.timestamp;
        s.stakes[msg.sender].active = true;

        // Calculate voting power
        s.totalStaked += amount;
        s.stakes[msg.sender].votingPower = (s.stakes[msg.sender].amount * 1e18) / s.totalStaked;

        // Recalculate all voting powers
        _recalculateVotingPowers();

        emit Staked(msg.sender, amount, s.stakes[msg.sender].votingPower);
    }

    /**
     * @notice Unstake USDC tokens
     */
    function unstake() external {
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();

        require(s.stakes[msg.sender].active, "No active stake");
        require(s.stakes[msg.sender].amount > 0, "Nothing to unstake");

        uint256 amount = s.stakes[msg.sender].amount;

        // Update state
        s.stakes[msg.sender].amount = 0;
        s.stakes[msg.sender].active = false;
        s.stakes[msg.sender].votingPower = 0;
        s.totalStaked -= amount;
        s.totalLPs--;

        // Recalculate voting powers
        _recalculateVotingPowers();

        // Transfer USDC back
        IERC20(s.usdcToken).safeTransfer(msg.sender, amount);

        emit Unstaked(msg.sender, amount);
    }

    /**
     * @notice Get stake information
     */
    function getStake(address staker) external view returns (
        uint256 amount,
        uint256 timestamp,
        uint256 votingPower,
        bool active
    ) {
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();
        LibAppStorage.Stake memory stake = s.stakes[staker];
        return (stake.amount, stake.timestamp, stake.votingPower, stake.active);
    }

    /**
     * @notice Get pool statistics
     */
    function getPoolStats() external view returns (
        uint256 totalStaked,
        uint256 totalLPs,
        uint256 contractBalance
    ) {
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();
        return (
            s.totalStaked,
            s.totalLPs,
            IERC20(s.usdcToken).balanceOf(address(this))
        );
    }

    /**
     * @notice Get all stakers
     */
    function getStakers() external view returns (address[] memory) {
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();
        return s.stakers;
    }

    /**
     * @notice Distribute rewards (owner only)
     */
    function distributeRewards(address staker, uint256 amount) external {
        LibDiamond.enforceIsContractOwner();
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();

        require(s.stakes[staker].active, "Staker not active");
        IERC20(s.usdcToken).safeTransfer(staker, amount);

        emit RewardsDistributed(staker, amount);
    }

    /**
     * @notice Recalculate voting powers for all stakers
     */
    function _recalculateVotingPowers() internal {
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();

        if (s.totalStaked == 0) return;

        for (uint256 i = 0; i < s.stakers.length; i++) {
            address staker = s.stakers[i];
            if (s.stakes[staker].active && s.stakes[staker].amount > 0) {
                s.stakes[staker].votingPower = (s.stakes[staker].amount * 1e18) / s.totalStaked;
            }
        }
    }
}

contracts/facets/DiamondLoupeFacet.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {LibDiamond} from "../libraries/LibDiamond.sol";
import {IDiamondLoupe} from "../interfaces/IDiamondLoupe.sol";

contract DiamondLoupeFacet is IDiamondLoupe {
    function facets() external view override returns (Facet[] memory facets_) {
        LibDiamond.DiamondStorage storage ds = LibDiamond.diamondStorage();
        uint256 numFacets = ds.facetAddresses.length;
        facets_ = new Facet[](numFacets);
        for (uint256 i; i < numFacets; i++) {
            address facetAddress_ = ds.facetAddresses[i];
            facets_[i].facetAddress = facetAddress_;
            facets_[i].functionSelectors = ds.facetFunctionSelectors[facetAddress_];
        }
    }

    function facetFunctionSelectors(address _facet) external view override returns (bytes4[] memory facetFunctionSelectors_) {
        LibDiamond.DiamondStorage storage ds = LibDiamond.diamondStorage();
        facetFunctionSelectors_ = ds.facetFunctionSelectors[_facet];
    }

    function facetAddresses() external view override returns (address[] memory facetAddresses_) {
        LibDiamond.DiamondStorage storage ds = LibDiamond.diamondStorage();
        facetAddresses_ = ds.facetAddresses;
    }

    function facetAddress(bytes4 _functionSelector) external view override returns (address facetAddress_) {
        LibDiamond.DiamondStorage storage ds = LibDiamond.diamondStorage();
        facetAddress_ = ds.selectorToFacetAndPosition[_functionSelector];
    }
}

