/**
 * Document Hash Manager
 * Integrates with DocumentFacet smart contract for on-chain document verification
 */

import { ethers } from "ethers";

// Document types matching the smart contract enum
export enum DocumentType {
  Contract = 0,
  Invoice = 1,
  ProofOfDelivery = 2,
  LegalDocument = 3,
  Specification = 4,
  ComplianceCert = 5,
  Other = 6
}

const DOCUMENT_FACET_ABI = [
  "function registerDocument(bytes32 documentHash, string metadataURI, uint8 docType) external returns (bytes32)",
  "function verifyDocument(bytes32 documentHash) external view returns (bool exists, address uploader, uint256 timestamp)",
  "function linkDocumentToEscrow(bytes32 documentHash, uint256 escrowId) external",
  "function linkDocumentToInvoice(bytes32 documentHash, uint256 invoiceId) external",
  "function markDocumentVerified(bytes32 documentHash) external",
  "function getDocument(bytes32 documentHash) external view returns (bytes32, string, address, uint256, uint8, uint256, uint256, bool)",
  "function getUserDocuments(address user) external view returns (bytes32[])",
  "function getEscrowDocuments(uint256 escrowId) external view returns (bytes32[])",
  "function getInvoiceDocuments(uint256 invoiceId) external view returns (bytes32[])",
  "function getTotalDocuments() external view returns (uint256)",
  "function batchVerifyDocuments(bytes32[] documentHashes) external view returns (bool[])"
];

export class DocumentHashManager {
  private diamondAddress: string;

  constructor(diamondAddress: string) {
    this.diamondAddress = diamondAddress;
  }

  private async getProvider(): Promise<ethers.BrowserProvider> {
    if (!(window as any).ethereum) {
      throw new Error("No ethereum provider found");
    }
    return new ethers.BrowserProvider((window as any).ethereum);
  }

  /**
   * Generate SHA-256 hash from file
   */
  async generateFileHash(file: File): Promise<string> {
    const arrayBuffer = await file.arrayBuffer();
    const hashBuffer = await crypto.subtle.digest('SHA-256', arrayBuffer);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
    return '0x' + hashHex;
  }

  /**
   * Generate SHA-256 hash from base64 data
   */
  async generateBase64Hash(base64Data: string): Promise<string> {
    // Convert base64 to binary
    const binaryString = atob(base64Data);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }

    const hashBuffer = await crypto.subtle.digest('SHA-256', bytes);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
    return '0x' + hashHex;
  }

  /**
   * Register document hash on-chain
   */
  async registerDocument(
    documentHash: string,
    metadataURI: string, // e.g., "db:12345" or "ipfs:Qm..."
    docType: DocumentType
  ): Promise<string> {
    try {
      const provider = await this.getProvider();
      const signer = await provider.getSigner();

      const contract = new ethers.Contract(
        this.diamondAddress,
        DOCUMENT_FACET_ABI,
        signer
      );

      const tx = await contract.registerDocument(documentHash, metadataURI, docType);
      const receipt = await tx.wait();

      return receipt.hash;
    } catch (error: any) {
      throw new Error(`Failed to register document: ${error.message}`);
    }
  }

  /**
   * Verify document exists on-chain
   */
  async verifyDocument(documentHash: string): Promise<{
    exists: boolean;
    uploader: string;
    timestamp: number;
  }> {
    try {
      const provider = await this.getProvider();

      const contract = new ethers.Contract(
        this.diamondAddress,
        DOCUMENT_FACET_ABI,
        provider
      );

      const [exists, uploader, timestamp] = await contract.verifyDocument(documentHash);

      return {
        exists,
        uploader,
        timestamp: Number(timestamp)
      };
    } catch (error: any) {
      throw new Error(`Failed to verify document: ${error.message}`);
    }
  }

  /**
   * Link document to escrow contract
   */
  async linkToEscrow(documentHash: string, escrowId: number): Promise<string> {
    try {
      const provider = await this.getProvider();
      const signer = await provider.getSigner();

      const contract = new ethers.Contract(
        this.diamondAddress,
        DOCUMENT_FACET_ABI,
        signer
      );

      const tx = await contract.linkDocumentToEscrow(documentHash, escrowId);
      const receipt = await tx.wait();

      return receipt.hash;
    } catch (error: any) {
      throw new Error(`Failed to link document to escrow: ${error.message}`);
    }
  }

  /**
   * Link document to invoice
   */
  async linkToInvoice(documentHash: string, invoiceId: number): Promise<string> {
    try {
      const provider = await this.getProvider();
      const signer = await provider.getSigner();

      const contract = new ethers.Contract(
        this.diamondAddress,
        DOCUMENT_FACET_ABI,
        signer
      );

      const tx = await contract.linkDocumentToInvoice(documentHash, invoiceId);
      const receipt = await tx.wait();

      return receipt.hash;
    } catch (error: any) {
      throw new Error(`Failed to link document to invoice: ${error.message}`);
    }
  }

  /**
   * Get complete document information
   */
  async getDocument(documentHash: string): Promise<{
    hash: string;
    metadataURI: string;
    uploader: string;
    timestamp: number;
    docType: DocumentType;
    linkedEscrowId: number;
    linkedInvoiceId: number;
    verified: boolean;
  }> {
    try {
      const provider = await this.getProvider();

      const contract = new ethers.Contract(
        this.diamondAddress,
        DOCUMENT_FACET_ABI,
        provider
      );

      const [hash, metadataURI, uploader, timestamp, docType, linkedEscrowId, linkedInvoiceId, verified] = 
        await contract.getDocument(documentHash);

      return {
        hash,
        metadataURI,
        uploader,
        timestamp: Number(timestamp),
        docType,
        linkedEscrowId: Number(linkedEscrowId),
        linkedInvoiceId: Number(linkedInvoiceId),
        verified
      };
    } catch (error: any) {
      throw new Error(`Failed to get document: ${error.message}`);
    }
  }

  /**
   * Get all documents for a user
   */
  async getUserDocuments(userAddress: string): Promise<string[]> {
    try {
      const provider = await this.getProvider();

      const contract = new ethers.Contract(
        this.diamondAddress,
        DOCUMENT_FACET_ABI,
        provider
      );

      const hashes = await contract.getUserDocuments(userAddress);
      return hashes;
    } catch (error: any) {
      throw new Error(`Failed to get user documents: ${error.message}`);
    }
  }

  /**
   * Get all documents linked to an escrow
   */
  async getEscrowDocuments(escrowId: number): Promise<string[]> {
    try {
      const provider = await this.getProvider();

      const contract = new ethers.Contract(
        this.diamondAddress,
        DOCUMENT_FACET_ABI,
        provider
      );

      const hashes = await contract.getEscrowDocuments(escrowId);
      return hashes;
    } catch (error: any) {
      throw new Error(`Failed to get escrow documents: ${error.message}`);
    }
  }

  /**
   * Batch verify multiple documents
   */
  async batchVerifyDocuments(documentHashes: string[]): Promise<boolean[]> {
    try {
      const provider = await this.getProvider();

      const contract = new ethers.Contract(
        this.diamondAddress,
        DOCUMENT_FACET_ABI,
        provider
      );

      const results = await contract.batchVerifyDocuments(documentHashes);
      return results;
    } catch (error: any) {
      throw new Error(`Failed to batch verify documents: ${error.message}`);
    }
  }

  /**
   * Helper: Register document from uploaded file
   */
  async registerFileDocument(
    file: File,
    documentId: number, // Database ID
    docType: DocumentType
  ): Promise<{
    hash: string;
    txHash: string;
  }> {
    // Generate hash from file
    const hash = await this.generateFileHash(file);

    // Create metadata URI referencing database
    const metadataURI = `db:${documentId}`;

    // Register on-chain
    const txHash = await this.registerDocument(hash, metadataURI, docType);

    return { hash, txHash };
  }

  /**
   * Helper: Verify document from file
   */
  async verifyFileDocument(file: File): Promise<{
    exists: boolean;
    uploader?: string;
    timestamp?: number;
  }> {
    const hash = await this.generateFileHash(file);
    return await this.verifyDocument(hash);
  }
}

