// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import {LibAppStorage} from "../libraries/LibAppStorage.sol";
import {LibDiamond} from "../libraries/LibDiamond.sol";

/**
 * @title PoolGuaranteeFacet
 * @notice Handles Pool Guarantee system with goods as collateral for BlockFinaX
 */
contract PoolGuaranteeFacet {
    using SafeERC20 for IERC20;

    event IssuanceFeePaid(string indexed requestId, address indexed buyer, uint256 amount);
    event GoodsDetailsAdded(string indexed requestId, string goodsType, uint256 totalValue);
    event DeliveryProofSubmitted(string indexed requestId, address indexed seller, string billOfLadingHash);
    event DeliveryProofVerified(string indexed requestId, address indexed verifier);
    event ClaimSubmitted(string indexed requestId, address indexed seller, uint256 claimAmount);
    event ClaimApproved(string indexed requestId, uint256 approvedAmount);
    event ClaimPaid(string indexed requestId, address indexed seller, uint256 paidAmount);
    event BuyerPaid(string indexed requestId, address indexed buyer, uint256 amount);
    event GuaranteeCompleted(string indexed requestId);

    /**
     * @notice Create Pool Guarantee request with goods as collateral
     */
    function createPoolGuarantee(
        string memory requestId,
        address seller,
        uint256 requestedAmount,
        string memory tradeDescription,
        uint256 issuanceFeeAmount,
        uint256 cashCollateral,
        uint256 paymentDueDays,
        // Goods details
        string memory goodsType,
        uint256 goodsQuantity,
        string memory goodsUnit,
        uint256 goodsTotalValue
    ) external payable {
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();

        require(bytes(requestId).length > 0, "Invalid request ID");
        require(seller != address(0), "Invalid seller");
        require(requestedAmount > 0, "Invalid amount");
        require(s.requests[requestId].createdAt == 0, "Request exists");
        require(goodsTotalValue >= (requestedAmount * 110) / 100, "Goods under-collateralized");

        // Calculate payment due date
        uint256 paymentDueDate = block.timestamp + (paymentDueDays * 1 days);

        // Create request
        s.requests[requestId] = LibAppStorage.TradeFinanceRequest({
            requestId: requestId,
            buyer: msg.sender,
            seller: seller,
            requestedAmount: requestedAmount,
            tradeDescription: tradeDescription,
            votesFor: 0,
            votesAgainst: 0,
            createdAt: block.timestamp,
            status: LibAppStorage.RequestStatus.Pending,
            fundsReleased: false,
            issuanceFee: issuanceFeeAmount,
            issuanceFeePaid: false,
            cashCollateral: cashCollateral,
            paymentDueDate: paymentDueDate
        });

        // Add goods details
        s.goodsDetails[requestId] = LibAppStorage.GoodsDetails({
            goodsType: goodsType,
            quantity: goodsQuantity,
            unit: goodsUnit,
            totalValue: goodsTotalValue,
            marketPrice: 0,
            inspected: false,
            insured: false,
            billOfLadingHash: "",
            billOfLadingNumber: ""
        });

        s.requestIds.push(requestId);
        s.totalRequests++;

        emit GoodsDetailsAdded(requestId, goodsType, goodsTotalValue);
    }

    /**
     * @notice Pay issuance fee for Pool Guarantee
     */
    function payIssuanceFee(string memory requestId) external {
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();
        LibAppStorage.TradeFinanceRequest storage request = s.requests[requestId];

        require(request.createdAt > 0, "Request not found");
        require(msg.sender == request.buyer, "Not buyer");
        require(!request.issuanceFeePaid, "Fee already paid");
        require(request.issuanceFee > 0, "No fee required");

        // Transfer issuance fee to contract
        IERC20(s.usdcToken).safeTransferFrom(msg.sender, address(this), request.issuanceFee);

        request.issuanceFeePaid = true;
        s.totalIssuanceFeesCollected += request.issuanceFee;

        emit IssuanceFeePaid(requestId, msg.sender, request.issuanceFee);
    }

    /**
     * @notice Update goods inspection status
     */
    function updateGoodsInspection(
        string memory requestId,
        uint256 marketPrice,
        bool inspected,
        bool insured
    ) external {
        LibDiamond.enforceIsContractOwner(); // Only admin/inspector
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();

        require(s.requests[requestId].createdAt > 0, "Request not found");

        LibAppStorage.GoodsDetails storage goods = s.goodsDetails[requestId];
        goods.marketPrice = marketPrice;
        goods.inspected = inspected;
        goods.insured = insured;
    }

    /**
     * @notice Issue guarantee after approval (release pool funds)
     */
    function issueGuarantee(string memory requestId) external {
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();
        LibAppStorage.TradeFinanceRequest storage request = s.requests[requestId];

        require(request.status == LibAppStorage.RequestStatus.Approved, "Not approved");
        require(request.issuanceFeePaid, "Fee not paid");
        require(!request.fundsReleased, "Already issued");
        require(s.goodsDetails[requestId].inspected, "Goods not inspected");
        require(s.goodsDetails[requestId].insured, "Goods not insured");

        uint256 balance = IERC20(s.usdcToken).balanceOf(address(this));
        require(balance >= request.requestedAmount, "Insufficient pool liquidity");

        request.fundsReleased = true;
        request.status = LibAppStorage.RequestStatus.Funded;
        s.totalGuaranteesIssued++;

        // Note: Funds stay in contract until buyer pays or claim is approved
    }

    /**
     * @notice Submit delivery proof (seller provides BoL and shipping docs)
     */
    function submitDeliveryProof(
        string memory requestId,
        string memory billOfLadingHash,
        string memory billOfLadingNumber,
        string memory trackingNumber,
        string memory logisticsProvider,
        string memory inspectionReportHash
    ) external {
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();
        LibAppStorage.TradeFinanceRequest storage request = s.requests[requestId];

        require(request.createdAt > 0, "Request not found");
        require(msg.sender == request.seller, "Not seller");
        require(request.status == LibAppStorage.RequestStatus.Funded, "Not funded");

        // Store delivery proof
        s.deliveryProofs[requestId] = LibAppStorage.DeliveryProof({
            billOfLadingHash: billOfLadingHash,
            trackingNumber: trackingNumber,
            logisticsProvider: logisticsProvider,
            deliveryDate: block.timestamp,
            inspectionReportHash: inspectionReportHash,
            verified: false,
            verifiedBy: address(0),
            verifiedAt: 0
        });

        // Update goods BoL details
        s.goodsDetails[requestId].billOfLadingHash = billOfLadingHash;
        s.goodsDetails[requestId].billOfLadingNumber = billOfLadingNumber;

        emit DeliveryProofSubmitted(requestId, msg.sender, billOfLadingHash);
    }

    /**
     * @notice Verify delivery proof (buyer or admin confirms delivery)
     */
    function verifyDeliveryProof(string memory requestId) external {
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();
        LibAppStorage.TradeFinanceRequest storage request = s.requests[requestId];
        LibAppStorage.DeliveryProof storage proof = s.deliveryProofs[requestId];

        require(request.createdAt > 0, "Request not found");
        require(msg.sender == request.buyer || msg.sender == LibDiamond.contractOwner(), "Not authorized");
        require(bytes(proof.billOfLadingHash).length > 0, "No proof submitted");
        require(!proof.verified, "Already verified");

        proof.verified = true;
        proof.verifiedBy = msg.sender;
        proof.verifiedAt = block.timestamp;

        emit DeliveryProofVerified(requestId, msg.sender);
    }

    /**
     * @notice Buyer pays seller directly (happy path - guarantee not executed)
     */
    function buyerPayment(string memory requestId) external {
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();
        LibAppStorage.TradeFinanceRequest storage request = s.requests[requestId];

        require(request.createdAt > 0, "Request not found");
        require(msg.sender == request.buyer, "Not buyer");
        require(request.status == LibAppStorage.RequestStatus.Funded, "Not active");
        require(s.deliveryProofs[requestId].verified, "Delivery not verified");

        // Transfer payment to seller
        IERC20(s.usdcToken).safeTransferFrom(msg.sender, request.seller, request.requestedAmount);

        request.status = LibAppStorage.RequestStatus.Completed;

        // Distribute issuance fee to stakers (80%) and treasury (20%)
        _distributeFees(request.issuanceFee);

        emit BuyerPaid(requestId, msg.sender, request.requestedAmount);
        emit GuaranteeCompleted(requestId);
    }

    /**
     * @notice Seller submits claim (buyer defaulted)
     */
    function submitClaim(
        string memory requestId,
        uint256 claimAmount,
        string memory claimReason
    ) external {
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();
        LibAppStorage.TradeFinanceRequest storage request = s.requests[requestId];

        require(request.createdAt > 0, "Request not found");
        require(msg.sender == request.seller, "Not seller");
        require(request.status == LibAppStorage.RequestStatus.Funded, "Not active");
        require(block.timestamp > request.paymentDueDate, "Payment not overdue");
        require(s.deliveryProofs[requestId].verified, "Delivery not verified");
        require(claimAmount <= request.requestedAmount, "Claim exceeds guarantee");

        s.claims[requestId] = LibAppStorage.GuaranteeClaim({
            requestId: requestId,
            seller: msg.sender,
            claimAmount: claimAmount,
            claimReason: claimReason,
            claimedAt: block.timestamp,
            status: LibAppStorage.ClaimStatus.Pending,
            paidAmount: 0,
            paidAt: 0
        });

        request.status = LibAppStorage.RequestStatus.Defaulted;
        s.totalDefaultsClaimed++;

        emit ClaimSubmitted(requestId, msg.sender, claimAmount);
    }

    /**
     * @notice Approve claim (governance or admin)
     */
    function approveClaim(string memory requestId, uint256 approvedAmount) external {
        LibDiamond.enforceIsContractOwner(); // Only admin/governance
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();
        LibAppStorage.GuaranteeClaim storage claim = s.claims[requestId];

        require(claim.claimedAt > 0, "Claim not found");
        require(claim.status == LibAppStorage.ClaimStatus.Pending, "Not pending");
        require(approvedAmount <= claim.claimAmount, "Exceeds claim");

        claim.status = LibAppStorage.ClaimStatus.Approved;

        emit ClaimApproved(requestId, approvedAmount);
    }

    /**
     * @notice Execute approved claim (pay seller from pool)
     */
    function executeClaim(string memory requestId) external {
        LibDiamond.enforceIsContractOwner(); // Only admin
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();
        LibAppStorage.GuaranteeClaim storage claim = s.claims[requestId];
        LibAppStorage.TradeFinanceRequest storage request = s.requests[requestId];

        require(claim.status == LibAppStorage.ClaimStatus.Approved, "Not approved");
        require(claim.paidAmount == 0, "Already paid");

        uint256 balance = IERC20(s.usdcToken).balanceOf(address(this));
        require(balance >= claim.claimAmount, "Insufficient balance");

        // Pay seller from pool
        IERC20(s.usdcToken).safeTransfer(claim.seller, claim.claimAmount);

        claim.paidAmount = claim.claimAmount;
        claim.paidAt = block.timestamp;
        claim.status = LibAppStorage.ClaimStatus.Paid;
        request.status = LibAppStorage.RequestStatus.Claimed;

        emit ClaimPaid(requestId, claim.seller, claim.claimAmount);
    }

    /**
     * @notice Get goods details for a guarantee
     */
    function getGoodsDetails(string memory requestId) external view returns (
        string memory goodsType,
        uint256 quantity,
        string memory unit,
        uint256 totalValue,
        bool inspected,
        bool insured,
        string memory billOfLadingHash
    ) {
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();
        LibAppStorage.GoodsDetails memory goods = s.goodsDetails[requestId];
        return (
            goods.goodsType,
            goods.quantity,
            goods.unit,
            goods.totalValue,
            goods.inspected,
            goods.insured,
            goods.billOfLadingHash
        );
    }

    /**
     * @notice Get delivery proof for a guarantee
     */
    function getDeliveryProof(string memory requestId) external view returns (
        string memory billOfLadingHash,
        string memory trackingNumber,
        string memory logisticsProvider,
        bool verified,
        address verifiedBy,
        uint256 verifiedAt
    ) {
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();
        LibAppStorage.DeliveryProof memory proof = s.deliveryProofs[requestId];
        return (
            proof.billOfLadingHash,
            proof.trackingNumber,
            proof.logisticsProvider,
            proof.verified,
            proof.verifiedBy,
            proof.verifiedAt
        );
    }

    /**
     * @notice Get claim details for a guarantee
     */
    function getClaim(string memory requestId) external view returns (
        address seller,
        uint256 claimAmount,
        string memory claimReason,
        LibAppStorage.ClaimStatus status,
        uint256 paidAmount,
        uint256 paidAt
    ) {
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();
        LibAppStorage.GuaranteeClaim memory claim = s.claims[requestId];
        return (
            claim.seller,
            claim.claimAmount,
            claim.claimReason,
            claim.status,
            claim.paidAmount,
            claim.paidAt
        );
    }

    /**
     * @notice Get Pool Guarantee statistics
     */
    function getPoolGuaranteeStats() external view returns (
        uint256 totalFeesCollected,
        uint256 totalGuarantees,
        uint256 totalDefaults
    ) {
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();
        return (
            s.totalIssuanceFeesCollected,
            s.totalGuaranteesIssued,
            s.totalDefaultsClaimed
        );
    }

    /**
     * @notice Internal: Distribute issuance fees to stakers and treasury
     */
    function _distributeFees(uint256 feeAmount) internal {
        LibAppStorage.AppStorage storage s = LibAppStorage.appStorage();

        // 80% to stakers, 20% to treasury (owner)
        uint256 stakersShare = (feeAmount * 80) / 100;
        uint256 treasuryShare = feeAmount - stakersShare;

        // Simple distribution: send to owner for now (can be improved to distribute proportionally)
        if (treasuryShare > 0) {
            IERC20(s.usdcToken).safeTransfer(LibDiamond.contractOwner(), treasuryShare);
        }

        // TODO: Implement proportional distribution to stakers based on voting power
        // For MVP: fees stay in contract for stakers to claim later
    }
}

