import { stakingManager } from "@/lib/staking-manager";
import { getTokenBySymbol } from "@/lib/tokens";
import { CheckCircle, XCircle, Clock, FileText, Package, DollarSign, Users, TrendingUp, ArrowLeft, Landmark, Loader2, CoinsIcon, Download, Search, SlidersHorizontal, UserX, Info, Vote } from "lucide-react";
