// Custom countdown hook
function useCountdown(endDate: Date | null) {
  const [timeRemaining, setTimeRemaining] = useState(() => {
    if (!endDate) return 0;
    return Math.max(0, endDate.getTime() - Date.now());
  });

  useEffect(() => {
    if (!endDate) return;

    const interval = setInterval(() => {
      const remaining = Math.max(0, endDate.getTime() - Date.now());
      setTimeRemaining(remaining);
    }, 1000); // Update every second

    return () => clearInterval(interval);
  }, [endDate]);

  const hours = Math.floor(timeRemaining / (1000 * 60 * 60));
  const minutes = Math.floor((timeRemaining % (1000 * 60 * 60)) / (1000 * 60));
  const seconds = Math.floor((timeRemaining % (1000 * 60)) / 1000);

  return { hours, minutes, seconds, timeRemaining };
}

// Countdown display component
function CountdownDisplay({ votingEndsAt }: { votingEndsAt: string }) {
  const endDate = new Date(votingEndsAt);
  const { hours, minutes, seconds, timeRemaining } = useCountdown(endDate);
  const votingEnded = timeRemaining === 0;

  if (votingEnded) {
    return <span>Ended</span>;
  }

  return <span>⏱️ {hours}h {minutes}m {seconds}s</span>;
}

// Claim Card component with countdown timer
function ClaimCardWithCountdown({ claim, onReview }: { claim: any; onReview: (claim: any) => void }) {
  const votingEndsAt = claim.votingEndsAt ? new Date(claim.votingEndsAt) : null;
  const { hours, minutes, seconds, timeRemaining } = useCountdown(votingEndsAt);
  const votingEnded = timeRemaining === 0;

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  return (
    <div 
      className="border rounded-lg p-4 space-y-3 bg-white dark:bg-gray-900"
      data-testid={`claim-card-${claim.id}`}
    >
      <div className="flex justify-between items-start">
        <div className="space-y-1 flex-1">
          <p className="font-medium">Claim #{claim.id} - {claim.requestId}</p>
          <p className="text-sm text-muted-foreground">Claimant: {claim.claimantAddress.slice(0, 10)}...{claim.claimantAddress.slice(-8)}</p>
          <div className="grid grid-cols-2 gap-x-4 text-sm">
            <p className="text-muted-foreground">
              Claim Amount: <span className="font-medium text-red-600">{parseFloat(claim.claimAmount).toFixed(2)} USDC</span>
            </p>
            <p className="text-muted-foreground">
              Reason: <span className="font-medium text-foreground capitalize">{claim.claimReason.replace(/_/g, ' ')}</span>
            </p>
          </div>
          {claim.supportingDocuments && (
            <p className="text-xs text-muted-foreground">
              Has supporting documents
            </p>
          )}

          {/* Voting Period Info with Countdown */}
          <div className="mt-3 p-3 bg-blue-50 dark:bg-blue-950/30 rounded-md border border-blue-200 dark:border-blue-800">
            <div className="flex items-center gap-2 mb-2">
              <Clock className="h-4 w-4 text-blue-600" />
              <span className="text-sm font-medium text-blue-900 dark:text-blue-300">
                {votingEnded ? 'Voting Period Ended' : '72-Hour Voting Period'}
              </span>
            </div>
            <div className="space-y-1 text-xs text-blue-800 dark:text-blue-300">
              {votingEndsAt && (
                <>
                  <p>Ends: {formatDate(votingEndsAt.toISOString())}</p>
                  {!votingEnded && (
                    <p className="font-medium text-blue-600 dark:text-blue-400 text-base">
                      ⏱️ {hours}h {minutes}m {seconds}s remaining
                    </p>
                  )}
                </>
              )}
              <div className="flex gap-4 mt-2 pt-2 border-t border-blue-200 dark:border-blue-800">
                <span className="text-green-600 dark:text-green-400 font-medium">
                  ✓ Approve: {claim.votesFor || 0}
                </span>
                <span className="text-red-600 dark:text-red-400 font-medium">
                  ✗ Reject: {claim.votesAgainst || 0}
                </span>
              </div>
            </div>
          </div>
        </div>
        <Button 
          onClick={() => onReview(claim)}
          size="sm"
          variant="default"
          data-testid={`button-review-claim-${claim.id}`}
        >
          <FileText className="h-4 w-4 mr-1" />
          Review & Vote
        </Button>
      </div>
    </div>
  );
}

// Delegation Management Section Component
function DelegationManagementSection({ walletAddress }: { walletAddress: string | null }) {
  const { toast } = useToast();

  // Fetch user's active delegations
  const { data: delegations, isLoading } = useQuery<Array<{
    delegatorAddress: string;
    delegateAddress: string;
    votingPower: number;
    delegatedAt: string;
  }>>({
    queryKey: ["/api/delegations/delegator", walletAddress],
    enabled: !!walletAddress,
  });

  // Fetch all specialists to get delegate information
  const { data: specialists } = useQuery<Array<{
    id: number;
    walletAddress: string;
    roleType: string;
    displayName: string;
    bio: string | null;
    specializations: string[] | null;
    isVerified: boolean;
    totalApplicationsReviewed: number;
    totalClaimsInvestigated: number;
  }>>({
    queryKey: ["/api/specialists/roles"],
  });

  // Revoke delegation mutation
  const revokeDelegationMutation = useMutation({
    mutationFn: async (delegateAddress: string) => {
      if (!walletAddress) throw new Error("Wallet address required");
      return await apiRequest("DELETE", "/api/delegations", {
        delegatorAddress: walletAddress,
        delegateAddress,
      });
    },
    onSuccess: () => {
      toast({
        title: "Delegation Revoked",
        description: "You have successfully revoked your vote delegation.",
      });
      queryClient.invalidateQueries({ queryKey: ["/api/delegations/delegator", walletAddress] });
      queryClient.invalidateQueries({ queryKey: ["/api/specialists/roles"] });
      queryClient.invalidateQueries({ queryKey: ["/api/trade-finance/staker-info", walletAddress] });
    },
    onError: (error: any) => {
      toast({
        title: "Revoke Failed",
        description: error.message || "Failed to revoke delegation. Please try again.",
        variant: "destructive",
      });
    },
  });

  // If no delegations, don't show the section
  if (!delegations || delegations.length === 0) {
    return null;
  }

  return (
    <Card className="mb-8">
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Vote className="w-5 h-5" />
          Vote Delegations
        </CardTitle>
        <CardDescription>
          Manage your delegated voting power to trusted specialists
        </CardDescription>
      </CardHeader>
      <CardContent>
        <div className="space-y-3">
          {delegations.map((delegation) => {
            const specialist = specialists?.find(
              s => s.walletAddress.toLowerCase() === delegation.delegateAddress.toLowerCase()
            );

            return (
              <div
                key={delegation.delegateAddress}
                className="flex items-center justify-between p-4 bg-muted/30 rounded-lg border"
                data-testid={`delegation-${delegation.delegateAddress}`}
              >
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <span className="font-semibold">
                      {specialist?.displayName || "Unknown Specialist"}
                    </span>
                    {specialist?.isVerified && (
                      <Badge variant="default" className="gap-1 text-xs">
                        <CheckCircle className="w-3 h-3" />
                        Verified
                      </Badge>
                    )}
                    {specialist?.roleType && (
                      <Badge variant="outline" className="text-xs">
                        {specialist.roleType === "trade_finance_specialist" 
                          ? "Trade Finance" 
                          : "Fraud Investigation"}
                      </Badge>
                    )}
                  </div>
                  <div className="text-sm text-muted-foreground">
                    {delegation.delegateAddress.slice(0, 10)}...{delegation.delegateAddress.slice(-8)}
                  </div>
                  <div className="flex items-center gap-4 mt-2 text-sm">
                    <div className="flex items-center gap-1">
                      <Vote className="w-4 h-4 text-blue-600" />
                      <span className="font-medium text-blue-600">
                        {delegation.votingPower.toFixed(2)} votes delegated
                      </span>
                    </div>
                    <div className="text-muted-foreground">
                      Since {new Date(delegation.delegatedAt).toLocaleDateString()}
                    </div>
                  </div>
                  {specialist?.specializations && specialist.specializations.length > 0 && (
                    <div className="flex flex-wrap gap-1 mt-2">
                      {specialist.specializations.slice(0, 3).map((spec, idx) => (
                        <Badge key={idx} variant="secondary" className="text-xs">
                          {spec}
                        </Badge>
                      ))}
                    </div>
                  )}
                </div>
                <div className="ml-4">
                  <Button
                    variant="destructive"
                    size="sm"
                    onClick={() => revokeDelegationMutation.mutate(delegation.delegateAddress)}
                    disabled={revokeDelegationMutation.isPending}
                    data-testid={`button-revoke-${delegation.delegateAddress}`}
                  >
                    {revokeDelegationMutation.isPending ? (
                      <>
                        <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                        Revoking...
                      </>
                    ) : (
                      <>
                        <UserX className="w-4 h-4 mr-2" />
                        Revoke
                      </>
                    )}
                  </Button>
                </div>
              </div>
            );
          })}

          <div className="bg-blue-50 dark:bg-blue-900/20 p-3 rounded-lg border border-blue-200 dark:border-blue-800 flex gap-2 mt-4">
            <Info className="w-4 h-4 text-blue-600 dark:text-blue-400 flex-shrink-0 mt-0.5" />
            <div className="text-xs text-blue-800 dark:text-blue-300">
              <strong>Note:</strong> You retain your staked USDC and continue earning 60% fee distributions. 
              Your delegate votes on Pool Guarantee applications using your voting power. You can revoke delegation anytime.
            </div>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

export default function TreasuryPortal() {
  const { wallet, settings } = useWallet();
  const { toast } = useToast();

  // Get the selected network (default to Base Sepolia)
  const selectedNetworkId = settings?.selectedNetworkId || 1;
  const selectedNetwork = getNetworkById(selectedNetworkId);
  const chainId = selectedNetwork?.chainId || 84532;
  const [, setLocation] = useLocation();
  const [selectedTab, setSelectedTab] = useState("pending");

  // Search and filter state
  const [searchQuery, setSearchQuery] = useState("");
  const [sortBy, setSortBy] = useState("newest");

  // Staking state
  const [stakingDialogOpen, setStakingDialogOpen] = useState(false);
  const [unstakingDialogOpen, setUnstakingDialogOpen] = useState(false);
  const [stakeAmount, setStakeAmount] = useState("");
  const [unstakeAmount, setUnstakeAmount] = useState("");
  const [isStaking, setIsStaking] = useState(false);
  const [isUnstaking, setIsUnstaking] = useState(false);
  const [selectedGuaranteeForCert, setSelectedGuaranteeForCert] = useState<string | null>(null);
  const [certificates, setCertificates] = useState<any[]>([]);
  const [selectedGuaranteeForDocs, setSelectedGuaranteeForDocs] = useState<string | null>(null);
  const [documents, setDocuments] = useState<any[]>([]);

  // Claim review state
  const [isClaimReviewDialogOpen, setIsClaimReviewDialogOpen] = useState(false);
  const [selectedClaim, setSelectedClaim] = useState<any>(null);
  const [reviewNotes, setReviewNotes] = useState("");
  const [approvedAmount, setApprovedAmount] = useState("");

  // Fetch staker information
  const { data: stakerInfo } = useQuery<StakerInfo>({
    queryKey: ['/api/trade-finance/staker-info', wallet?.address],
    queryFn: async () => {
      if (!wallet?.address) throw new Error('No wallet address');
      const res = await fetch(`/api/trade-finance/staker-info?walletAddress=${wallet.address}`, { 
        credentials: "include" 
      });
      if (!res.ok) throw new Error('Failed to fetch staker info');
      return await res.json();
    },
    enabled: !!wallet?.address,
  });

  // Fetch user's stakes
  const { data: userStakes = [] } = useQuery({
    queryKey: ["/api/trade-finance/stakes", wallet?.address],
    queryFn: async () => {
      if (!wallet?.address) return [];
      const res = await fetch(`/api/trade-finance/stakes?stakerAddress=${wallet.address}&status=active`, { credentials: "include" });
      if (!res.ok) return [];
      return await res.json();
    },
    enabled: !!wallet?.address
  });

  // Fetch all pool guarantees
  const { data: guarantees = [], isLoading } = useQuery<PoolGuarantee[]>({
    queryKey: ['/api/pool-guarantees'],
    enabled: !!wallet?.address,
  });

  // Fetch earnings data
  const { data: earnings } = useQuery({
    queryKey: ['/api/treasury/earnings', wallet?.address],
    queryFn: async () => {
      if (!wallet?.address) return null;
      const res = await fetch(`/api/treasury/earnings/${wallet.address}`, { credentials: "include" });
      if (!res.ok) return null;
      return await res.json();
    },
    enabled: !!wallet?.address
  });

  // Fetch all pending claims (treasury reviews all claims)
  const { data: allClaims = [] } = useQuery({
    queryKey: ["/api/pool-guarantee/claims"],
    queryFn: async () => {
      const res = await fetch(`/api/pool-guarantee/claims`, {
        credentials: "include",
      });
      if (!res.ok) {
        if (res.status === 404) return [];
        throw new Error(`${res.status}: ${await res.text() || res.statusText}`);
      }
      return await res.json();
    },
    enabled: !!wallet?.address
  });

  // Claim earnings mutation
  const claimEarningsMutation = useMutation({
    mutationFn: async () => {
      if (!wallet?.address || !earnings?.earnings) {
        throw new Error('Wallet or earnings data not available');
      }

      const pendingEarnings = earnings.earnings.filter((e: any) => e.claimStatus === 'pending');
      if (pendingEarnings.length === 0) {
        throw new Error('No pending earnings to claim');
      }

      const distributionIds = pendingEarnings.map((e: any) => e.id);

      const res = await fetch(`/api/treasury/earnings/claim`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({
          walletAddress: wallet.address,
          distributionIds
        })
      });

      if (!res.ok) {
        const error = await res.json();
        throw new Error(error.message || 'Failed to claim earnings');
      }

      return await res.json();
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ['/api/treasury/earnings', wallet?.address] });
      queryClient.invalidateQueries({ queryKey: ['/api/wallet-balance'] });

      const txHash = data.transactionHash;
      const explorerUrl = `https://sepolia.basescan.org/tx/${txHash}`;

      toast({
        title: "✅ Earnings Claimed & Transferred!",
        description: (
          <div className="space-y-2">
            <p>USDC sent from treasury to your wallet</p>
            <p className="text-sm">Amount: {data.totalClaimed} USDC</p>
            <a 
              href={explorerUrl} 
              target="_blank" 
              rel="noopener noreferrer"
              className="text-sm text-blue-500 hover:underline block"
            >
              View on BaseScan →
            </a>
          </div>
        ),
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Error",
        description: error.message || "Failed to claim earnings",
        variant: "destructive",
      });
    }
  });

  // Vote mutation
  const voteMutation = useMutation({
    mutationFn: async ({ guaranteeId, voteFor }: { guaranteeId: string; voteFor: boolean }) => {
      const response = await fetch(`/api/pool-guarantees/${guaranteeId}/vote`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          walletAddress: wallet?.address,
          voteFor,
        }),
      });
      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.message || 'Failed to vote');
      }
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/pool-guarantees'] });
      toast({
        title: "Vote Recorded",
        description: "Your vote has been recorded successfully.",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Vote Failed",
        description: error.message || "Failed to record your vote.",
        variant: "destructive",
      });
    },
  });

  const handleVote = (guaranteeId: string, voteFor: boolean) => {
    voteMutation.mutate({ guaranteeId, voteFor });
  };

  // Create draft mutation (manual trigger)
  const createDraftMutation = useMutation({
    mutationFn: async (guaranteeId: string) => {
      return await apiRequest("POST", `/api/pool-guarantees/${guaranteeId}/create-draft`, {
        walletAddress: wallet?.address
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/pool-guarantee/applications'] });
      queryClient.invalidateQueries({ queryKey: ['/api/pool-guarantees'] });
      toast({
        title: "Draft Created",
        description: "Draft certificate has been created and sent to seller for approval.",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Draft Creation Failed",
        description: error.message || "Failed to create draft certificate.",
        variant: "destructive",
      });
    },
  });

  const handleCreateDraft = (guaranteeId: string) => {
    createDraftMutation.mutate(guaranteeId);
  };

  // Helper to check if application is ready for manual draft creation
  const canCreateDraft = (guarantee: any) => {
    // Use rawStatus (database status) instead of status (UI status)
    if (guarantee.rawStatus !== 'pending_draft') return false;

    const totalVotes = (guarantee.votesFor || 0) + (guarantee.votesAgainst || 0);
    if (totalVotes < 60) return false;

    const approvalPercentage = (guarantee.votesFor / totalVotes) * 100;
    return approvalPercentage >= 60;
  };

  // Issue final certificate mutation
  const issueFinalCertMutation = useMutation({
    mutationFn: async (requestId: string) => {
      return await apiRequest("POST", `/api/pool-guarantee/applications/${requestId}/finalize`, {
        treasuryAddress: wallet?.address
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/pool-guarantee/applications'] });
      queryClient.invalidateQueries({ queryKey: ['/api/pool-guarantees'] });
      queryClient.invalidateQueries({ queryKey: ['/api/pool-guarantee/certificates'] });
      toast({
        title: "Certificate Issued",
        description: "Final guarantee certificate has been issued successfully.",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Issuance Failed",
        description: error.message || "Failed to issue final certificate.",
        variant: "destructive",
      });
    },
  });

  const handleIssueFinalCert = (requestId: string) => {
    issueFinalCertMutation.mutate(requestId);
  };

  // Vote on claim mutation
  const voteOnClaimMutation = useMutation({
    mutationFn: async ({ claimId, vote, comment }: { claimId: number, vote: 'approve' | 'reject', comment?: string }) => {
      const votingPower = stakerInfo?.votingPower || "0";
      return await apiRequest("POST", `/api/pool-guarantee/claims/${claimId}/vote`, {
        voterAddress: wallet?.address,
        vote,
        votingPower,
        comment
      });
    },
    onSuccess: (_, variables) => {
      queryClient.invalidateQueries({ queryKey: ["/api/pool-guarantee/claims"] });
      queryClient.invalidateQueries({ queryKey: ["/api/pool-guarantee/claims", variables.claimId, "votes"] });
      toast({
        title: "Vote Submitted",
        description: `You voted to ${variables.vote === 'approve' ? 'approve' : 'reject'} this claim.`,
      });
      setIsClaimReviewDialogOpen(false);
      setSelectedClaim(null);
      setReviewNotes("");
      setApprovedAmount("");
    },
    onError: (error: any) => {
      toast({
        title: "Error Submitting Vote",
        description: error.message || "Failed to submit vote",
        variant: "destructive"
      });
    }
  });

  const handleOpenClaimReview = (claim: any) => {
    setSelectedClaim(claim);
    setApprovedAmount(claim.claimAmount.toString());
    setReviewNotes("");
    setIsClaimReviewDialogOpen(true);
  };

  const handleVoteOnClaim = (vote: 'approve' | 'reject') => {
    if (!selectedClaim) {
      return;
    }

    if (!stakerInfo || stakerInfo.votingPower <= 0) {
      toast({
        title: "Cannot Vote",
        description: "You must be a staker to vote on claims",
        variant: "destructive"
      });
      return;
    }

    voteOnClaimMutation.mutate({
      claimId: selectedClaim.id,
      vote,
      comment: reviewNotes
    });
  };

  // Filter and sort guarantees
  const filterAndSortGuarantees = (gList: PoolGuarantee[]) => {
    let filtered = [...gList];

    // Apply search filter
    if (searchQuery.trim()) {
      const query = searchQuery.toLowerCase();
      filtered = filtered.filter(g => 
        g.guaranteeId.toLowerCase().includes(query) ||
        g.buyerAddress.toLowerCase().includes(query) ||
        g.sellerAddress.toLowerCase().includes(query) ||
        g.goodsDescription.toLowerCase().includes(query)
      );
    }

    // Apply sorting
    switch(sortBy) {
      case "newest":
        filtered.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
        break;
      case "oldest":
        filtered.sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());
        break;
      case "amount-high":
        filtered.sort((a, b) => b.totalValue - a.totalValue);
        break;
      case "amount-low":
        filtered.sort((a, b) => a.totalValue - b.totalValue);
        break;
    }

    return filtered;
  };

  const pendingGuarantees = filterAndSortGuarantees(guarantees.filter(g => g.status === 'pending'));
  const feePaidGuarantees = filterAndSortGuarantees(guarantees.filter(g => g.rawStatus === 'fee_paid'));
  const approvedGuarantees = filterAndSortGuarantees(guarantees.filter(g => g.status === 'approved' || g.status === 'funded'));
  const rejectedGuarantees = filterAndSortGuarantees(guarantees.filter(g => g.status === 'rejected'));

  // Filter claims by status
  const pendingClaims = allClaims.filter((claim: any) => claim.status === "pending" || claim.status === "under_review");
  const approvedClaims = allClaims.filter((claim: any) => claim.status === "approved");
  const rejectedClaims = allClaims.filter((claim: any) => claim.status === "rejected");

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 2,
    }).format(amount);
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });
  };

  const calculateApprovalPercentage = (votesFor: number, votesAgainst: number) => {
    const total = votesFor + votesAgainst;
    if (total === 0) return 0;
    return Math.round((votesFor / total) * 100);
  };

  // Staking handlers
  const handleStake = async () => {
    if (!wallet?.address) {
      toast({
        title: "Wallet Not Connected",
        description: "Please connect your wallet first",
        variant: "destructive"
      });
      return;
    }

    if (!stakeAmount || parseFloat(stakeAmount) <= 0) {
      toast({
        title: "Invalid Amount",
        description: "Please enter a valid amount to stake",
        variant: "destructive"
      });
      return;
    }

    setIsStaking(true);
    try {
      // Get USDC token for selected network (USDC on Base, USDC.e on Lisk)
      const tokenSymbol = selectedNetworkId === 2 ? 'USDC.e' : 'USDC';
      const usdcToken = getTokenBySymbol(selectedNetworkId, tokenSymbol);
      if (!usdcToken) {
        throw new Error(`${tokenSymbol} token not found on this network`);
      }

      const result = await stakingManager.stakeTokens({
        amount: stakeAmount,
        tokenAddress: usdcToken.address,
        tokenSymbol: tokenSymbol,
        networkId: chainId // Use the actual chainId for blockchain operations
      });

      await apiRequest('POST', '/api/trade-finance/stake', {
        stakerAddress: wallet.address,
        tokenAddress: usdcToken.address,
        tokenSymbol: tokenSymbol,
        amount: stakeAmount,
        networkId: selectedNetworkId,
        status: 'active',
        votingPower: stakeAmount,
        transactionHash: result.txHash
      });

      queryClient.invalidateQueries({ queryKey: ["/api/trade-finance/staker-info"] });
      queryClient.invalidateQueries({ queryKey: ["/api/trade-finance/stakes"] });

      toast({
        title: "Staking Successful!",
        description: `You've staked ${stakeAmount} USDC to the Treasury Pool`,
      });

      setStakingDialogOpen(false);
      setStakeAmount("");
    } catch (error: any) {
      toast({
        title: "Staking Failed",
        description: error.message || "Failed to stake tokens",
        variant: "destructive"
      });
    } finally {
      setIsStaking(false);
    }
  };

  // Certificate viewing
  const handleViewCertificate = async (guaranteeId: string) => {
    try {
      const response = await fetch(`/api/pool-guarantee/${guaranteeId}/certificates`, {
        credentials: 'include'
      });
      if (!response.ok) throw new Error('Failed to fetch certificates');
      const certs = await response.json();
      setCertificates(certs);
      setSelectedGuaranteeForCert(guaranteeId);
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to load certificates",
        variant: "destructive"
      });
    }
  };

  // Document viewing
  const handleViewDocuments = async (guaranteeId: string) => {
    try {
      const response = await fetch(`/api/pool-guarantee/${guaranteeId}/documents`, {
        credentials: 'include'
      });
      if (!response.ok) throw new Error('Failed to fetch documents');
      const docs = await response.json();
      setDocuments(docs);
      setSelectedGuaranteeForDocs(guaranteeId);
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to load documents",
        variant: "destructive"
      });
    }
  };

  const handleUnstake = async () => {
    if (!wallet?.address) {
      toast({
        title: "Wallet Not Connected",
        description: "Please connect your wallet first",
        variant: "destructive"
      });
      return;
    }

    if (!unstakeAmount || parseFloat(unstakeAmount) <= 0) {
      toast({
        title: "Invalid Amount",
        description: "Please enter a valid amount to unstake",
        variant: "destructive"
      });
      return;
    }

    const totalStaked = userStakes.reduce((sum: number, stake: any) => sum + parseFloat(stake.amount), 0);

    if (parseFloat(unstakeAmount) > totalStaked) {
      toast({
        title: "Insufficient Stake",
        description: `You can only unstake up to ${totalStaked.toFixed(2)} USDC`,
        variant: "destructive"
      });
      return;
    }

    setIsUnstaking(true);
    try {
      const totalStakedAmount = userStakes.reduce((sum: number, stake: any) => sum + parseFloat(stake.amount), 0);

      if (parseFloat(unstakeAmount) !== totalStakedAmount) {
        toast({
          title: "Partial Unstaking Not Supported",
          description: `Please unstake the full amount: ${totalStakedAmount.toFixed(2)} USDC`,
          variant: "destructive"
        });
        setIsUnstaking(false);
        return;
      }

      for (const stake of userStakes) {
        await apiRequest('POST', `/api/trade-finance/unstake/${stake.id}`, {
          walletAddress: wallet.address
        });
      }

      queryClient.invalidateQueries({ queryKey: ["/api/trade-finance/staker-info"] });
      queryClient.invalidateQueries({ queryKey: ["/api/trade-finance/stakes"] });

      toast({
        title: "Unstaking Successful!",
        description: `${unstakeAmount} USDC has been returned to your wallet`,
      });

      setUnstakingDialogOpen(false);
      setUnstakeAmount("");
    } catch (error: any) {
      toast({
        title: "Unstaking Failed",
        description: error.message || "Failed to unstake tokens",
        variant: "destructive"
      });
    } finally {
      setIsUnstaking(false);
    }
  };

  if (!wallet?.address) {
    return (
      <div className="min-h-screen bg-background">
        <div className="container mx-auto p-8">
          <Button
            variant="ghost"
            onClick={() => setLocation('/wallet')}
            className="mb-6"
            data-testid="button-back-to-wallet"
          >
            <ArrowLeft className="h-4 w-4 mr-2" />
            Back to Wallet
          </Button>
          <Card>
            <CardContent className="pt-6 text-center">
              <p className="text-muted-foreground">Please unlock your wallet to access the Treasury Portal.</p>
            </CardContent>
          </Card>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      <div className="container mx-auto p-8">
        <div className="flex items-center justify-between mb-6">
          <Button
            variant="ghost"
            onClick={() => setLocation('/wallet')}
            data-testid="button-back-to-wallet"
          >
            <ArrowLeft className="h-4 w-4 mr-2" />
            Back to Wallet
          </Button>
          <Button
            variant="outline"
            onClick={() => setLocation('/treasury/specialists')}
            data-testid="button-discover-specialists"
            className="gap-2"
          >
            <Users className="h-4 w-4" />
            Discover Specialists
          </Button>
        </div>

        <div className="mb-8">
          <h1 className="text-3xl font-bold mb-2">Treasury Portal</h1>
          <p className="text-muted-foreground">
            Review and vote on Pool Guarantee applications
          </p>
        </div>

        {/* Staking Management & Voting Power */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
          {/* Staking Card */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <CoinsIcon className="w-5 h-5" />
                Treasury Staking
              </CardTitle>
              <CardDescription>Stake USDC to earn fees and voting power</CardDescription>
            </CardHeader>
            <CardContent>
