                          <CardTitle className="flex items-center gap-2">
                            <Package className="w-5 h-5" />
                            {guarantee.guaranteeId}
                          </CardTitle>
                          <CardDescription>
                            Applied on {formatDate(guarantee.createdAt)}
                          </CardDescription>
                        </div>
                        <Badge variant="outline" className="bg-red-500/10 text-red-600 border-red-500/20">
                          <XCircle className="w-3 h-3 mr-1" />
                          Rejected
                        </Badge>
                      </div>
                    </CardHeader>
                    <CardContent>
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        <div>
                          <div className="text-sm font-medium text-muted-foreground mb-1">Goods</div>
                          <div className="text-sm">{guarantee.goodsDescription}</div>
                        </div>
                        <div>
                          <div className="text-sm font-medium text-muted-foreground mb-1">Guarantee Amount</div>
                          <div className="text-lg font-bold">{formatCurrency(guarantee.totalValue)}</div>
                        </div>
                        <div>
                          <div className="text-sm font-medium text-muted-foreground mb-1">Final Vote</div>
                          <div className="text-sm">
                            {calculateApprovalPercentage(guarantee.votesFor, guarantee.votesAgainst)}% Approval
                          </div>
                        </div>
                      </div>
                      <div className="grid grid-cols-2 gap-3 mt-4">
                        <Button
                          onClick={() => handleViewDocuments(guarantee.guaranteeId)}
                          variant="outline"
                          data-testid={`button-view-docs-rejected-${guarantee.guaranteeId}`}
                        >
                          <FileText className="w-4 h-4 mr-2" />
                          View Documents
                        </Button>
                        <Button
                          onClick={() => handleViewCertificate(guarantee.guaranteeId)}
                          variant="outline"
                          data-testid={`button-view-cert-rejected-${guarantee.guaranteeId}`}
                        >
                          <FileText className="w-4 h-4 mr-2" />
                          View Draft
                        </Button>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            )}
          </TabsContent>
        </Tabs>

        {/* Certificate Viewing Dialog */}
        <Dialog open={!!selectedGuaranteeForCert} onOpenChange={() => {setSelectedGuaranteeForCert(null); setCertificates([]);}}>
          <DialogContent className="max-w-4xl max-h-[80vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>Pool Guarantee Certificates - {selectedGuaranteeForCert}</DialogTitle>
              <DialogDescription>
                View draft and final certificates for this Pool Guarantee application
              </DialogDescription>
            </DialogHeader>
            {certificates.length === 0 ? (
              <div className="text-center py-8">
                <FileText className="w-12 h-12 mx-auto mb-4 text-muted-foreground" />
                <p className="text-muted-foreground">No certificates found for this guarantee</p>
              </div>
            ) : (
              <div className="space-y-4">
                {certificates.map((cert: any) => (
                  <Card key={cert.id}>
                    <CardHeader>
                      <CardTitle className="text-lg flex items-center justify-between">
                        <span>{cert.certificateType === 'draft' ? 'Draft Certificate' : 'Final Certificate'}</span>
                        <div className="flex gap-2">
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => {
                              const blob = new Blob([cert.content], { type: 'text/plain' });
                              const url = URL.createObjectURL(blob);
                              const a = document.createElement('a');
                              a.href = url;
                              a.download = `${selectedGuaranteeForCert}-${cert.certificateType}-v${cert.version}.txt`;
                              document.body.appendChild(a);
                              a.click();
                              document.body.removeChild(a);
                              URL.revokeObjectURL(url);
                            }}
                            data-testid={`button-download-cert-${cert.id}`}
                          >
                            <Download className="h-4 w-4 mr-2" />
                            Download
                          </Button>
                          <Badge variant={cert.certificateType === 'draft' ? 'outline' : 'default'}>
                            {cert.certificateType}
                          </Badge>
                        </div>
                      </CardTitle>
                      <CardDescription>
                        Created {new Date(cert.createdAt).toLocaleDateString()} - Version {cert.version}
                      </CardDescription>
                    </CardHeader>
                    <CardContent>
                      <div className="w-full">
                        <div className="whitespace-pre-wrap font-mono text-sm leading-relaxed bg-white dark:bg-gray-900 p-6 rounded-lg border-2 border-gray-200 dark:border-gray-700 overflow-x-auto">
{cert.content}
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            )}
          </DialogContent>
        </Dialog>

        {/* Documents Viewing Dialog */}
        <Dialog open={!!selectedGuaranteeForDocs} onOpenChange={() => {setSelectedGuaranteeForDocs(null); setDocuments([]);}}>
          <DialogContent className="max-w-4xl max-h-[80vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>Supporting Documents - {selectedGuaranteeForDocs}</DialogTitle>
              <DialogDescription>
                View invoices, sales contracts, and other documents for this Pool Guarantee application
              </DialogDescription>
            </DialogHeader>
            {documents.length === 0 ? (
              <div className="text-center py-8">
                <FileText className="w-12 h-12 mx-auto mb-4 text-muted-foreground" />
                <p className="text-muted-foreground">No documents found for this guarantee</p>
              </div>
            ) : (
              <div className="space-y-4">
                {documents.map((doc: any) => (
                  <Card key={doc.id}>
                    <CardHeader>
                      <CardTitle className="text-lg flex items-center justify-between">
                        <span className="flex items-center gap-2">
                          <FileText className="w-5 h-5" />
                          {doc.fileName}
                        </span>
                        <Badge variant="outline">
                          {doc.documentType.replace('_', ' ').toUpperCase()}
                        </Badge>
                      </CardTitle>
                      <CardDescription>
                        Uploaded {new Date(doc.createdAt).toLocaleDateString()} • {doc.mimeType} • {(doc.fileSize / 1024).toFixed(2)} KB
                      </CardDescription>
                    </CardHeader>
                    <CardContent>
                      {doc.storageKey ? (
                        <div className="space-y-3">
                          <div className="bg-gray-100 dark:bg-gray-800 p-4 rounded border">
                            <p className="text-sm font-medium mb-2">Document Preview:</p>
                            <embed
                              src={`data:${doc.mimeType};base64,${doc.storageKey}#toolbar=1&navpanes=1&scrollbar=1`}
                              type={doc.mimeType}
                              className="w-full h-[500px] border rounded bg-white"
                              title={doc.fileName}
                            />
                          </div>
                          <div className="flex gap-2">
                            <Button
                              variant="default"
                              className="flex-1"
                              onClick={() => {
                                const link = document.createElement('a');
                                link.href = `data:${doc.mimeType};base64,${doc.storageKey}`;
                                link.download = doc.fileName;
                                link.click();
                              }}
                              data-testid={`button-download-${doc.id}`}
                            >
                              <Download className="w-4 h-4 mr-2" />
                              Download PDF
                            </Button>
                            <Button
                              variant="outline"
                              onClick={() => {
                                const pdfWindow = window.open('');
                                if (pdfWindow) {
                                  pdfWindow.document.write(`
                                    <iframe width='100%' height='100%' src='data:${doc.mimeType};base64,${doc.storageKey}'></iframe>
                                  `);
                                }
                              }}
                            >
                              <FileText className="w-4 h-4 mr-2" />
                              Open in New Tab
                            </Button>
                          </div>
                        </div>
                      ) : (
                        <p className="text-sm text-muted-foreground">Document data not available</p>
                      )}
                    </CardContent>
                  </Card>
                ))}
              </div>
            )}
          </DialogContent>
        </Dialog>

        {/* Staking Dialog */}
        <Dialog open={stakingDialogOpen} onOpenChange={setStakingDialogOpen}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Stake USDC to Treasury Pool</DialogTitle>
              <DialogDescription>
                Stake USDC tokens to become a Treasury member and earn from 1% Pool Guarantee fees
              </DialogDescription>
            </DialogHeader>
            <div className="space-y-4 py-4">
              <div className="space-y-2">
                <Label htmlFor="stake-amount">Amount to Stake (USDC)</Label>
                <Input
                  id="stake-amount"
                  type="number"
                  placeholder="0.00"
                  value={stakeAmount}
                  onChange={(e) => setStakeAmount(e.target.value)}
                  data-testid="input-stake-amount"
                />
              </div>
              <div className="bg-muted p-4 rounded-lg space-y-2">
                <h4 className="font-semibold text-sm">Benefits of Staking:</h4>
                <ul className="text-sm text-muted-foreground space-y-1">
                  <li>• Earn 1% fee from all Pool Guarantee issuances</li>
                  <li>• Voting power proportional to your stake</li>
                  <li>• Participate in Treasury governance</li>
                  <li>• Support decentralized trade finance</li>
                </ul>
              </div>
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={() => setStakingDialogOpen(false)}>Cancel</Button>
              <Button onClick={handleStake} disabled={isStaking} data-testid="button-confirm-stake">
                {isStaking ? (
                  <>
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                    Staking...
                  </>
                ) : (
                  <>
                    <CoinsIcon className="h-4 w-4 mr-2" />
                    Stake USDC
                  </>
                )}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>

        {/* Unstaking Dialog */}
        <Dialog open={unstakingDialogOpen} onOpenChange={setUnstakingDialogOpen}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Unstake USDC from Treasury Pool</DialogTitle>
              <DialogDescription>
                Withdraw your staked USDC tokens back to your wallet
              </DialogDescription>
            </DialogHeader>
            <div className="space-y-4 py-4">
              <div className="space-y-2">
                <Label htmlFor="unstake-amount">Amount to Unstake (USDC)</Label>
                <Input
                  id="unstake-amount"
                  type="number"
                  placeholder="0.00"
                  value={unstakeAmount}
                  onChange={(e) => setUnstakeAmount(e.target.value)}
                  data-testid="input-unstake-amount"
                />
                <p className="text-sm text-muted-foreground">
                  Your Staked Balance: {userStakes.reduce((sum: number, stake: any) => sum + parseFloat(stake.amount), 0).toFixed(2)} USDC
                </p>
              </div>
              <div className="bg-muted p-4 rounded-lg space-y-2">
                <h4 className="font-semibold text-sm">Unstaking Details:</h4>
                <ul className="text-sm text-muted-foreground space-y-1">
                  <li>• Tokens will be returned to your wallet immediately</li>
                  <li>• You'll lose voting power proportional to unstaked amount</li>
                  <li>• You'll no longer earn fees on unstaked portion</li>
                  <li>• You can re-stake anytime</li>
                </ul>
              </div>
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={() => setUnstakingDialogOpen(false)}>Cancel</Button>
              <Button onClick={handleUnstake} disabled={isUnstaking} data-testid="button-confirm-unstake">
                {isUnstaking ? (
                  <>
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                    Unstaking...
                  </>
                ) : (
                  <>
                    <Download className="h-4 w-4 mr-2" />
                    Unstake USDC
                  </>
                )}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>

        {/* Claim Review Dialog */}
        <Dialog open={isClaimReviewDialogOpen} onOpenChange={setIsClaimReviewDialogOpen}>
          <DialogContent className="max-w-2xl">
            <DialogHeader>
              <DialogTitle>Review Claim #{selectedClaim?.id}</DialogTitle>
              <DialogDescription>
                Review seller's claim for buyer default and approve or reject the payment request
              </DialogDescription>
            </DialogHeader>
            {selectedClaim && (
              <div className="space-y-4 py-4">
                <div className="grid grid-cols-2 gap-4 p-4 bg-muted rounded-lg">
                  <div>
                    <p className="text-sm text-muted-foreground">Guarantee ID</p>
                    <p className="font-medium">{selectedClaim.requestId}</p>
                  </div>
                  <div>
                    <p className="text-sm text-muted-foreground">Claimant</p>
                    <p className="font-medium">{selectedClaim.claimantAddress.slice(0, 10)}...{selectedClaim.claimantAddress.slice(-8)}</p>
                  </div>
                  <div>
                    <p className="text-sm text-muted-foreground">Claim Amount</p>
                    <p className="font-medium text-red-600">{parseFloat(selectedClaim.claimAmount).toFixed(2)} USDC</p>
                  </div>
                  <div>
                    <p className="text-sm text-muted-foreground">Claim Reason</p>
                    <p className="font-medium capitalize">{selectedClaim.claimReason.replace(/_/g, ' ')}</p>
                  </div>
                </div>

                {selectedClaim.deliveryProofId && (
                  <div className="p-4 bg-muted rounded-lg">
                    <p className="text-sm text-muted-foreground mb-2">Delivery Proof</p>
                    <p className="text-sm">Delivery Proof ID: {selectedClaim.deliveryProofId}</p>
                  </div>
                )}

                {selectedClaim.supportingDocuments && (
                  <div className="p-4 bg-muted rounded-lg">
                    <p className="text-sm text-muted-foreground mb-2">Supporting Documents</p>
                    <p className="text-sm">{selectedClaim.supportingDocuments}</p>
                  </div>
                )}

                {/* Voting Period Status */}
                {selectedClaim.votingEndsAt && (
                  <div className="p-4 bg-blue-50 dark:bg-blue-950/30 rounded-lg border border-blue-200 dark:border-blue-800">
                    <div className="flex items-center gap-2 mb-3">
                      <Clock className="h-5 w-5 text-blue-600" />
                      <span className="font-semibold text-blue-900 dark:text-blue-300">Voting Period Status</span>
                    </div>
                    <div className="grid grid-cols-2 gap-4 text-sm">
                      <div>
                        <p className="text-blue-700 dark:text-blue-400 mb-1">Voting Ends</p>
                        <p className="font-medium">{formatDate(selectedClaim.votingEndsAt)}</p>
                      </div>
                      <div>
                        <p className="text-blue-700 dark:text-blue-400 mb-1">Time Remaining</p>
                        <p className="font-medium text-blue-600 dark:text-blue-400 text-base">
                          <CountdownDisplay votingEndsAt={selectedClaim.votingEndsAt} />
                        </p>
                      </div>
                    </div>
                    <div className="mt-3 pt-3 border-t border-blue-200 dark:border-blue-800">
                      <p className="text-sm text-blue-700 dark:text-blue-400 mb-2">Current Votes</p>
                      <div className="flex gap-6">
                        <div className="flex items-center gap-2">
                          <CheckCircle className="h-4 w-4 text-green-600" />
                          <span className="text-green-600 dark:text-green-400 font-medium">Approve: {selectedClaim.votesFor || 0}</span>
                        </div>
                        <div className="flex items-center gap-2">
                          <XCircle className="h-4 w-4 text-red-600" />
                          <span className="text-red-600 dark:text-red-400 font-medium">Reject: {selectedClaim.votesAgainst || 0}</span>
                        </div>
                      </div>
                    </div>
                  </div>
                )}

                <div className="space-y-2">
                  <Label htmlFor="approved-amount">Approved Amount (USDC)</Label>
                  <Input
                    id="approved-amount"
                    type="number"
                    placeholder="0.00"
                    value={approvedAmount}
                    onChange={(e) => setApprovedAmount(e.target.value)}
                    data-testid="input-approved-amount"
                  />
                  <p className="text-sm text-muted-foreground">
                    You can adjust the approved amount if needed
                  </p>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="review-notes">Review Notes</Label>
                  <textarea
                    id="review-notes"
                    className="w-full min-h-[100px] p-3 border rounded-md"
                    placeholder="Add your review notes here..."
                    value={reviewNotes}
                    onChange={(e) => setReviewNotes(e.target.value)}
                    data-testid="textarea-review-notes"
                  />
                </div>
              </div>
            )}
            <DialogFooter className="flex gap-2">
              <Button 
                variant="outline" 
                onClick={() => setIsClaimReviewDialogOpen(false)}
                data-testid="button-cancel-claim-review"
              >
                Cancel
              </Button>
              <Button 
                variant="destructive"
                onClick={() => handleVoteOnClaim('reject')}
                disabled={voteOnClaimMutation.isPending}
                data-testid="button-vote-reject-claim"
              >
                {voteOnClaimMutation.isPending ? (
                  <>
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                    Voting...
                  </>
                ) : (
                  <>
                    <XCircle className="h-4 w-4 mr-2" />
                    Vote to Reject
                  </>
                )}
              </Button>
              <Button 
                onClick={() => handleVoteOnClaim('approve')}
                disabled={voteOnClaimMutation.isPending}
                data-testid="button-vote-approve-claim"
              >
                {voteOnClaimMutation.isPending ? (
                  <>
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                    Voting...
                  </>
                ) : (
                  <>
                    <CheckCircle className="h-4 w-4 mr-2" />
                    Vote to Approve
                  </>
                )}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>
    </div>
  );
}

