import { useState } from "react";
import { useMutation } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { useToast } from "@/hooks/use-toast";
import { useWallet } from "@/hooks/use-wallet";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { getNetworkById } from "@/lib/networks";
import { getTokenBySymbol } from "@/lib/tokens";
import { FileTextIcon, Loader2, Shield, Upload, X } from "lucide-react";
import { useDropzone } from "react-dropzone";

interface DocumentUpload {
  documentType: string;
  fileName: string;
  fileSize: number;
  mimeType: string;
  data: string;
  hash: string;
}

export function PoolGuaranteeApplication({ walletAddress }: { walletAddress: string }) {
  const { toast } = useToast();
  const { settings } = useWallet();

  // Get the selected network (default to Base Sepolia)
  const selectedNetworkId = settings?.selectedNetworkId || 1;
  const selectedNetwork = getNetworkById(selectedNetworkId);
  const tokenSymbol = selectedNetworkId === 2 ? 'USDC.e' : 'USDC';
  const usdcToken = getTokenBySymbol(selectedNetworkId, tokenSymbol);

  // Customer Identity Fields
  const [buyerCompanyName, setBuyerCompanyName] = useState("");
  const [buyerRegistrationNumber, setBuyerRegistrationNumber] = useState("");
  const [buyerCountry, setBuyerCountry] = useState("");
  const [buyerContactPerson, setBuyerContactPerson] = useState("");
  const [buyerEmail, setBuyerEmail] = useState("");
  const [buyerPhone, setBuyerPhone] = useState("");

  // Trade Details
  const [tradeDescription, setTradeDescription] = useState("");
  const [tradeValue, setTradeValue] = useState("");
  const [requestedAmount, setRequestedAmount] = useState("");
  const [collateralDescription, setCollateralDescription] = useState("");
  const [collateralValue, setCollateralValue] = useState("");
  const [sellerAddress, setSellerAddress] = useState("");
  const [requestedDuration, setRequestedDuration] = useState("90");

  // Sales Contract Details
  const [salesContractNumber, setSalesContractNumber] = useState("");
  const [salesContractDate, setSalesContractDate] = useState("");

  // Document Uploads
  const [proformaInvoice, setProformaInvoice] = useState<DocumentUpload | null>(null);
  const [salesContract, setSalesContract] = useState<DocumentUpload | null>(null);

  // Calculate 1% fee
  const calculatedFee = requestedAmount ? (parseFloat(requestedAmount) * 0.01).toFixed(2) : "0.00";

  // File upload handler
  const handleFileUpload = async (file: File, documentType: string) => {
    return new Promise<DocumentUpload>((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => {
        const base64 = reader.result as string;
        const base64Data = base64.split(',')[1]; // Remove data:image/png;base64, prefix

        // Simple hash (in production, use crypto.subtle.digest)
        const hash = `0x${btoa(base64Data.substring(0, 100)).replace(/[^a-zA-Z0-9]/g, '').substring(0, 64)}`;

        resolve({
          documentType,
          fileName: file.name,
          fileSize: file.size,
          mimeType: file.type,
          data: base64Data,
          hash
        });
      };
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  };

  // Proforma Invoice Dropzone
  const proformaDropzone = useDropzone({
    accept: {
      'application/pdf': ['.pdf'],
      'image/*': ['.png', '.jpg', '.jpeg']
    },
    maxFiles: 1,
    maxSize: 10 * 1024 * 1024, // 10MB limit
    onDrop: async (acceptedFiles) => {
      if (acceptedFiles.length > 0) {
        try {
          const doc = await handleFileUpload(acceptedFiles[0], "proforma_invoice");
          setProformaInvoice(doc);
          toast({ title: "Proforma Invoice uploaded successfully" });
        } catch (error) {
          toast({ title: "Upload failed", description: "Could not process file", variant: "destructive" });
        }
      }
    },
    onDropRejected: (fileRejections) => {
      const rejection = fileRejections[0];
      if (rejection.errors.some(e => e.code === 'file-too-large')) {
        toast({
          title: "File too large",
          description: "Maximum file size is 10MB. Please compress your document or use a smaller file.",
          variant: "destructive"
        });
      } else if (rejection.errors.some(e => e.code === 'file-invalid-type')) {
        toast({
          title: "Invalid file type",
          description: "Only PDF and image files (PNG, JPG) are accepted.",
          variant: "destructive"
        });
      }
    }
  });

  // Sales Contract Dropzone
  const salesContractDropzone = useDropzone({
    accept: {
      'application/pdf': ['.pdf'],
      'image/*': ['.png', '.jpg', '.jpeg']
    },
    maxFiles: 1,
    maxSize: 10 * 1024 * 1024, // 10MB limit
    onDrop: async (acceptedFiles) => {
      if (acceptedFiles.length > 0) {
        try {
          const doc = await handleFileUpload(acceptedFiles[0], "sales_contract");
          setSalesContract(doc);
          toast({ title: "Sales Contract uploaded successfully" });
        } catch (error) {
          toast({ title: "Upload failed", description: "Could not process file", variant: "destructive" });
        }
      }
    },
    onDropRejected: (fileRejections) => {
      const rejection = fileRejections[0];
      if (rejection.errors.some(e => e.code === 'file-too-large')) {
        toast({
          title: "File too large",
          description: "Maximum file size is 10MB. Please compress your document or use a smaller file.",
          variant: "destructive"
        });
      } else if (rejection.errors.some(e => e.code === 'file-invalid-type')) {
        toast({
          title: "Invalid file type",
          description: "Only PDF and image files (PNG, JPG) are accepted.",
          variant: "destructive"
        });
      }
    }
  });

  const applyMutation = useMutation({
    mutationFn: async (data: any) => {
      return apiRequest("POST", "/api/pool-guarantee/applications", data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/pool-guarantee/applications"] });
      toast({
        title: "Application Submitted!",
        description: `Your Pool Guarantee application has been submitted. Issuance fee: ${calculatedFee} USDC (1%)`
      });
      // Reset form
      setBuyerCompanyName("");
      setBuyerRegistrationNumber("");
      setBuyerCountry("");
      setBuyerContactPerson("");
      setBuyerEmail("");
      setBuyerPhone("");
      setTradeDescription("");
      setTradeValue("");
      setRequestedAmount("");
      setCollateralDescription("");
      setCollateralValue("");
      setSellerAddress("");
      setRequestedDuration("90");
      setSalesContractNumber("");
      setSalesContractDate("");
      setProformaInvoice(null);
      setSalesContract(null);
    },
    onError: (error: Error) => {
      toast({
        title: "Application Failed",
        description: error.message,
        variant: "destructive"
      });
    }
  });

  const handleSubmit = () => {
    // Validate required customer identity fields
    if (!buyerCompanyName || !buyerRegistrationNumber || !buyerCountry || !buyerContactPerson || !buyerEmail || !buyerPhone) {
      toast({
        title: "Incomplete Customer Identity",
        description: "All customer identity fields are required (company name, registration number, country, contact person, email, phone)",
        variant: "destructive"
      });
      return;
    }

    // Validate required trade details
    if (!tradeDescription || !requestedAmount || !collateralDescription || !sellerAddress) {
      toast({
        title: "Incomplete Trade Details",
        description: "Please fill in all required trade details",
        variant: "destructive"
      });
      return;
    }

    if (!proformaInvoice) {
      toast({
        title: "Missing Document",
        description: "Please upload the Proforma Invoice",
        variant: "destructive"
      });
      return;
    }

    if (!salesContract) {
      toast({
        title: "Missing Document",
        description: "Please upload the Sales Contract",
        variant: "destructive"
      });
      return;
    }

    // Calculate payment due date
    const paymentDueDate = new Date();
    paymentDueDate.setDate(paymentDueDate.getDate() + parseInt(requestedDuration));

    const applicationData = {
      buyerAddress: walletAddress,
      sellerAddress: sellerAddress.toLowerCase(),

      // Customer Identity
      buyerCompanyName,
      buyerRegistrationNumber,
      buyerCountry,
      buyerContactPerson,
      buyerEmail,
      buyerPhone,

      // Trade Details
      tradeDescription,
      tradeValue,
      requestedAmount,
      collateralDescription,
      collateralValue,
      requestedDuration: parseInt(requestedDuration),
      paymentDueDate: paymentDueDate.toISOString(),

      // Sales Contract
      salesContractNumber,
      salesContractDate: salesContractDate ? new Date(salesContractDate).toISOString() : null,

      // Token details (network-aware: USDC on Base, USDC.e on Lisk)
      tokenAddress: usdcToken?.address || "0x036CbD53842c5426634e7929541eC2318f3dCF7e",
      tokenSymbol: tokenSymbol,
      networkId: selectedNetworkId,

      // Documents array
      documents: [proformaInvoice, salesContract]
    };

    applyMutation.mutate(applicationData);
  };

  return (
    <Card data-testid="card-pool-guarantee-apply">
      <CardHeader>
        <CardTitle>Apply for Pool Guarantee</CardTitle>
        <CardDescription>
          Submit application with proforma invoice and sales contract. Replaces traditional Letter of Credit.
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-6">

        {/* Customer Identity Section */}
        <div className="border rounded-lg p-4 space-y-4 bg-muted/30">
          <h3 className="font-semibold text-sm">Customer Identity (Required)</h3>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="input-company-name">Company Name *</Label>
              <Input
                id="input-company-name"
                data-testid="input-company-name"
                placeholder="ABC Trading Ltd."
                value={buyerCompanyName}
                onChange={(e) => setBuyerCompanyName(e.target.value)}
                required
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="input-registration-number">Registration Number *</Label>
              <Input
                id="input-registration-number"
                data-testid="input-registration-number"
                placeholder="12345678"
                value={buyerRegistrationNumber}
                onChange={(e) => setBuyerRegistrationNumber(e.target.value)}
                required
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="input-country">Country *</Label>
              <Input
                id="input-country"
                data-testid="input-country"
                placeholder="United States"
                value={buyerCountry}
                onChange={(e) => setBuyerCountry(e.target.value)}
                required
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="input-contact-person">Contact Person *</Label>
              <Input
                id="input-contact-person"
                data-testid="input-contact-person"
                placeholder="John Doe"
                value={buyerContactPerson}
                onChange={(e) => setBuyerContactPerson(e.target.value)}
                required
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="input-buyer-email">Email *</Label>
              <Input
                id="input-buyer-email"
                data-testid="input-buyer-email"
                type="email"
                placeholder="contact@company.com"
                value={buyerEmail}
                onChange={(e) => setBuyerEmail(e.target.value)}
                required
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="input-buyer-phone">Phone *</Label>
              <Input
                id="input-buyer-phone"
                data-testid="input-buyer-phone"
                placeholder="+1 234 567 8900"
                value={buyerPhone}
                onChange={(e) => setBuyerPhone(e.target.value)}
                required
              />
            </div>
          </div>
        </div>

        {/* Trade Details Section */}
        <div className="space-y-4">
          <h3 className="font-semibold text-sm">Trade Details</h3>

          <div className="space-y-2">
            <Label htmlFor="input-trade-description">Trade Description *</Label>
            <Textarea
              id="input-trade-description"
              data-testid="input-trade-description"
              placeholder="e.g., Import of 10,000 units of electronics from China"
              value={tradeDescription}
              onChange={(e) => setTradeDescription(e.target.value)}
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="input-trade-value">Total Trade Value (USDC)</Label>
              <Input
                id="input-trade-value"
                data-testid="input-trade-value"
                type="number"
                placeholder="100000"
                value={tradeValue}
                onChange={(e) => setTradeValue(e.target.value)}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="input-requested-amount">Guarantee Amount Requested (USDC) *</Label>
              <Input
                id="input-requested-amount"
                data-testid="input-requested-amount"
                type="number"
                placeholder="50000"
                value={requestedAmount}
                onChange={(e) => setRequestedAmount(e.target.value)}
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="input-collateral-description">Collateral Description *</Label>
              <Input
                id="input-collateral-description"
                data-testid="input-collateral-description"
                placeholder="e.g., 10,000 units of electronics (goods as collateral)"
                value={collateralDescription}
                onChange={(e) => setCollateralDescription(e.target.value)}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="input-collateral-value">Collateral Value (USDC)</Label>
              <Input
                id="input-collateral-value"
                data-testid="input-collateral-value"
                type="number"
                placeholder="100000"
                value={collateralValue}
                onChange={(e) => setCollateralValue(e.target.value)}
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="input-seller-address">Seller/Beneficiary Wallet Address *</Label>
              <Input
                id="input-seller-address"
                data-testid="input-seller-address"
                placeholder="0x..."
                value={sellerAddress}
                onChange={(e) => setSellerAddress(e.target.value)}
              />
              <p className="text-xs text-muted-foreground">
                Seller will approve the draft guarantee certificate
              </p>
            </div>

            <div className="space-y-2">
              <Label htmlFor="input-requested-duration">Financing Duration (days)</Label>
              <Input
                id="input-requested-duration"
                data-testid="input-requested-duration"
                type="number"
                placeholder="90"
                value={requestedDuration}
                onChange={(e) => setRequestedDuration(e.target.value)}
              />
            </div>
          </div>
        </div>

        {/* Sales Contract Reference */}
        <div className="space-y-4">
          <h3 className="font-semibold text-sm">Sales Contract Reference</h3>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="input-sales-contract-number">Contract Number</Label>
              <Input
                id="input-sales-contract-number"
                data-testid="input-sales-contract-number"
                placeholder="SC-2025-001"
                value={salesContractNumber}
                onChange={(e) => setSalesContractNumber(e.target.value)}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="input-sales-contract-date">Contract Date</Label>
              <Input
                id="input-sales-contract-date"
                data-testid="input-sales-contract-date"
                type="date"
                value={salesContractDate}
                onChange={(e) => setSalesContractDate(e.target.value)}
              />
            </div>
          </div>
        </div>

        {/* Document Uploads Section */}
        <div className="space-y-4">
          <h3 className="font-semibold text-sm">Required Documents</h3>

          {/* Proforma Invoice Upload */}
          <div className="space-y-2">
            <Label>Proforma Invoice *</Label>
            {!proformaInvoice ? (
              <div
                {...proformaDropzone.getRootProps()}
                className="border-2 border-dashed rounded-lg p-6 text-center cursor-pointer hover:border-primary transition-colors"
                data-testid="dropzone-proforma-invoice"
              >
                <input {...proformaDropzone.getInputProps()} />
                <Upload className="h-8 w-8 mx-auto mb-2 text-muted-foreground" />
                <p className="text-sm text-muted-foreground">
                  Drag & drop proforma invoice here, or click to select
                </p>
                <p className="text-xs text-muted-foreground mt-1">
                  PDF or Image (PNG, JPG) • Max 10MB
                </p>
              </div>
            ) : (
              <div className="flex items-center justify-between p-3 border rounded-lg bg-muted/30" data-testid="uploaded-proforma-invoice">
                <div className="flex items-center gap-2">
                  <FileTextIcon className="h-5 w-5 text-blue-600" />
                  <div>
                    <p className="text-sm font-medium">{proformaInvoice.fileName}</p>
                    <p className="text-xs text-muted-foreground">
                      {(proformaInvoice.fileSize / 1024).toFixed(2)} KB
                    </p>
                  </div>
                </div>
                <Button
                  size="sm"
                  variant="ghost"
                  onClick={() => setProformaInvoice(null)}
                  data-testid="button-remove-proforma-invoice"
                >
                  <X className="h-4 w-4" />
                </Button>
              </div>
            )}
          </div>

          {/* Sales Contract Upload */}
          <div className="space-y-2">
            <Label>Sales Contract *</Label>
            {!salesContract ? (
              <div
                {...salesContractDropzone.getRootProps()}
                className="border-2 border-dashed rounded-lg p-6 text-center cursor-pointer hover:border-primary transition-colors"
                data-testid="dropzone-sales-contract"
              >
                <input {...salesContractDropzone.getInputProps()} />
                <Upload className="h-8 w-8 mx-auto mb-2 text-muted-foreground" />
                <p className="text-sm text-muted-foreground">
                  Drag & drop sales contract here, or click to select
                </p>
                <p className="text-xs text-muted-foreground mt-1">
                  PDF or Image (PNG, JPG) • Max 10MB
                </p>
              </div>
            ) : (
              <div className="flex items-center justify-between p-3 border rounded-lg bg-muted/30" data-testid="uploaded-sales-contract">
                <div className="flex items-center gap-2">
                  <FileTextIcon className="h-5 w-5 text-green-600" />
                  <div>
                    <p className="text-sm font-medium">{salesContract.fileName}</p>
                    <p className="text-xs text-muted-foreground">
                      {(salesContract.fileSize / 1024).toFixed(2)} KB
                    </p>
                  </div>
                </div>
                <Button
                  size="sm"
                  variant="ghost"
                  onClick={() => setSalesContract(null)}
                  data-testid="button-remove-sales-contract"
                >
                  <X className="h-4 w-4" />
                </Button>
              </div>
            )}
          </div>
        </div>

        {/* Fee Calculation Display */}
        {requestedAmount && parseFloat(requestedAmount) > 0 && (
          <div className="border rounded-lg p-4 bg-blue-50 dark:bg-blue-950/20 border-blue-200 dark:border-blue-800">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium">Issuance Fee (1%)</p>
                <p className="text-xs text-muted-foreground">
                  Payable after seller approves draft certificate
                </p>
              </div>
              <div className="text-2xl font-bold text-blue-600" data-testid="text-calculated-fee">
                {calculatedFee} USDC
              </div>
            </div>
          </div>
        )}

        {/* Submit Button */}
        <Button
          data-testid="button-submit-pool-guarantee"
          onClick={handleSubmit}
          disabled={applyMutation.isPending}
          className="w-full"
          size="lg"
        >
          {applyMutation.isPending ? (
            <>
              <Loader2 className="h-5 w-5 mr-2 animate-spin" />
              Submitting Application...
            </>
          ) : (
            <>
              <Shield className="h-5 w-5 mr-2" />
              Submit Pool Guarantee Application
            </>
          )}
        </Button>

        <p className="text-xs text-center text-muted-foreground">
          After submission, treasury will draft a guarantee certificate following ICC URDG 758 standards
        </p>
      </CardContent>
    </Card>
  );
}

