import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { useToast } from "@/hooks/use-toast";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { 
  FileTextIcon, 
  CheckCircleIcon,
  XCircleIcon,
  Clock,
  Shield,
  Eye,
  Edit,
  Send
} from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
  DialogFooter
} from "@/components/ui/dialog";
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/components/ui/accordion";

interface TreasuryPortalProps {
  walletAddress: string;
}

export function TreasuryPortal({ walletAddress }: TreasuryPortalProps) {
  const { toast } = useToast();
  const [selectedApplication, setSelectedApplication] = useState<any>(null);
  const [isDraftDialogOpen, setIsDraftDialogOpen] = useState(false);

  // Claim review state
  const [isClaimReviewDialogOpen, setIsClaimReviewDialogOpen] = useState(false);
  const [selectedClaim, setSelectedClaim] = useState<any>(null);
  const [reviewNotes, setReviewNotes] = useState("");
  const [approvedAmount, setApprovedAmount] = useState("");

  // Fetch all applications (treasury sees everything)
  const { data: allApplications = [], isLoading } = useQuery({
    queryKey: ["/api/pool-guarantee/applications", "all"],
    queryFn: async () => {
      const res = await fetch(`/api/pool-guarantee/applications/all`, {
        credentials: "include",
      });
      if (!res.ok) {
        if (res.status === 404) return [];
        throw new Error(`${res.status}: ${await res.text() || res.statusText}`);
      }
      return await res.json();
    }
  });

  // Fetch all pending claims (treasury reviews all claims)
  const { data: allClaims = [] } = useQuery({
    queryKey: ["/api/pool-guarantee/claims"],
    queryFn: async () => {
      const res = await fetch(`/api/pool-guarantee/claims`, {
        credentials: "include",
      });
      if (!res.ok) {
        if (res.status === 404) return [];
        throw new Error(`${res.status}: ${await res.text() || res.statusText}`);
      }
      return await res.json();
    }
  });

  // Filter applications by status
  const pendingDraft = allApplications.filter((app: any) => app.status === "pending_draft");
  const awaitingFee = allApplications.filter((app: any) => app.status === "awaiting_fee_payment");
  const feePaid = allApplications.filter((app: any) => app.status === "fee_paid");
  const approved = allApplications.filter((app: any) => app.status === "approved");

  // Filter claims by status
  const pendingClaims = allClaims.filter((claim: any) => claim.status === "pending");
  const approvedClaims = allClaims.filter((claim: any) => claim.status === "approved");
  const rejectedClaims = allClaims.filter((claim: any) => claim.status === "rejected");

  // Create draft certificate mutation (server now generates certificate)
  const createDraftMutation = useMutation({
    mutationFn: async ({ requestId }: { requestId: string }) => {
      return await apiRequest("POST", `/api/pool-guarantee/applications/${requestId}/draft`, {
        treasuryAddress: walletAddress
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/pool-guarantee/applications"] });
      toast({
        title: "Draft Certificate Created",
        description: "URDG 758-compliant draft certificate has been sent to the seller for approval",
      });
      setIsDraftDialogOpen(false);
      setSelectedApplication(null);
    },
    onError: (error: any) => {
      toast({
        title: "Error Creating Draft",
        description: error.message || "Failed to create draft certificate",
        variant: "destructive"
      });
    }
  });

  // Finalize guarantee mutation
  const finalizeMutation = useMutation({
    mutationFn: async (requestId: string) => {
      return await apiRequest("POST", `/api/pool-guarantee/applications/${requestId}/finalize`, {
        treasuryAddress: walletAddress
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/pool-guarantee/applications"] });
      toast({
        title: "Guarantee Finalized",
        description: "Final Pool Guarantee certificate has been issued",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Error Finalizing",
        description: error.message || "Failed to finalize guarantee",
        variant: "destructive"
      });
    }
  });

  // Approve claim mutation
  const approveClaimMutation = useMutation({
    mutationFn: async ({ claimId, approvedAmount, reviewNotes }: { claimId: number; approvedAmount: string; reviewNotes: string }) => {
      return await apiRequest("PATCH", `/api/pool-guarantee/claims/${claimId}`, {
        status: "approved",
        reviewedBy: walletAddress,
        reviewNotes,
        approvedAmount,
        reviewedAt: new Date().toISOString()
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/pool-guarantee/claims"] });
      toast({
        title: "Claim Approved",
        description: "Claim has been approved. Payment will be processed within 24 hours.",
      });
      setIsClaimReviewDialogOpen(false);
      setSelectedClaim(null);
      setReviewNotes("");
      setApprovedAmount("");
    },
    onError: (error: any) => {
      toast({
        title: "Error Approving Claim",
        description: error.message || "Failed to approve claim",
        variant: "destructive"
      });
    }
  });

  // Reject claim mutation
  const rejectClaimMutation = useMutation({
    mutationFn: async ({ claimId, reviewNotes }: { claimId: number; reviewNotes: string }) => {
      return await apiRequest("PATCH", `/api/pool-guarantee/claims/${claimId}`, {
        status: "rejected",
        reviewedBy: walletAddress,
        reviewNotes,
        reviewedAt: new Date().toISOString()
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/pool-guarantee/claims"] });
      toast({
        title: "Claim Rejected",
        description: "Claim has been rejected.",
      });
      setIsClaimReviewDialogOpen(false);
      setSelectedClaim(null);
      setReviewNotes("");
    },
    onError: (error: any) => {
      toast({
        title: "Error Rejecting Claim",
        description: error.message || "Failed to reject claim",
        variant: "destructive"
      });
    }
  });

  const handleCreateDraft = (app: any) => {
    setSelectedApplication(app);
    setIsDraftDialogOpen(true);
  };

  const handleSubmitDraft = () => {
    if (!selectedApplication) {
      toast({
        title: "Invalid Selection",
        description: "Please select an application",
        variant: "destructive"
      });
      return;
    }

    createDraftMutation.mutate({
      requestId: selectedApplication.requestId
    });
  };

  const handleFinalize = (requestId: string) => {
    if (confirm("Are you sure you want to issue the final Pool Guarantee certificate?")) {
      finalizeMutation.mutate(requestId);
    }
  };

  const handleOpenClaimReview = (claim: any) => {
    setSelectedClaim(claim);
    setApprovedAmount(claim.claimAmount);
    setIsClaimReviewDialogOpen(true);
  };

  const handleApproveClaim = () => {
    if (!selectedClaim || !approvedAmount) {
      toast({
        title: "Missing Information",
        description: "Please enter the approved amount",
        variant: "destructive"
      });
      return;
    }

    approveClaimMutation.mutate({
      claimId: selectedClaim.id,
      approvedAmount,
      reviewNotes
    });
  };

  const handleRejectClaim = () => {
    if (!selectedClaim || !reviewNotes) {
      toast({
        title: "Missing Information",
        description: "Please provide a reason for rejection",
        variant: "destructive"
      });
      return;
    }

    rejectClaimMutation.mutate({
      claimId: selectedClaim.id,
      reviewNotes
    });
  };

  if (isLoading) {
    return (
      <Card>
        <CardContent className="pt-6">
          <p className="text-center text-muted-foreground">Loading applications...</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-6">
      {/* Treasury Overview Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <Card data-testid="stat-pending-draft">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Pending Draft</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-yellow-600">{pendingDraft.length}</div>
            <p className="text-xs text-muted-foreground">Awaiting draft creation</p>
          </CardContent>
        </Card>

        <Card data-testid="stat-awaiting-fee">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Awaiting Fee</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-orange-600">{awaitingFee.length}</div>
            <p className="text-xs text-muted-foreground">Fee payment pending</p>
          </CardContent>
        </Card>

        <Card data-testid="stat-ready-to-finalize">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Ready to Finalize</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-purple-600">{feePaid.length}</div>
            <p className="text-xs text-muted-foreground">Fee paid, issue final</p>
          </CardContent>
        </Card>

        <Card data-testid="stat-finalized">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Finalized</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-green-600">{approved.length}</div>
            <p className="text-xs text-muted-foreground">Active guarantees</p>
          </CardContent>
        </Card>
      </div>

      {/* Pending Draft Applications */}
      <Card data-testid="card-pending-drafts">
        <CardHeader>
          <CardTitle className="flex items-center">
            <Clock className="h-5 w-5 mr-2 text-yellow-600" />
            Applications Pending Draft ({pendingDraft.length})
          </CardTitle>
          <CardDescription>Create draft Pool Guarantee certificates for buyer applications</CardDescription>
        </CardHeader>
        <CardContent>
          {pendingDraft.length === 0 ? (
            <p className="text-sm text-muted-foreground text-center py-8" data-testid="text-no-pending-drafts">
              No applications pending draft creation
            </p>
          ) : (
            <div className="space-y-4">
              {pendingDraft.map((app: any) => (
                <ApplicationCard 
                  key={app.requestId} 
                  app={app}
                  action={
                    <Button 
                      onClick={() => handleCreateDraft(app)}
                      size="sm"
                      data-testid={`button-create-draft-${app.requestId}`}
                    >
