      {/* Claim Review Dialog */}
      <Dialog open={isClaimReviewDialogOpen} onOpenChange={setIsClaimReviewDialogOpen}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>Review Claim for Buyer Default</DialogTitle>
            <DialogDescription>
              Review seller claim and approve payment from guarantee pool or reject with reason
            </DialogDescription>
          </DialogHeader>

          {selectedClaim && (
            <div className="space-y-4">
              {/* Claim Summary */}
              <div className="border rounded-lg p-4 bg-muted/30 space-y-2">
                <h4 className="font-semibold text-sm">Claim Details</h4>
                <div className="grid grid-cols-2 gap-3 text-sm">
                  <div>
                    <span className="text-muted-foreground">Claim ID:</span>
                    <span className="ml-2 font-medium">#{selectedClaim.id}</span>
                  </div>
                  <div>
                    <span className="text-muted-foreground">Request ID:</span>
                    <span className="ml-2 font-medium">{selectedClaim.requestId}</span>
                  </div>
                  <div>
                    <span className="text-muted-foreground">Claimant:</span>
                    <span className="ml-2 font-medium text-xs">{selectedClaim.claimantAddress}</span>
                  </div>
                  <div>
                    <span className="text-muted-foreground">Claim Amount:</span>
                    <span className="ml-2 font-medium text-red-600">
                      {parseFloat(selectedClaim.claimAmount).toFixed(2)} USDC
                    </span>
                  </div>
                  <div>
                    <span className="text-muted-foreground">Reason:</span>
                    <span className="ml-2 font-medium capitalize">{selectedClaim.claimReason.replace(/_/g, ' ')}</span>
                  </div>
                  <div>
                    <span className="text-muted-foreground">Submitted:</span>
                    <span className="ml-2 font-medium">
                      {selectedClaim.claimedAt ? new Date(selectedClaim.claimedAt).toLocaleDateString() : 'Unknown'}
                    </span>
                  </div>
                </div>
              </div>

              {/* Supporting Evidence */}
              {selectedClaim.supportingDocuments && (
                <div className="space-y-2">
                  <Label className="text-sm font-medium">Supporting Evidence</Label>
                  <div className="border rounded-lg p-3 bg-muted/50 text-sm whitespace-pre-wrap">
                    {JSON.parse(selectedClaim.supportingDocuments).join('\n')}
                  </div>
                </div>
              )}

              {/* Approved Amount Input */}
              <div className="space-y-2">
                <Label htmlFor="approved-amount">Approved Amount (USDC)</Label>
                <Input
                  id="approved-amount"
                  type="number"
                  step="0.01"
                  value={approvedAmount}
                  onChange={(e) => setApprovedAmount(e.target.value)}
                  placeholder="Enter approved amount"
                  data-testid="input-approved-amount"
                />
                <p className="text-xs text-muted-foreground">
                  You can approve a different amount than requested. Maximum: {parseFloat(selectedClaim.claimAmount).toFixed(2)} USDC
                </p>
              </div>

              {/* Review Notes */}
              <div className="space-y-2">
                <Label htmlFor="review-notes">Review Notes</Label>
                <Textarea
                  id="review-notes"
                  value={reviewNotes}
                  onChange={(e) => setReviewNotes(e.target.value)}
                  placeholder="Add review notes (required for rejection)"
                  rows={3}
                  data-testid="textarea-review-notes"
                />
                <p className="text-xs text-muted-foreground">
                  Provide reasoning for your decision
                </p>
              </div>

              {/* Action Notice */}
              <div className="border-l-4 border-blue-500 bg-blue-50 dark:bg-blue-950/20 p-3 rounded">
                <p className="text-sm text-blue-800 dark:text-blue-200">
                  <strong>Approval:</strong> Payment will be automatically executed from the treasury pool within 24 hours.
                </p>
              </div>
            </div>
          )}

          <DialogFooter className="flex gap-2">
            <Button 
              variant="outline" 
              onClick={() => setIsClaimReviewDialogOpen(false)}
              data-testid="button-cancel-review"
            >
              Cancel
            </Button>
            <Button 
              variant="destructive"
              onClick={handleRejectClaim}
              disabled={rejectClaimMutation.isPending}
              data-testid="button-reject-claim"
            >
              {rejectClaimMutation.isPending ? (
                <>Rejecting...</>
              ) : (
                <>
                  <XCircleIcon className="h-4 w-4 mr-1" />
