              onClick={handleApproveClaim}
              disabled={approveClaimMutation.isPending || !approvedAmount}
              data-testid="button-approve-claim"
              className="bg-green-600 hover:bg-green-700"
            >
              {approveClaimMutation.isPending ? (
                <>Approving...</>
              ) : (
                <>
                  <CheckCircleIcon className="h-4 w-4 mr-1" />
                  Approve & Execute Payment
                </>
              )}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

