// Helper function to convert number to words (simplified version)
function numberToWords(num: number): string {
  if (num === 0) return 'Zero';

  const ones = ['', 'One', 'Two', 'Three', 'Four', 'Five', 'Six', 'Seven', 'Eight', 'Nine'];
  const tens = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty', 'Seventy', 'Eighty', 'Ninety'];
  const teens = ['Ten', 'Eleven', 'Twelve', 'Thirteen', 'Fourteen', 'Fifteen', 'Sixteen', 'Seventeen', 'Eighteen', 'Nineteen'];

  const numStr = Math.floor(num).toString();
  const len = numStr.length;

  if (len > 9) return num.toFixed(2); // Return number if too large

  let words = '';

  // Millions
  if (len >= 7) {
    const millionDigit = parseInt(numStr[len - 7]);
    if (millionDigit > 0) words += ones[millionDigit] + ' Million ';
  }

  // Hundred thousands
  if (len >= 6) {
    const hundredThousandDigit = parseInt(numStr[len - 6]);
    if (hundredThousandDigit > 0) words += ones[hundredThousandDigit] + ' Hundred ';
  }

  // Ten thousands
  if (len >= 5) {
    const tenThousandDigit = parseInt(numStr[len - 5]);
    const thousandDigit = len >= 4 ? parseInt(numStr[len - 4]) : 0;
    if (tenThousandDigit === 1) {
      words += teens[thousandDigit] + ' Thousand ';
    } else {
      if (tenThousandDigit > 0) words += tens[tenThousandDigit] + ' ';
      if (thousandDigit > 0) words += ones[thousandDigit] + ' ';
      if (tenThousandDigit > 0 || thousandDigit > 0) words += 'Thousand ';
    }
  } else if (len >= 4) {
    const thousandDigit = parseInt(numStr[len - 4]);
    if (thousandDigit > 0) words += ones[thousandDigit] + ' Thousand ';
  }

  // Hundreds
  if (len >= 3) {
    const hundredDigit = parseInt(numStr[len - 3]);
    if (hundredDigit > 0) words += ones[hundredDigit] + ' Hundred ';
  }

  // Tens and ones
  if (len >= 2) {
    const tenDigit = parseInt(numStr[len - 2]);
    const oneDigit = len >= 1 ? parseInt(numStr[len - 1]) : 0;
    if (tenDigit === 1) {
      words += teens[oneDigit];
    } else {
      if (tenDigit > 0) words += tens[tenDigit] + ' ';
      if (oneDigit > 0) words += ones[oneDigit];
    }
  } else if (len === 1) {
    words += ones[parseInt(numStr[0])];
  }

  // Add decimal part
  const decimalPart = (num % 1).toFixed(2).substring(2);
  if (decimalPart !== '00') {
    words += ' and ' + decimalPart + '/100';
  }

  return words.trim();
}

// Helper function for status badge colors
function getStatusBadgeClass(status: string): string {
  switch (status) {
    case 'approved':
      return 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200';
    case 'pending_draft':
      return 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-200';
    case 'draft_sent_to_seller':
      return 'bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200';
    case 'seller_approved':
      return 'bg-purple-100 text-purple-800 dark:bg-purple-900 dark:text-purple-200';
    case 'awaiting_fee_payment':
      return 'bg-orange-100 text-orange-800 dark:bg-orange-900 dark:text-orange-200';
    case 'fee_paid':
      return 'bg-indigo-100 text-indigo-800 dark:bg-indigo-900 dark:text-indigo-200';
    case 'seller_rejected':
      return 'bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200';
    default:
      return 'bg-gray-100 text-gray-800 dark:bg-gray-800 dark:text-gray-200';
  }
}

