export function SellerApprovalDashboard({ sellerAddress }: SellerApprovalDashboardProps) {
  const { toast } = useToast();
  const [selectedApplication, setSelectedApplication] = useState<any>(null);
  const [isReviewDialogOpen, setIsReviewDialogOpen] = useState(false);
  const [rejectionReason, setRejectionReason] = useState("");
  const [draftCertificate, setDraftCertificate] = useState("");
  const [isCertificateViewDialogOpen, setIsCertificateViewDialogOpen] = useState(false);
  const [viewingApplication, setViewingApplication] = useState<any>(null);
  const [viewingCertificate, setViewingCertificate] = useState("");

  // Fetch all applications for this seller (not just pending approval)
  const { data: allSellerApplications = [], isLoading } = useQuery({
    queryKey: ["/api/pool-guarantee/applications", "seller", sellerAddress],
    queryFn: async () => {
      const res = await fetch(`/api/pool-guarantee/applications/all`, {
        credentials: "include",
      });
      if (!res.ok) {
        if (res.status === 404) return [];
        throw new Error(`${res.status}: ${await res.text() || res.statusText}`);
      }
      const allApps = await res.json();
      // Filter for applications sent to this seller
      return allApps.filter((app: any) => 
        app.sellerAddress.toLowerCase() === sellerAddress.toLowerCase()
      );
    },
    enabled: !!sellerAddress
  });

  // Separate applications by status
  const draftReadyApplications = allSellerApplications.filter((app: any) => 
    app.status === "draft_sent_to_seller"
  );
  const awaitingDraftApplications = allSellerApplications.filter((app: any) => 
    app.status === "pending_draft"
  );
  const completedApplications = allSellerApplications.filter((app: any) => 
    app.status !== "draft_sent_to_seller" && app.status !== "pending_draft"
  );

  // Approve draft mutation
  const approveMutation = useMutation({
    mutationFn: async (requestId: string) => {
      return await apiRequest("POST", `/api/pool-guarantee/applications/${requestId}/seller-response`, {
        approved: true,
        sellerAddress
      });
    },
    onSuccess: (data: any) => {
      queryClient.invalidateQueries({ queryKey: ["/api/pool-guarantee/applications"] });
      toast({
        title: "Draft Approved",
        description: `Buyer will be notified to pay ${data.feeDue} USDC issuance fee`,
      });
      setIsReviewDialogOpen(false);
      setSelectedApplication(null);
      setDraftCertificate("");
    },
    onError: (error: any) => {
      toast({
        title: "Error Approving Draft",
        description: error.message || "Failed to approve draft",
        variant: "destructive"
      });
    }
  });

  // Reject draft mutation
  const rejectMutation = useMutation({
    mutationFn: async ({ requestId, reason }: { requestId: string; reason: string }) => {
      return await apiRequest("POST", `/api/pool-guarantee/applications/${requestId}/seller-response`, {
        approved: false,
        rejectionReason: reason,
        sellerAddress
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/pool-guarantee/applications"] });
      toast({
        title: "Draft Rejected",
        description: "Treasury will be notified to revise the draft certificate",
      });
      setIsReviewDialogOpen(false);
      setSelectedApplication(null);
      setDraftCertificate("");
      setRejectionReason("");
    },
    onError: (error: any) => {
      toast({
        title: "Error Rejecting Draft",
        description: error.message || "Failed to reject draft",
        variant: "destructive"
      });
    }
  });

  const handleReviewDraft = async (app: any) => {
    setSelectedApplication(app);

    // Fetch the draft certificate
    try {
      const res = await fetch(`/api/pool-guarantee/${app.requestId}/certificates`, {
        credentials: "include"
      });
      if (res.ok) {
        const certificates = await res.json();
        const draftCert = certificates.find((cert: any) => cert.certificateType === "draft" && cert.isActive);
        if (draftCert) {
          setDraftCertificate(draftCert.content);
        } else {
          // No draft certificate found
          toast({
            title: "Draft Not Available",
            description: "The draft certificate hasn't been created yet. Please wait for treasury to prepare it.",
            variant: "destructive"
          });
          return;
        }
      }
    } catch (error) {
      console.error("Error fetching certificate:", error);
      toast({
        title: "Error",
        description: "Failed to load draft certificate. Please try again.",
        variant: "destructive"
      });
      return;
    }

    setIsReviewDialogOpen(true);
  };

  const handleViewCertificate = async (app: any) => {
    setViewingApplication(app);

    // Fetch the appropriate certificate (final if approved, draft otherwise)
    try {
      const res = await fetch(`/api/pool-guarantee/${app.requestId}/certificates`, {
        credentials: "include"
      });
      if (res.ok) {
        const certificates = await res.json();
        // Look for final certificate first, then draft
        const finalCert = certificates.find((cert: any) => cert.certificateType === "final" && cert.isActive);
        const draftCert = certificates.find((cert: any) => cert.certificateType === "draft" && cert.isActive);

        if (finalCert) {
          setViewingCertificate(finalCert.content);
        } else if (draftCert) {
          setViewingCertificate(draftCert.content);
        } else {
          // No certificate found
          setViewingCertificate("No certificate available for this application yet.");
          toast({
            title: "No Certificate Found",
            description: "The certificate for this application has not been created yet.",
            variant: "default"
          });
        }
      }
    } catch (error) {
      console.error("Error fetching certificate:", error);
      toast({
        title: "Error Loading Certificate",
        description: "Failed to load certificate. Please try again.",
        variant: "destructive"
      });
      setViewingCertificate("Error loading certificate. Please try again.");
    }

    setIsCertificateViewDialogOpen(true);
  };

  const handleApprove = () => {
    if (!selectedApplication) return;

    if (confirm("Are you sure you want to approve this Pool Guarantee draft certificate?")) {
      approveMutation.mutate(selectedApplication.requestId);
    }
  };

  const handleReject = () => {
    if (!selectedApplication) return;

    if (!rejectionReason.trim()) {
      toast({
        title: "Rejection Reason Required",
        description: "Please provide a reason for rejecting this draft",
        variant: "destructive"
      });
      return;
    }

    if (confirm("Are you sure you want to reject this draft? The treasury will need to revise it.")) {
      rejectMutation.mutate({
        requestId: selectedApplication.requestId,
        reason: rejectionReason
      });
    }
  };

  if (isLoading) {
    return (
      <Card>
        <CardContent className="pt-6">
          <p className="text-center text-muted-foreground">Loading applications...</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-6">
      {/* Seller Dashboard Header */}
      <Card data-testid="card-seller-dashboard-header">
        <CardHeader>
          <CardTitle className="flex items-center">
            <FileTextIcon className="h-5 w-5 mr-2 text-blue-600" />
            Draft Certificates Pending Your Approval
          </CardTitle>
          <CardDescription>
            Review and approve/reject Pool Guarantee draft certificates from treasury
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-2 gap-4">
            <div className="text-center p-3 bg-blue-50 dark:bg-blue-950/20 rounded-lg border border-blue-200 dark:border-blue-800">
              <div className="text-2xl font-bold text-blue-600">{draftReadyApplications.length}</div>
              <div className="text-xs text-muted-foreground">Ready for Your Review</div>
            </div>
            <div className="text-center p-3 bg-orange-50 dark:bg-orange-950/20 rounded-lg border border-orange-200 dark:border-orange-800">
              <div className="text-2xl font-bold text-orange-600">{awaitingDraftApplications.length}</div>
              <div className="text-xs text-muted-foreground">Waiting for Treasury</div>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Waiting for Treasury Draft Section */}
      {awaitingDraftApplications.length > 0 && (
        <Card data-testid="card-awaiting-draft" className="bg-gradient-to-br from-orange-50 to-amber-50 dark:from-orange-950/20 dark:to-amber-950/20 border-orange-200 dark:border-orange-800">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Clock className="h-5 w-5 text-orange-600" />
              Waiting for Treasury to Create Draft ({awaitingDraftApplications.length})
            </CardTitle>
            <CardDescription>
              These applications have been approved by treasury voting but are waiting for treasury to prepare the draft Pool Guarantee certificate
            </CardDescription>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              {awaitingDraftApplications.map((app: any) => (
                <div
                  key={app.requestId}
                  className="border rounded-lg p-4 space-y-2 bg-white dark:bg-gray-900"
                  data-testid={`awaiting-draft-${app.requestId}`}
                >
                  <div className="space-y-3">
                    <div className="space-y-1">
                      <p className="font-medium text-lg">{app.buyerCompanyName}</p>
                      <p className="text-sm text-muted-foreground">Request ID: {app.requestId}</p>
                    </div>

                    <div className="grid grid-cols-2 gap-x-4 gap-y-3">
                      <div>
                        <p className="text-xs text-muted-foreground">Guarantee Amount</p>
                        <p className="font-semibold text-green-600">{parseFloat(app.requestedAmount).toFixed(2)} USDC</p>
                      </div>
                      <div>
                        <p className="text-xs text-muted-foreground">Issuance Fee (1%)</p>
                        <p className="font-semibold text-blue-600">{parseFloat(app.feeDue || app.requestedAmount * 0.01).toFixed(2)} USDC</p>
                      </div>
                      <div>
                        <p className="text-xs text-muted-foreground">Buyer Address</p>
                        <p className="font-mono text-xs">{app.buyerAddress.slice(0, 10)}...{app.buyerAddress.slice(-8)}</p>
                      </div>
                      <div>
                        <p className="text-xs text-muted-foreground">Application Date</p>
