              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Drafts Ready for Review */}
      <Card data-testid="card-pending-seller-approvals">
        <CardHeader>
          <CardTitle>Drafts Ready for Your Approval</CardTitle>
