                           app.status === 'fee_paid' ? 'AWAITING CERTIFICATE' :
                           app.status === 'seller_approved' ? 'AWAITING FEE PAYMENT' :
                           app.status === 'awaiting_fee_payment' ? 'AWAITING FEE PAYMENT' :
                           app.status === 'seller_rejected' ? 'REJECTED' :
                           app.status.toUpperCase().replace(/_/g, ' ')}
