                        <span className="text-xs text-muted-foreground">
                          {parseFloat(app.requestedAmount).toFixed(2)} USDC
                        </span>
                      </div>
                    </div>
                    <Button 
                      onClick={() => handleViewCertificate(app)}
                      size="sm"
                      variant="outline"
                      data-testid={`button-view-certificate-${app.requestId}`}
                    >
                      <Eye className="h-4 w-4 mr-1" />
                      View Certificate
                    </Button>
                  </div>
                  {app.status === 'seller_rejected' && app.sellerRejectionReason && (
                    <div className="mt-2 p-2 bg-red-50 dark:bg-red-950/20 border border-red-200 dark:border-red-800 rounded text-xs">
                      <p className="font-medium text-red-800 dark:text-red-200">Your Rejection Reason:</p>
                      <p className="text-red-700 dark:text-red-300 mt-1">{app.sellerRejectionReason}</p>
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Review Dialog */}
      <Dialog open={isReviewDialogOpen} onOpenChange={setIsReviewDialogOpen}>
        <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Review Draft Pool Guarantee Certificate</DialogTitle>
            <DialogDescription>
              Approve or reject this draft certificate. If approved, the buyer will be notified to pay the 1% issuance fee.
            </DialogDescription>
          </DialogHeader>

          {selectedApplication && (
            <div className="space-y-4">
              {/* Application Summary */}
              <div className="border rounded-lg p-4 bg-muted/30 space-y-2">
                <h4 className="font-semibold">Application Summary</h4>
                <div className="grid grid-cols-2 gap-3 text-sm">
                  <div>
                    <span className="text-muted-foreground">Request ID:</span>
                    <span className="ml-2 font-medium">{selectedApplication.requestId}</span>
                  </div>
                  <div>
                    <span className="text-muted-foreground">Buyer:</span>
                    <span className="ml-2 font-medium">{selectedApplication.buyerCompanyName}</span>
                  </div>
                  <div>
                    <span className="text-muted-foreground">Guarantee Amount:</span>
                    <span className="ml-2 font-medium text-green-600">{parseFloat(selectedApplication.requestedAmount).toFixed(2)} USDC</span>
                  </div>
                  <div>
                    <span className="text-muted-foreground">Issuance Fee:</span>
                    <span className="ml-2 font-medium text-blue-600">{parseFloat(selectedApplication.feeDue).toFixed(2)} USDC</span>
                  </div>
                </div>
              </div>

              {/* Draft Certificate Content */}
              <div className="space-y-2">
                <Label>Draft Certificate (ICC URDG 758 Format)</Label>
                <Textarea
                  value={draftCertificate}
                  readOnly
                  rows={20}
                  className="font-mono text-xs bg-muted/50"
                  data-testid="textarea-draft-certificate-preview"
                />
              </div>

              {/* Rejection Reason (shown when user wants to reject) */}
              <div className="space-y-2">
                <Label htmlFor="textarea-rejection-reason">Rejection Reason (Optional - required only if rejecting)</Label>
                <Textarea
                  id="textarea-rejection-reason"
                  data-testid="textarea-rejection-reason"
                  value={rejectionReason}
                  onChange={(e) => setRejectionReason(e.target.value)}
                  rows={3}
                  placeholder="Provide a reason if you want to reject this draft..."
                />
              </div>
            </div>
          )}

          <DialogFooter className="flex gap-2">
            <Button 
              variant="outline" 
              onClick={() => setIsReviewDialogOpen(false)}
              data-testid="button-cancel-review"
            >
              Cancel
            </Button>
            <Button 
              variant="destructive"
              onClick={handleReject}
              disabled={rejectMutation.isPending}
              data-testid="button-reject-draft"
            >
              {rejectMutation.isPending ? (
                <>Rejecting...</>
              ) : (
                <>
                  <XCircleIcon className="h-4 w-4 mr-1" />
                  Reject Draft
                </>
              )}
            </Button>
            <Button 
              onClick={handleApprove}
              disabled={approveMutation.isPending}
              data-testid="button-approve-draft"
            >
              {approveMutation.isPending ? (
                <>Approving...</>
              ) : (
                <>
                  <CheckCircleIcon className="h-4 w-4 mr-1" />
                  Approve Draft
                </>
              )}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Certificate View Dialog */}
      <Dialog open={isCertificateViewDialogOpen} onOpenChange={setIsCertificateViewDialogOpen}>
        <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>
              {viewingApplication?.status === 'approved' ? 'Final Pool Guarantee Certificate' : 'Draft Pool Guarantee Certificate'}
            </DialogTitle>
            <DialogDescription>
              {viewingApplication?.status === 'approved' 
                ? 'This is the final issued Pool Guarantee certificate (ICC URDG 758 Format)'
                : 'This is the draft certificate you approved'}
            </DialogDescription>
          </DialogHeader>

          {viewingApplication && (
            <div className="space-y-4">
              {/* Application Summary */}
              <div className="border rounded-lg p-4 bg-muted/30 space-y-2">
                <h4 className="font-semibold">Application Details</h4>
                <div className="grid grid-cols-2 gap-3 text-sm">
                  <div>
                    <span className="text-muted-foreground">Request ID:</span>
                    <span className="ml-2 font-medium">{viewingApplication.requestId}</span>
                  </div>
                  <div>
                    <span className="text-muted-foreground">Buyer:</span>
                    <span className="ml-2 font-medium">{viewingApplication.buyerCompanyName}</span>
                  </div>
                  <div>
                    <span className="text-muted-foreground">Guarantee Amount:</span>
                    <span className="ml-2 font-medium text-green-600">{parseFloat(viewingApplication.requestedAmount).toFixed(2)} USDC</span>
                  </div>
                  <div>
                    <span className="text-muted-foreground">Status:</span>
                    <span className={`ml-2 font-medium ${
                      viewingApplication.status === 'approved' ? 'text-green-600' : 'text-blue-600'
                    }`}>
                      {viewingApplication.status === 'approved' ? 'CERTIFICATE ISSUED' :
                       viewingApplication.status === 'fee_paid' ? 'AWAITING CERTIFICATE' :
                       viewingApplication.status.toUpperCase().replace(/_/g, ' ')}
                    </span>
                  </div>
                </div>
              </div>

              {/* Certificate Content */}
              <div className="space-y-2">
                <Label>Certificate (ICC URDG 758 Format)</Label>
                <Textarea
                  value={viewingCertificate}
                  readOnly
                  rows={20}
                  className="font-mono text-xs bg-muted/50"
                  data-testid="textarea-certificate-view"
                />
              </div>
            </div>
          )}

          <DialogFooter>
            <Button 
              variant="outline" 
              onClick={() => setIsCertificateViewDialogOpen(false)}
              data-testid="button-close-certificate-view"
            >
              Close
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

