import { ethers } from "ethers";

const USDC_ADDRESS = "0x036CbD53842c5426634e7929541eC2318f3dCF7e"; // Base Sepolia USDC
const BASE_SEPOLIA_RPC = "https://sepolia.base.org";

const USDC_ABI = [
  "function transfer(address to, uint256 amount) returns (bool)",
  "event Transfer(address indexed from, address indexed to, uint256 value)"
];

interface PaymentVerification {
  valid: boolean;
  error?: string;
  actualAmount?: string;
  from?: string;
  to?: string;
}

export async function verifyUSDCPayment(
  txHash: string,
  expectedTo: string,
  expectedAmount: string,
  tolerance: number = 0.01 // 1% tolerance for rounding
): Promise<PaymentVerification> {
  try {
    const provider = new ethers.JsonRpcProvider(BASE_SEPOLIA_RPC);

    // Get transaction receipt
    const receipt = await provider.getTransactionReceipt(txHash);

    if (!receipt) {
      return {
        valid: false,
        error: "Transaction not found or not yet confirmed"
      };
    }

    // Check if transaction was successful
    if (receipt.status !== 1) {
      return {
        valid: false,
        error: "Transaction failed on-chain"
      };
    }

    // Get the transaction details
    const tx = await provider.getTransaction(txHash);

    if (!tx) {
      return {
        valid: false,
        error: "Transaction details not found"
      };
    }

    // Verify it's a USDC contract interaction
    if (tx.to?.toLowerCase() !== USDC_ADDRESS.toLowerCase()) {
      return {
        valid: false,
        error: "Transaction is not a USDC transfer"
      };
    }

    // Parse transfer event from logs
    const usdcInterface = new ethers.Interface(USDC_ABI);
    let transferEvent = null;

    for (const log of receipt.logs) {
      try {
        const parsed = usdcInterface.parseLog({
          topics: [...log.topics],
          data: log.data
        });

        if (parsed?.name === "Transfer") {
          transferEvent = parsed;
          break;
        }
      } catch (e) {
        continue;
      }
    }

    if (!transferEvent) {
      return {
        valid: false,
        error: "No USDC transfer event found in transaction"
      };
    }

    const from = transferEvent.args[0];
    const to = transferEvent.args[1];
    const value = transferEvent.args[2];

    // Convert to human-readable amount (USDC has 6 decimals)
    const actualAmount = ethers.formatUnits(value, 6);

    // Verify recipient
    if (to.toLowerCase() !== expectedTo.toLowerCase()) {
      return {
        valid: false,
        error: `Payment sent to wrong address. Expected: ${expectedTo}, Got: ${to}`,
        actualAmount,
        from,
        to
      };
    }

    // Verify amount (with tolerance)
    const expectedAmountNum = parseFloat(expectedAmount);
    const actualAmountNum = parseFloat(actualAmount);
    const difference = Math.abs(actualAmountNum - expectedAmountNum);
    const percentDiff = difference / expectedAmountNum;

    if (percentDiff > tolerance) {
      return {
        valid: false,
        error: `Payment amount incorrect. Expected: ${expectedAmount} USDC, Got: ${actualAmount} USDC`,
        actualAmount,
        from,
        to
      };
    }

    // All checks passed!
    return {
      valid: true,
      actualAmount,
      from,
      to
    };

  } catch (error) {
    console.error("Payment verification error:", error);
    return {
      valid: false,
      error: error instanceof Error ? error.message : "Unknown verification error"
    };
  }
}

